function sortRegexByLength(regex) {
  if (!regex.includes('|')) return regex;
  const parts = regex.split('|');
  if (parts.length <= 1) return regex;
  if (parts.some((p, i) => i > 0 && p.length > parts[i - 1].length)) {
    parts.sort((a, b) => b.length - a.length);
    return parts.join('|');
  }
  return regex;
}

// 判断选中文本是否匹配规则的正则表达式
// rule.regex 可能包含正则转义（如 \\.），selectedText 是原始文本
function textMatchesRegex(selectedText, ruleRegex) {
  if (selectedText === ruleRegex) return true;
  try {
    const regex = new RegExp('^' + ruleRegex + '$');
    return regex.test(selectedText);
  } catch {
    return false;
  }
}

function getDefaultPreviewText(plugin, className) {
  if (plugin?.settings?.showClassNameAsPreview && className) {
    return className;
  }
  if (_currentLang === 'zh') {
    const custom = plugin?.settings?.defaultPreviewTextCN;
    return (custom !== undefined && custom !== '') ? custom : t('main.preview');
  } else {
    const custom = plugin?.settings?.defaultPreviewTextEN;
    return (custom !== undefined && custom !== '') ? custom : t('main.preview');
  }
}

function t(key, params) {
  let text = key;
  if (i18n[_currentLang] && i18n[_currentLang].hasOwnProperty(key)) {
    text = i18n[_currentLang][key];
  } else if (i18n['zh'] && i18n['zh'].hasOwnProperty(key)) {
    text = i18n['zh'][key];
  }
  if (params) {
    for (const [k, v] of Object.entries(params)) {
      text = text.replace(new RegExp('\\{' + k + '\\}', 'g'), v);
    }
  }
  return text;
}



// 自定义输入模态框类
class InputModal extends Modal {
  constructor(app, title, placeholder = "", defaultValue = "", onSubmit, description = "") {
    super(app);
    this.title = title;
    this.placeholder = placeholder;
    this.defaultValue = defaultValue;
    this.onSubmit = onSubmit;
    this.description = description;
  }

  onOpen() {
    const { contentEl } = this;
    
    contentEl.empty();
    contentEl.addClass("input-modal");
    
    // 设置标题
    contentEl.createEl("h2", { text: this.title });
    
    // 显示描述信息（如类名）
    if (this.description) {
      const descEl = contentEl.createDiv();
      descEl.style.cssText = `
        font-size: 12px;
        color: var(--text-muted);
        margin-bottom: 12px;
        padding: 4px 8px;
        background: var(--background-secondary);
        border-radius: 4px;
        user-select: text;
        cursor: text;
        word-break: break-all;
      `;
      descEl.textContent = this.description;
    }
    
    // 创建输入框
    const inputEl = contentEl.createEl("input");
    inputEl.type = "text";
    inputEl.placeholder = this.placeholder;
    inputEl.value = this.defaultValue;
    inputEl.style.width = "100%";
    inputEl.style.padding = "8px";
    inputEl.style.marginBottom = "16px";
    inputEl.style.border = "1px solid var(--background-modifier-border)";
    inputEl.style.borderRadius = "4px";
    
    // 自动聚焦输入框
    setTimeout(() => inputEl.focus(), 100);
    
    // 创建按钮容器
    const buttonContainer = contentEl.createEl("div");
    buttonContainer.style.display = "flex";
    buttonContainer.style.justifyContent = "flex-end";
    buttonContainer.style.gap = "8px";
    
    // 取消按钮
    const cancelBtn = buttonContainer.createEl("button");
    cancelBtn.textContent = t('main.cancel');
    cancelBtn.style.padding = "6px 16px";
    cancelBtn.addEventListener("click", () => this.close());
    
    // 确认按钮
    const confirmBtn = buttonContainer.createEl("button");
    confirmBtn.textContent = t('main.confirm');
    confirmBtn.style.padding = "6px 16px";
    confirmBtn.style.backgroundColor = "var(--interactive-accent)";
    confirmBtn.style.color = "white";
    confirmBtn.style.border = "none";
    confirmBtn.style.borderRadius = "4px";
    
    // 确认按钮点击事件
    confirmBtn.addEventListener("click", () => {
      if (this.onSubmit) {
        this.onSubmit(inputEl.value);
      }
      this.close();
    });
    
    // 监听Enter键提交
    inputEl.addEventListener("keydown", (e) => {
      if (e.key === "Enter") {
        if (this.onSubmit) {
          this.onSubmit(inputEl.value);
        }
        this.close();
      }
    });
    
    // 监听Escape键关闭
    inputEl.addEventListener("keydown", (e) => {
      if (e.key === "Escape") {
        this.close();
      }
    });
  }

  onClose() {
    const { contentEl } = this;
    contentEl.empty();
  }
}

// 提示词模板编辑模态框 - 支持同时编辑名称和内容
class PromptTemplateModal extends Modal {
  constructor(app, title, template = null, onSubmit) {
    super(app);
    this.title = title;
    this.template = template;
    this.onSubmit = onSubmit;
  }

  onOpen() {
    const { contentEl } = this;
    
    contentEl.empty();
    contentEl.addClass("prompt-template-modal");
    
    // 设置标题
    contentEl.createEl("h2", { text: this.title });
    
    // 名称输入
    const nameDiv = contentEl.createDiv();
    nameDiv.style.marginBottom = "12px";
    
    const nameLabel = nameDiv.createEl("label");
    nameLabel.textContent = t('remark.promptName');
    nameLabel.style.display = "block";
    nameLabel.style.marginBottom = "4px";
    nameLabel.style.fontWeight = "bold";
    
    const nameInput = nameDiv.createEl("input");
    nameInput.type = "text";
    nameInput.placeholder = t('remark.inputPromptName');
    nameInput.value = this.template?.name || "";
    nameInput.style.width = "100%";
    nameInput.style.padding = "8px";
    nameInput.style.border = "1px solid var(--background-modifier-border)";
    nameInput.style.borderRadius = "4px";
    
    // 内容输入
    const contentDiv = contentEl.createDiv();
    contentDiv.style.marginBottom = "16px";
    
    const contentLabel = contentDiv.createEl("label");
    contentLabel.textContent = t('remark.promptContent');
    contentLabel.style.display = "block";
    contentLabel.style.marginBottom = "4px";
    contentLabel.style.fontWeight = "bold";
    
    const contentTextarea = contentDiv.createEl("textarea");
    contentTextarea.placeholder = t('remark.inputPromptContent');
    contentTextarea.value = this.template?.content || "";
    contentTextarea.style.width = "100%";
    contentTextarea.style.height = "200px";
    contentTextarea.style.padding = "8px";
    contentTextarea.style.border = "1px solid var(--background-modifier-border)";
    contentTextarea.style.borderRadius = "4px";
    contentTextarea.style.resize = "vertical";
    contentTextarea.style.fontFamily = "monospace";
    
    // 自动聚焦名称输入框
    setTimeout(() => nameInput.focus(), 100);
    
    // 创建按钮容器
    const buttonContainer = contentEl.createEl("div");
    buttonContainer.style.display = "flex";
    buttonContainer.style.justifyContent = "flex-end";
    buttonContainer.style.gap = "8px";
    
    // 取消按钮
    const cancelBtn = buttonContainer.createEl("button");
    cancelBtn.textContent = t('main.cancel');
    cancelBtn.style.padding = "6px 16px";
    cancelBtn.addEventListener("click", () => this.close());
    
    // 确认按钮
    const confirmBtn = buttonContainer.createEl("button");
    confirmBtn.textContent = t('main.confirm');
    confirmBtn.style.padding = "6px 16px";
    confirmBtn.style.backgroundColor = "var(--interactive-accent)";
    confirmBtn.style.color = "white";
    confirmBtn.style.border = "none";
    confirmBtn.style.borderRadius = "4px";
    confirmBtn.addEventListener("click", () => {
      if (this.onSubmit) {
        this.onSubmit({
          id: this.template?.id,
          name: nameInput.value,
          content: contentTextarea.value
        });
      }
      this.close();
    });
    
    // 按下Enter键(Shift+Enter换行)确认
    contentTextarea.addEventListener("keydown", (e) => {
      if (e.key === "Enter" && !e.shiftKey) {
        e.preventDefault();
        if (this.onSubmit) {
          this.onSubmit({
            id: this.template?.id,
            name: nameInput.value,
            content: contentTextarea.value
          });
        }
        this.close();
      }
    });
  }
  
  onClose() {
    const { contentEl } = this;
    contentEl.empty();
  }
}

// 自定义备注输入模态框类
class AddRemarkModal extends Modal {
  constructor(app, title, placeholder = "", defaultValue = "", onSubmit, plugin = null, matchedText = '') {
    super(app);
    this.title = title;
    this.placeholder = placeholder;
    this.defaultValue = defaultValue;
    this.onSubmit = onSubmit;
    this.plugin = plugin;
    this.matchedText = matchedText;
  }

  // 控制点击遮罩层是否关闭弹窗
  shouldCloseOnOutsideClick() {
    return true;
  }

  async saveImageToVault(imageData, fileName) {
    const attachmentFolder = this.app.vault.config?.attachmentFolderPath || 'attachments';
    const fullPath = `${attachmentFolder}/${fileName}`;
    try {
      if (!(await this.app.vault.adapter.exists(attachmentFolder))) {
        await this.app.vault.adapter.mkdir(attachmentFolder);
      }
    } catch (e) {
      await this.app.vault.adapter.mkdir(attachmentFolder);
    }
    let finalPath = fullPath;
    let finalName = fileName;
    let counter = 1;
    while (await this.app.vault.adapter.exists(finalPath)) {
      const ext = fileName.substring(fileName.lastIndexOf('.'));
      const base = fileName.substring(0, fileName.lastIndexOf('.'));
      finalName = `${base}_${counter}${ext}`;
      finalPath = `${attachmentFolder}/${finalName}`;
      counter++;
    }
    await this.app.vault.adapter.writeBinary(finalPath, imageData);
    return finalName;
  }

  insertAtCursor(textarea, text) {
    const start = textarea.selectionStart;
    const end = textarea.selectionEnd;
    const value = textarea.value;
    textarea.value = value.substring(0, start) + text + value.substring(end);
    textarea.selectionStart = textarea.selectionEnd = start + text.length;
    textarea.focus();
    textarea.dispatchEvent(new Event('input'));
  }

  onOpen() {
    const { contentEl } = this;
    
    contentEl.empty();
    contentEl.addClass("input-modal");
    
    const pluginSettings = this.plugin?.settings || {};
    const popupFontSize = pluginSettings.popupFontSize !== undefined ? pluginSettings.popupFontSize : 14;
    const popupSpacing = pluginSettings.popupSpacing !== undefined ? pluginSettings.popupSpacing : 10;
    const popupWidth = pluginSettings.popupWidth !== undefined ? pluginSettings.popupWidth : 300;
    const popupBorderWidth = pluginSettings.popupBorderWidth !== undefined ? pluginSettings.popupBorderWidth : 1;
    const popupBorderColor = pluginSettings.popupBorderColor || 'var(--text-accent)';
    const savedOpacity = pluginSettings.popupOpacity !== undefined ? pluginSettings.popupOpacity : 1;
    
    // 与备注弹窗风格一致的模态窗口样式
    this.modalEl.style.width = `auto`;
    this.modalEl.style.maxWidth = `${Math.max(popupWidth, 500)}px`;
    this.modalEl.style.borderRadius = '8px';
    this.modalEl.style.overflow = 'hidden';
    this.modalEl.style.backgroundColor = 'var(--background-primary)';
    this.modalEl.style.opacity = savedOpacity;
    
    if (popupBorderWidth === 0) {
      this.modalEl.style.border = 'none';
      this.modalEl.style.boxShadow = '0 4px 16px rgba(0,0,0,0.35)';
    } else {
      this.modalEl.style.border = `${popupBorderWidth}px solid ${popupBorderColor}`;
      this.modalEl.style.boxShadow = '0 4px 16px rgba(0,0,0,0.35)';
    }
    
    // 深色模式增强
    if (document.body.classList.contains('theme-dark')) {
      this.modalEl.style.boxShadow = '0 4px 16px rgba(0,0,0,0.5)';
      this.modalEl.style.outline = '1px solid rgba(255, 255, 255, 0.1)';
    }
    
    // 添加与备注弹窗一致的 Markdown 样式
    const mdStyle = document.createElement('style');
    mdStyle.textContent = `
      .input-modal p { margin: 0; }
      .input-modal ul, .input-modal ol { margin: 0; padding-left: 20px; }
      .input-modal li { margin: 0; }
      .input-modal h1, .input-modal h2, .input-modal h3, .input-modal h4, .input-modal h5, .input-modal h6 { margin: 0; }
      .input-modal blockquote { margin: 0; }
      .input-modal hr { margin: 5px 0; }
      .input-modal img { max-width: 100%; height: auto; border-radius: 4px; margin: 4px 0; }
      .input-modal .internal-embed { max-width: 100%; }
      .input-modal .internal-embed img { max-width: 100%; height: auto; border-radius: 4px; margin: 4px 0; }
    `;
    contentEl.appendChild(mdStyle);
    
    // 获取当前文件信息
    const av = this.plugin?.app?.workspace?.getActiveViewOfType(MarkdownView);
    const linkFilePath = av?.file?.path || this.plugin?.currentFilePath || '';
    const fileName = linkFilePath ? linkFilePath.split('/').pop().replace(/\.md$/, '') : '';
    const matchedText = this.matchedText || '';
    
    // 文件名 + 搜索词 标题栏（与备注弹窗样式一致）
    if (fileName || matchedText) {
      const headerEl = contentEl.createDiv();
      headerEl.style.cssText = 'display:flex;align-items:center;gap:6px;margin-bottom:8px;flex-wrap:wrap;';
      
      const headerLeft = headerEl.createDiv();
      headerLeft.style.cssText = 'display:flex;align-items:center;gap:6px;flex-wrap:wrap;flex:1;min-width:0;';
      
      const fileHue = 210;
      
      if (fileName) {
        const fileNameEl = headerLeft.createEl('span');
        fileNameEl.textContent = '📄 ' + fileName;
        fileNameEl.style.cssText = `font-size:12px;font-weight:600;color:hsl(${fileHue},50%,35%);background:hsl(${fileHue},50%,90%);padding:2px 8px;border-radius:10px;flex-shrink:0;white-space:nowrap;`;
      }
      
      if (matchedText) {
        const searchTag = headerLeft.createEl('span');
        const displayText = matchedText.length > 20 ? matchedText.substring(0, 20) + '...' : matchedText;
        searchTag.textContent = displayText;
        searchTag.style.cssText = 'font-size:10px;color:var(--text-muted);background:var(--background-modifier-hover);padding:1px 6px;border-radius:8px;';
      }
    }
    
    // 编辑/预览 切换状态
    let isEditing = true;
    let currentValue = this.defaultValue || '';
    
    // 内容容器
    const contentContainer = contentEl.createDiv();
    contentContainer.style.cssText = `position:relative;`;
    
    // ===== 编辑模式 =====
    const editContainer = contentContainer.createDiv();
    
    const textareaEl = editContainer.createEl("textarea");
    textareaEl.placeholder = this.placeholder;
    textareaEl.value = currentValue;
    textareaEl.style.cssText = `width:100%;height:150px;padding:${popupSpacing}px;background-color:var(--background-primary);color:var(--text-normal);border:1px solid var(--background-modifier-border);border-radius:4px;font-size:${popupFontSize}px;font-family:var(--font-ui);line-height:1.5;resize:vertical;box-sizing:border-box;outline:none;`;
    
    // ===== 预览模式 =====
    const previewContainer = contentContainer.createDiv();
    previewContainer.className = 'remark-popup-content';
    previewContainer.style.cssText = `width:100%;min-height:60px;max-height:200px;padding:${popupSpacing}px;overflow-y:auto;font-size:${popupFontSize}px;line-height:1.5;box-sizing:border-box;max-width:100%;word-wrap:break-word;display:none;`;
    
    // 渲染预览
    const renderPreview = async () => {
      if (previewContainer._component) {
        previewContainer._component.unload();
        previewContainer._component = null;
      }
      previewContainer.innerHTML = '';
      if (!currentValue.trim()) {
        previewContainer.innerHTML = `<em style="color: var(--text-muted)">${t('main.empty')}</em>`;
        return;
      }
      try {
        const { MarkdownRenderer, Component } = require('obsidian');
        if (this.app && MarkdownRenderer) {
          const component = new Component();
          component.load();
          const sourcePath = this.plugin?.currentFilePath || '';
          MarkdownRenderer.renderMarkdown(currentValue, previewContainer, sourcePath, component);
          previewContainer._component = component;
        }
        await new Promise(r => requestAnimationFrame(r));
        if (this.plugin) {
          await this.plugin.renderImagesManually(currentValue, previewContainer, this.plugin);
        }
      } catch (err) {
        if (this.plugin) {
          await this.plugin.renderImagesManually(currentValue, previewContainer, this.plugin);
        } else {
          previewContainer.textContent = currentValue;
        }
      }
    };
    
    // 切换到预览模式
    const switchToPreview = async () => {
      if (!isEditing) return;
      currentValue = textareaEl.value;
      isEditing = false;
      editContainer.style.display = 'none';
      previewContainer.style.display = 'block';
      await renderPreview();
    };
    
    // 切换到编辑模式（双击预览区）
    const switchToEdit = () => {
      if (isEditing) return;
      isEditing = true;
      previewContainer.style.display = 'none';
      editContainer.style.display = 'block';
      textareaEl.value = currentValue;
      textareaEl.focus();
    };
    
    // 双击预览区切换回编辑模式
    previewContainer.addEventListener('dblclick', switchToEdit);
    
    // 失焦时切换到预览模式
    textareaEl.addEventListener('blur', async () => {
      // 延迟检查，避免点击按钮时立即触发
      await new Promise(r => setTimeout(r, 150));
      // 如果焦点不在弹窗内的任何元素上，切换到预览
      if (isEditing && !this.modalEl.contains(document.activeElement)) {
        switchToPreview();
      }
    });
    
    // 图片粘贴功能
    const handleImageFile = async (file) => {
      if (!file) return;
      const arrayBuffer = await file.arrayBuffer();
      let ext = 'png';
      if (file.type) {
        const mimeExt = file.type.split('/')[1];
        if (mimeExt === 'jpeg') ext = 'jpg';
        else if (mimeExt === 'svg+xml') ext = 'svg';
        else if (['png', 'gif', 'bmp', 'webp'].includes(mimeExt)) ext = mimeExt;
      } else {
        const nameExt = file.name.split('.').pop()?.toLowerCase();
        if (['jpg', 'jpeg', 'png', 'gif', 'bmp', 'webp', 'svg'].includes(nameExt)) {
          ext = nameExt === 'jpeg' ? 'jpg' : nameExt;
        }
      }
      const imgFileName = `remark_${Date.now()}.${ext}`;
      try {
        const savedName = await this.saveImageToVault(new Uint8Array(arrayBuffer), imgFileName);
        this.insertAtCursor(textareaEl, `![[${savedName}]]`);
        new Notice(t('main.imageSaved') + ': ' + savedName);
      } catch (err) {
        console.error('保存图片失败:', err);
        new Notice(t('main.imageSaveFailed') + ': ' + err.message);
      }
    };
    
    // 隐藏的文件选择器
    const fileInput = document.createElement('input');
    fileInput.type = "file";
    fileInput.accept = "image/png,image/jpeg,image/gif,image/bmp,image/webp,image/svg+xml";
    fileInput.style.display = "none";
    contentEl.appendChild(fileInput);
    
    fileInput.addEventListener("change", async () => {
      const file = fileInput.files[0];
      if (file) await handleImageFile(file);
      fileInput.value = '';
    });
    
    // Ctrl+V 粘贴图片
    textareaEl.addEventListener("paste", async (e) => {
      const items = e.clipboardData?.items;
      if (!items) return;
      let imageItem = null;
      for (let i = 0; i < items.length; i++) {
        if (items[i].type.startsWith('image/')) {
          imageItem = items[i];
          break;
        }
      }
      if (!imageItem) return;
      e.preventDefault();
      const file = imageItem.getAsFile();
      if (file) await handleImageFile(file);
    });
    
    // 拖放图片支持
    textareaEl.addEventListener('drop', async (e) => {
      const files = e.dataTransfer?.files;
      if (!files || files.length === 0) return;
      for (const file of files) {
        if (file.type.startsWith('image/')) {
          e.preventDefault();
          await handleImageFile(file);
          break;
        }
      }
    });
    textareaEl.addEventListener('dragover', (e) => {
      if (e.dataTransfer?.types?.includes('Files')) {
        e.preventDefault();
      }
    });
    
    setTimeout(() => textareaEl.focus(), 100);
    
    // 底部按钮区
    const buttonContainer = contentEl.createEl("div");
    buttonContainer.style.cssText = `display:flex;justify-content:flex-end;gap:${popupSpacing}px;align-items:center;margin-top:${popupSpacing}px;`;
    
    // 提示文字
    const hintEl = buttonContainer.createEl("span");
    hintEl.style.cssText = `font-size:11px;color:var(--text-muted);flex:1;`;
    hintEl.textContent = 'Ctrl+V 粘贴图片 · Enter 确认';
    
    const cancelBtn = buttonContainer.createEl("button");
    cancelBtn.textContent = t('main.cancel');
    cancelBtn.style.cssText = `padding:${Math.floor(popupSpacing * 0.6)}px ${Math.floor(popupSpacing * 1.5)}px;font-size:${popupFontSize}px;cursor:pointer;border:1px solid var(--background-modifier-border);border-radius:4px;background:var(--background-secondary);color:var(--text-normal);`;
    
    const confirmBtn = buttonContainer.createEl("button");
    confirmBtn.textContent = t('main.confirm');
    confirmBtn.style.cssText = `padding:${Math.floor(popupSpacing * 0.6)}px ${Math.floor(popupSpacing * 1.5)}px;font-size:${popupFontSize}px;cursor:pointer;background-color:var(--interactive-accent);color:white;border:none;border-radius:4px;`;
    
    cancelBtn.addEventListener("click", () => this.close());
    
    confirmBtn.addEventListener("click", () => {
      const finalValue = isEditing ? textareaEl.value : currentValue;
      if (this.onSubmit) {
        this.onSubmit(finalValue);
      }
      this.close();
    });
    
    // Enter 确认
    textareaEl.addEventListener("keydown", (e) => {
      if (e.key === "Enter" && !e.shiftKey) {
        e.preventDefault();
        if (this.onSubmit) {
          this.onSubmit(textareaEl.value);
        }
        this.close();
      }
    });
    
    // 点击编辑区外部只是让编辑框失焦（由blur事件处理预览切换）
    this.shouldCloseOnOutsideClick = () => {
      if (isEditing) {
        // 让textarea失焦，触发blur切换到预览
        textareaEl.blur();
        return false;
      }
      return true;
    };
    
    // 恢复记住的大小
    const savedWidth = this.plugin?.settings?.addRemarkModalWidth;
    const savedHeight = this.plugin?.settings?.addRemarkModalHeight;
    if (savedWidth) {
      this.modalEl.style.width = `${savedWidth}px`;
      this.modalEl.style.maxWidth = `${savedWidth}px`;
      const contentWidth = savedWidth - 30;
      contentEl.style.maxWidth = `${contentWidth}px`;
      contentEl.style.width = `${contentWidth}px`;
    }
    if (savedHeight) {
      this.modalEl.style.height = `${savedHeight}px`;
      this.modalEl.style.maxHeight = 'none';
      contentEl.style.maxHeight = 'none';
    }
    
    // 添加调整大小手柄
    this._setupRemarkModalResize();
  }
  
  _setupRemarkModalResize() {
    const modalEl = this.modalEl;
    const contentEl = this.contentEl;
    
    // 清理旧的
    if (this._remarkResizeHandle && document.body.contains(this._remarkResizeHandle)) {
      document.body.removeChild(this._remarkResizeHandle);
    }
    if (this._remarkPositionInterval) {
      clearInterval(this._remarkPositionInterval);
    }
    
    const resizeHandle = document.body.createDiv();
    resizeHandle.className = "modal-resize-handle";
    resizeHandle.style.position = "fixed";
    resizeHandle.style.width = "12px";
    resizeHandle.style.height = "12px";
    resizeHandle.style.cursor = "nwse-resize";
    resizeHandle.style.zIndex = "9999";
    resizeHandle.style.background = "linear-gradient(135deg, transparent 50%, var(--text-muted) 50%)";
    resizeHandle.style.pointerEvents = "auto";
    resizeHandle.style.borderRadius = "0 0 8px 0";
    
    const updatePosition = () => {
      if (!modalEl || !document.body.contains(modalEl)) return;
      const rect = modalEl.getBoundingClientRect();
      resizeHandle.style.right = `${window.innerWidth - rect.right + 2}px`;
      resizeHandle.style.bottom = `${window.innerHeight - rect.bottom + 2}px`;
    };
    
    setTimeout(updatePosition, 0);
    setTimeout(updatePosition, 50);
    setTimeout(updatePosition, 200);
    
    this._remarkPositionInterval = setInterval(updatePosition, 500);
    
    let isResizing = false;
    let resizeStartX, resizeStartY, resizeStartWidth, resizeStartHeight;
    
    const onResizeMouseDown = (e) => {
      isResizing = true;
      resizeStartX = e.clientX;
      resizeStartY = e.clientY;
      resizeStartWidth = modalEl.offsetWidth;
      resizeStartHeight = modalEl.offsetHeight;
      modalEl.style.maxHeight = 'none';
      contentEl.style.maxHeight = 'none';
      document.addEventListener("mousemove", onResizeMouseMove);
      document.addEventListener("mouseup", onResizeMouseUp);
      e.preventDefault();
      e.stopPropagation();
    };
    
    const onResizeMouseMove = (e) => {
      if (!isResizing) return;
      const newWidth = Math.max(400, resizeStartWidth + (e.clientX - resizeStartX));
      const newHeight = Math.max(300, resizeStartHeight + (e.clientY - resizeStartY));
      modalEl.style.width = `${newWidth}px`;
      modalEl.style.maxWidth = `${newWidth}px`;
      modalEl.style.height = `${newHeight}px`;
      const contentWidth = newWidth - 30;
      contentEl.style.maxWidth = `${contentWidth}px`;
      contentEl.style.width = `${contentWidth}px`;
      updatePosition();
    };
    
    const onResizeMouseUp = () => {
      isResizing = false;
      document.removeEventListener("mousemove", onResizeMouseMove);
      document.removeEventListener("mouseup", onResizeMouseUp);
      // 保存大小
      if (this.plugin && this.plugin.settings) {
        this.plugin.settings.addRemarkModalWidth = modalEl.offsetWidth;
        this.plugin.settings.addRemarkModalHeight = modalEl.offsetHeight;
        this.plugin.saveData(this.plugin.settings);
      }
    };
    
    resizeHandle.addEventListener("mousedown", onResizeMouseDown);
    
    this._remarkResizeHandle = resizeHandle;
    this._remarkResizeListeners = { mousemove: onResizeMouseMove, mouseup: onResizeMouseUp };
    
    // 覆盖 onClose 确保清理
    const originalOnClose = this.onClose.bind(this);
    this.onClose = () => {
      if (this._remarkResizeListeners) {
        document.removeEventListener("mousemove", this._remarkResizeListeners.mousemove);
        document.removeEventListener("mouseup", this._remarkResizeListeners.mouseup);
      }
      if (this._remarkResizeHandle && document.body.contains(this._remarkResizeHandle)) {
        document.body.removeChild(this._remarkResizeHandle);
        this._remarkResizeHandle = null;
      }
      if (this._remarkPositionInterval) {
        clearInterval(this._remarkPositionInterval);
        this._remarkPositionInterval = null;
      }
      originalOnClose();
    };
  }

  async renderPreview(content, container) {
    container.empty();
    if (!content.trim()) {
      container.innerHTML = `<span style="color: var(--text-muted)">${t('main.noContent')}</span>`;
      return;
    }
    try {
      // 先渲染基础 markdown
      const { MarkdownRenderer, Component } = require("obsidian");
      if (this.app && MarkdownRenderer && this.plugin) {
        const sourcePath = this.plugin?.currentFilePath || '';
        const component = new Component();
        component.load();
        await MarkdownRenderer.renderMarkdown(content, container, sourcePath, component);
        container._component = component;
      }
      
      // 使用插件里的通用图片渲染方法
      if (this.plugin) {
        await this.plugin.renderImagesManually(content, container, this.plugin);
      }
    } catch (err) {
      console.error('渲染错误:', err);
      // 降级：尝试直接用通用方法
      if (this.plugin) {
        await this.plugin.renderImagesManually(content, container, this.plugin);
      }
    }
  }

  onClose() {
    const { contentEl } = this;
    contentEl.empty();
  }
}

// 格式替换模态框类
class FormatReplaceModal extends Modal {
  constructor(app, plugin) {
    super(app);
    this.plugin = plugin;
    this.replaceHistory = []; // 替换历史记录
    this.historyIndex = -1; // 当前历史位置
  }

  async onOpen() {
    const { contentEl } = this;
    contentEl.empty();
    contentEl.addClass('format-replace-modal');

    this.modalEl.style.width = '600px';
    this.modalEl.style.maxWidth = '90vw';

    // 标题
    const titleEl = contentEl.createEl('h2', { text: t('format.title') });
    titleEl.style.marginBottom = '16px';

    // 说明
    const descEl = contentEl.createEl('p');
    descEl.textContent = t('format.inputFormat');
    descEl.style.fontSize = '13px';
    descEl.style.color = 'var(--text-muted)';
    descEl.style.marginBottom = '16px';

    // 输入区域
    const inputContainer = contentEl.createDiv();
    inputContainer.style.display = 'flex';
    inputContainer.style.gap = '12px';
    inputContainer.style.marginBottom = '16px';

    // 格式模式输入
    const patternGroup = inputContainer.createDiv();
    patternGroup.style.flex = '1';
    
    const patternLabel = patternGroup.createEl('div', { text: t('showcase.formatPattern') });
    patternLabel.style.fontSize = '13px';
    patternLabel.style.marginBottom = '4px';
    
    const patternInput = patternGroup.createEl('input');
    patternInput.type = 'text';
    patternInput.placeholder = t('format.patternExample');
    patternInput.style.width = '100%';
    patternInput.style.padding = '8px';
    patternInput.style.border = '1px solid var(--background-modifier-border)';
    patternInput.style.borderRadius = '4px';
    patternInput.style.fontFamily = 'monospace';

    // 常用MD格式快捷按钮
    const quickPatterns = [
      { label: '**加粗**', pattern: '\\*\\*(.+?)\\*\\*' },
      { label: '*斜体*', pattern: '\\*(.+?)\\*' },
      { label: '==高亮==', pattern: '==(.+?)==' },
      { label: '`' + t('format.code') + '`', pattern: '`(.+?)`' },
      { label: '~~删除线~~', pattern: '~~(.+?)~~' },
      { label: '__下划线__', pattern: '__(.+?)__' },
    ];
    
    const quickButtons = patternGroup.createDiv();
    quickButtons.style.display = 'flex';
    quickButtons.style.flexWrap = 'wrap';
    quickButtons.style.gap = '4px';
    quickButtons.style.marginTop = '4px';
    
    quickPatterns.forEach(item => {
      const btn = quickButtons.createEl('button');
      btn.textContent = item.label;
      btn.style.padding = '2px 6px';
      btn.style.fontSize = '12px';
      btn.style.border = '1px solid var(--background-modifier-border)';
      btn.style.borderRadius = '3px';
      btn.style.backgroundColor = 'var(--background-secondary)';
      btn.style.color = 'var(--text-muted)';
      btn.style.cursor = 'pointer';
      
      btn.addEventListener('click', () => {
        patternInput.value = item.pattern;
      });
    });

    // 样式名输入
    const styleGroup = inputContainer.createDiv();
    styleGroup.style.minWidth = '150px';
    
    const styleLabel = styleGroup.createEl('div', { text: t('showcase.styleNameLabel') });
    styleLabel.style.fontSize = '13px';
    styleLabel.style.marginBottom = '4px';
    
    const styleInput = styleGroup.createEl('input');
    styleInput.type = 'text';
    styleInput.placeholder = t('format.styleExample');
    styleInput.style.width = '100%';
    styleInput.style.padding = '8px';
    styleInput.style.border = '1px solid var(--background-modifier-border)';
    styleInput.style.borderRadius = '4px';

    // 操作按钮
    const buttonContainer = contentEl.createEl('div');
    buttonContainer.style.display = 'flex';
    buttonContainer.style.gap = '8px';
    buttonContainer.style.marginBottom = '16px';

    const replaceBtn = buttonContainer.createEl('button');
    replaceBtn.textContent = t('showcase.executeReplace');
    replaceBtn.style.padding = '8px 16px';
    replaceBtn.style.backgroundColor = 'var(--interactive-accent)';
    replaceBtn.style.color = 'white';
    replaceBtn.style.border = 'none';
    replaceBtn.style.borderRadius = '4px';
    replaceBtn.style.cursor = 'pointer';

    const undoBtn = buttonContainer.createEl('button');
    undoBtn.textContent = t('format.undo');
    undoBtn.style.padding = '8px 16px';
    undoBtn.style.border = '1px solid var(--background-modifier-border)';
    undoBtn.style.borderRadius = '4px';
    undoBtn.style.backgroundColor = 'var(--background-primary)';
    undoBtn.style.color = 'var(--text-normal)';
    undoBtn.style.cursor = 'pointer';
    undoBtn.disabled = true;

    const redoBtn = buttonContainer.createEl('button');
    redoBtn.textContent = t('format.redo');
    redoBtn.style.padding = '8px 16px';
    redoBtn.style.border = '1px solid var(--background-modifier-border)';
    redoBtn.style.borderRadius = '4px';
    redoBtn.style.backgroundColor = 'var(--background-primary)';
    redoBtn.style.color = 'var(--text-normal)';
    redoBtn.style.cursor = 'pointer';
    redoBtn.disabled = true;

    // 状态显示
    const statusEl = contentEl.createEl('div');
    statusEl.style.fontSize = '13px';
    statusEl.style.color = 'var(--text-muted)';
    statusEl.style.marginBottom = '16px';

    // 替换历史列表
    const historySection = contentEl.createDiv();
    historySection.style.borderTop = '1px solid var(--background-modifier-border)';
    historySection.style.paddingTop = '16px';

    const historyTitle = historySection.createEl('div', { text: t('showcase.replaceHistory') });
    historyTitle.style.fontSize = '14px';
    historyTitle.style.fontWeight = 'bold';
    historyTitle.style.marginBottom = '8px';

    const historyList = historySection.createEl('div');
    historyList.style.maxHeight = '200px';
    historyList.style.overflowY = 'auto';

    // 加载历史记录
    this.loadHistory();
    this.updateHistoryList(historyList);

    // 执行替换
    replaceBtn.addEventListener('click', async () => {
      const pattern = patternInput.value.trim();
      const styleName = styleInput.value.trim();

      if (!pattern) {
        new Notice(t('main.inputFormat'));
        return;
      }
      if (!styleName) {
        new Notice(t('main.inputStyleName'));
        return;
      }

      try {
        // 创建正则表达式
        const regex = new RegExp(pattern, 'g');

        // 获取当前文档内容
        const activeView = this.app.workspace.getActiveViewOfType(MarkdownView);
        if (!activeView || !activeView.file) {
          new Notice(t('main.openMdFile'));
          return;
        }

        const filePath = activeView.file.path;
        const file = this.app.vault.getFileByPath(filePath);
        const content = await this.app.vault.read(file);

        // 查找所有匹配的文本（捕获组1的内容，即去除格式符号后的文本）
        const matches = [];
        let match;
        while ((match = regex.exec(content)) !== null) {
          if (match[1]) {
            matches.push(match[1]);
          }
        }

        if (matches.length === 0) {
          new Notice(t('main.noMatchText'));
          return;
        }

        // 保存当前规则状态和文档内容用于撤销
        await this.plugin.loadFileRules(filePath);
        const oldRules = JSON.parse(JSON.stringify(this.plugin.rules));
        const oldContent = content;

        // 替换文档中的格式符号
        const newContent = content.replace(regex, '$1');
        await this.app.vault.modify(file, newContent);

        // 添加高亮规则
        const addedRules = [];
        for (const text of matches) {
          const trimmedText = text.trim();
          if (trimmedText && !this.plugin.rules.find(r => r.regex === trimmedText)) {
            await this.plugin.addFileRule(trimmedText, styleName);
            addedRules.push(trimmedText);
          }
        }

        if (addedRules.length > 0) {
          // 记录历史
          const historyItem = {
            pattern,
            styleName,
            addedRules,
            oldRules,
            oldContent,
            newContent,
            filePath, // 保存文件路径
            timestamp: Date.now()
          };

          // 清除当前位置之后的历史
          this.replaceHistory = this.replaceHistory.slice(0, this.historyIndex + 1);
          this.replaceHistory.push(historyItem);
          this.historyIndex = this.replaceHistory.length - 1;

          // 保存到设置
          this.saveHistory();

          statusEl.textContent = t('format.replacedCount') + ` ${matches.length} ` + t('format.addedCount') + ` ${addedRules.length} ` + t('format.highlightRules');
          statusEl.style.color = '#27ae60';

          this.plugin.rulesVersion++;
          this.plugin.rulesUpdateEmitter.dispatchEvent(new Event('update'));
          this.plugin.refreshCurrentView();

          this.updateHistoryList(historyList);
          this.updateUndoRedoButtons(undoBtn, redoBtn);

          new Notice(t('main.formatReplaced'));
        } else {
          statusEl.textContent = t('showcase.allMatchExist');
          statusEl.style.color = 'var(--text-muted)';
        }

      } catch (error) {
        console.error('格式替换错误:', error);
        new Notice(t('main.formatReplaceFailed'));
        statusEl.textContent = t('showcase.errorPrefix') + error.message;
        statusEl.style.color = '#e74c3c';
      }
    });

    // 撤销
    undoBtn.addEventListener('click', async () => {
      if (this.historyIndex < 0) return;

      const historyItem = this.replaceHistory[this.historyIndex];
      
      const activeView = this.app.workspace.getActiveViewOfType(MarkdownView);
      if (!activeView || !activeView.file) return;

      const filePath = activeView.file.path;
      const file = this.app.vault.getFileByPath(filePath);
      
      // 恢复旧文档内容
      if (historyItem.oldContent) {
        await this.app.vault.modify(file, historyItem.oldContent);
      }
      
      // 恢复旧规则
      this.plugin.rules = JSON.parse(JSON.stringify(historyItem.oldRules));
      await this.plugin.saveFileRules(filePath, this.plugin.rules);

      this.historyIndex--;
      this.saveHistory();

      this.plugin.rulesVersion++;
      this.plugin.rulesUpdateEmitter.dispatchEvent(new Event('update'));
      this.plugin.refreshCurrentView();

      this.updateHistoryList(historyList);
      this.updateUndoRedoButtons(undoBtn, redoBtn);

      new Notice(t('main.undone'));
    });

    // 重做
    redoBtn.addEventListener('click', async () => {
      if (this.historyIndex >= this.replaceHistory.length - 1) return;

      this.historyIndex++;
      const historyItem = this.replaceHistory[this.historyIndex];

      const activeView = this.app.workspace.getActiveViewOfType(MarkdownView);
      if (!activeView || !activeView.file) return;

      const filePath = activeView.file.path;
      const file = this.app.vault.getFileByPath(filePath);

      // 重新应用文档替换
      if (historyItem.newContent) {
        await this.app.vault.modify(file, historyItem.newContent);
      }

      await this.plugin.loadFileRules(filePath);

      // 重新应用规则
      for (const text of historyItem.addedRules) {
        await this.plugin.addFileRule(text, historyItem.styleName);
      }

      this.saveHistory();

      this.plugin.rulesVersion++;
      this.plugin.rulesUpdateEmitter.dispatchEvent(new Event('update'));
      this.plugin.refreshCurrentView();

      this.updateHistoryList(historyList);
      this.updateUndoRedoButtons(undoBtn, redoBtn);

      new Notice(t('main.redone'));
    });

    // 更新按钮状态
    this.updateUndoRedoButtons(undoBtn, redoBtn);
  }

  loadHistory() {
    if (this.plugin.settings.replaceHistory) {
      try {
        this.replaceHistory = JSON.parse(this.plugin.settings.replaceHistory);
        this.historyIndex = this.replaceHistory.length - 1;
      } catch (e) {
        this.replaceHistory = [];
        this.historyIndex = -1;
      }
    }
  }

  saveHistory() {
    this.plugin.settings.replaceHistory = JSON.stringify(this.replaceHistory);
    this.plugin.saveData(this.plugin.settings);
  }

  updateHistoryList(container) {
    container.empty();

    // 获取当前文档路径
    const activeView = this.app.workspace.getActiveViewOfType(MarkdownView);
    const currentFilePath = activeView?.file?.path;

    // 过滤当前文档的历史记录
    const currentDocHistory = currentFilePath 
      ? this.replaceHistory.filter(item => item.filePath === currentFilePath)
      : this.replaceHistory;

    if (currentDocHistory.length === 0) {
      const emptyEl = container.createEl('div');
      emptyEl.textContent = t('showcase.noReplaceHistory');
      emptyEl.style.fontSize = '13px';
      emptyEl.style.color = 'var(--text-muted)';
      return;
    }

    currentDocHistory.forEach((item, displayIndex) => {
      // 找到在完整历史中的真实索引
      const realIndex = this.replaceHistory.indexOf(item);
      const row = container.createDiv();
      row.style.display = 'flex';
      row.style.alignItems = 'center';
      row.style.justifyContent = 'space-between';
      row.style.padding = '8px';
      row.style.borderBottom = '1px solid var(--background-modifier-border)';
      row.title = t('format.clickReapply') + `\n` + t('format.pattern') + `: ${item.pattern}\n` + t('format.style') + `: ${item.styleName}`;

      if (realIndex === this.historyIndex) {
        row.style.backgroundColor = 'var(--background-modifier-hover)';
      }

      // 删除按钮
      const deleteBtn = row.createEl('button');
      deleteBtn.textContent = '×';
      deleteBtn.style.width = '20px';
      deleteBtn.style.height = '20px';
      deleteBtn.style.display = 'flex';
      deleteBtn.style.alignItems = 'center';
      deleteBtn.style.justifyContent = 'center';
      deleteBtn.style.border = 'none';
      deleteBtn.style.borderRadius = '3px';
      deleteBtn.style.backgroundColor = 'transparent';
      deleteBtn.style.color = 'var(--text-muted)';
      deleteBtn.style.fontSize = '16px';
      deleteBtn.style.cursor = 'pointer';
      deleteBtn.style.marginRight = '8px';
      
      deleteBtn.addEventListener('click', (e) => {
        e.stopPropagation();
        this.replaceHistory.splice(realIndex, 1);
        if (this.historyIndex >= realIndex) {
          this.historyIndex = Math.max(-1, this.historyIndex - 1);
        }
        this.saveHistory();
        this.updateHistoryList(container);
      });

      // 点击重新应用
      row.addEventListener('click', async () => {
        const activeView = this.app.workspace.getActiveViewOfType(MarkdownView);
        if (!activeView || !activeView.file) return;

        const filePath = activeView.file.path;
        await this.plugin.loadFileRules(filePath);

        for (const text of item.addedRules) {
          await this.plugin.addFileRule(text, item.styleName);
        }

        this.plugin.rulesVersion++;
        this.plugin.rulesUpdateEmitter.dispatchEvent(new Event('update'));
        this.plugin.refreshCurrentView();

        new Notice(t('main.reapplied'));
      });

      const infoEl = row.createEl('div');
      infoEl.style.flex = '1';
      infoEl.style.fontSize = '13px';
      infoEl.style.cursor = 'pointer';
      infoEl.textContent = `${item.pattern} → ${item.styleName} (${item.addedRules.length})`;

      const timeEl = row.createEl('div');
      timeEl.style.fontSize = '12px';
      timeEl.style.color = 'var(--text-muted)';
      timeEl.style.marginLeft = '8px';
      timeEl.textContent = this.formatTime(item.timestamp);

      container.appendChild(row);
    });
  }

  formatTime(timestamp) {
    const date = new Date(timestamp);
    return `${date.getHours().toString().padStart(2, '0')}:${date.getMinutes().toString().padStart(2, '0')}`;
  }

  updateUndoRedoButtons(undoBtn, redoBtn) {
    undoBtn.disabled = this.historyIndex < 0;
    redoBtn.disabled = this.historyIndex >= this.replaceHistory.length - 1;
  }

  onClose() {
    const { contentEl } = this;
    contentEl.empty();
  }
}

// 自定义确认模态框类
class ConfirmModal extends Modal {
  constructor(app, title, message, onConfirm, onCancel = null) {
    super(app);
    this.title = title;
    this.message = message;
    this.onConfirm = onConfirm;
    this.onCancel = onCancel;
  }

  onOpen() {
    const { contentEl } = this;
    
    contentEl.empty();
    contentEl.addClass("confirm-modal");
    
    // 设置标题
    contentEl.createEl("h2", { text: this.title });
    
    // 设置消息
    const messageEl = contentEl.createEl("p");
    messageEl.textContent = this.message;
    messageEl.style.marginBottom = "16px";
    
    // 创建按钮容器
    const buttonContainer = contentEl.createEl("div");
    buttonContainer.style.display = "flex";
    buttonContainer.style.justifyContent = "flex-end";
    buttonContainer.style.gap = "8px";
    
    // 取消按钮
    const cancelBtn = buttonContainer.createEl("button");
    cancelBtn.textContent = t('main.cancel');
    cancelBtn.style.padding = "6px 16px";
    cancelBtn.addEventListener("click", () => {
      if (this.onCancel) {
        this.onCancel();
      }
      this.close();
    });
    
    // 确认按钮
    const confirmBtn = buttonContainer.createEl("button");
    confirmBtn.textContent = t('main.confirm');
    confirmBtn.style.padding = "6px 16px";
    confirmBtn.style.backgroundColor = "var(--interactive-danger)";
    confirmBtn.style.color = "white";
    confirmBtn.style.border = "none";
    confirmBtn.style.borderRadius = "4px";
    
    // 确认按钮点击事件
    confirmBtn.addEventListener("click", () => {
      if (this.onConfirm) {
        this.onConfirm();
      }
      this.close();
    });
  }

  onClose() {
    const { contentEl } = this;
    contentEl.empty();
  }
}

function setupModalResizeHandle(modalInstance, modalEl, widthInput, opacityInput, options) {
  const { minWidth, maxWidth, widthStep, widthSettingsKey, opacitySettingsKey } = options;
  const contentEl = modalInstance.contentEl;
  
  // 清理旧的resize handle，防止重复创建
  if (modalInstance._resizeHandle && document.body.contains(modalInstance._resizeHandle)) {
    document.body.removeChild(modalInstance._resizeHandle);
  }
  if (modalInstance._positionInterval) {
    clearInterval(modalInstance._positionInterval);
  }
  if (modalInstance._resizeUpdatePosition) {
    window.removeEventListener("resize", modalInstance._resizeUpdatePosition);
  }
  
  const resizeHandle = document.body.createDiv();
  resizeHandle.className = "modal-resize-handle";
  resizeHandle.style.position = "fixed";
  resizeHandle.style.width = "12px";
  resizeHandle.style.height = "12px";
  resizeHandle.style.cursor = "nwse-resize";
  resizeHandle.style.zIndex = "9999";
  resizeHandle.style.background = "linear-gradient(135deg, transparent 50%, var(--text-muted) 50%)";
  resizeHandle.style.pointerEvents = "auto";
  resizeHandle.style.borderRadius = "0 0 8px 0";
  
  const updatePosition = () => {
    if (!modalEl || !document.body.contains(modalEl)) return;
    const rect = modalEl.getBoundingClientRect();
    resizeHandle.style.right = `${window.innerWidth - rect.right + 2}px`;
    resizeHandle.style.bottom = `${window.innerHeight - rect.bottom + 2}px`;
  };
  
  setTimeout(updatePosition, 0);
  setTimeout(updatePosition, 50);
  setTimeout(updatePosition, 100);
  setTimeout(updatePosition, 200);
  
  window.addEventListener("resize", updatePosition);
  
  const positionInterval = setInterval(updatePosition, 500);
  
  let isResizing = false;
  let resizeStartX, resizeStartY, resizeStartWidth, resizeStartHeight;
  
  const onResizeMouseDown = (e) => {
    isResizing = true;
    resizeStartX = e.clientX;
    resizeStartY = e.clientY;
    resizeStartWidth = modalEl.offsetWidth;
    resizeStartHeight = modalEl.offsetHeight;
    modalEl.style.maxHeight = 'none';
    if (contentEl) contentEl.style.maxHeight = 'none';
    document.addEventListener("mousemove", onResizeMouseMove);
    document.addEventListener("mouseup", onResizeMouseUp);
    e.preventDefault();
    e.stopPropagation();
  };
  
  const onResizeMouseMove = (e) => {
    if (!isResizing) return;
    const newWidth = Math.max(minWidth, Math.min(maxWidth, resizeStartWidth + (e.clientX - resizeStartX)));
    const newHeight = Math.max(300, resizeStartHeight + (e.clientY - resizeStartY));
    modalEl.style.width = `${newWidth}px`;
    modalEl.style.maxWidth = `${newWidth}px`;
    modalEl.style.height = `${newHeight}px`;
    const contentWidth = newWidth - 30;
    contentEl.style.maxWidth = `${contentWidth}px`;
    contentEl.style.width = `${contentWidth}px`;
    if (widthInput) widthInput.value = newWidth;
    updatePosition();
  };
  
  const onResizeMouseUp = () => {
    isResizing = false;
    document.removeEventListener("mousemove", onResizeMouseMove);
    document.removeEventListener("mouseup", onResizeMouseUp);
    const newWidth = modalEl.offsetWidth;
    if (modalInstance.plugin && modalInstance.plugin.settings) {
      modalInstance.plugin.settings[widthSettingsKey] = newWidth;
      modalInstance.plugin.saveData(modalInstance.plugin.settings);
    }
  };
  
  resizeHandle.addEventListener("mousedown", onResizeMouseDown);
  
  modalInstance._resizeHandle = resizeHandle;
  modalInstance._resizeUpdatePosition = updatePosition;
  modalInstance._resizeListeners = { mousemove: onResizeMouseMove, mouseup: onResizeMouseUp };
  modalInstance._positionInterval = positionInterval;
}

// 高亮列表弹窗类
class StyleShowcaseModal extends Modal {
  constructor(app, plugin, styleNames = [], showcaseMode = 'showcase') {
    super(app);
    this.plugin = plugin;
    this.styleNames = styleNames;
    this.showcaseMode = 'count';
    this.showcaseMinCount = plugin.settings?.showcaseMinCount || 2;
    this.sourceFilter = plugin.settings?.showcaseSourceFilter || 'current'; // current/open/all/global
    this.showGlobalRules = plugin.settings?.showcaseShowGlobal !== undefined ? plugin.settings?.showcaseShowGlobal : true;
    this.minLength = plugin.settings?.showcaseMinLength || 0; // 最小字数
    this.maxLength = plugin.settings?.showcaseMaxLength || 0; // 最大字数（0表示不限制）
    
    const settings = plugin.settings?.showcaseModal || {};
    this.sortBy = settings.sortBy || 'styleName';
    this.sortOrder = settings.sortOrder || 'asc';
    this.showStyleName = settings.showStyleName !== false;
    this.showSource = settings.showSource !== false;
    this.showRemark = settings.showRemark !== false;
    this.showTimestamp = settings.showTimestamp === true;
    this.modalOpacity = settings.opacity || 100;
    this.modalWidth = settings.width || 900;
    this.modalHeight = settings.height || null;
    this.scrollPosition = settings.scrollPosition || 0;
    this.columnWidths = settings.columnWidths || {
      text: '30%',
      styleName: '18%',
      source: '10%',
      timestamp: '14%',
      remark: '20%'
    };
    this.allRules = [];
    this.columnFilters = {};
  }

  async onOpen() {
    const { contentEl } = this;
    contentEl.empty();
    contentEl.addClass("style-showcase-modal");
    
    this.modalEl.style.position = 'relative';
    this.modalEl.style.width = `${this.modalWidth}px`;
    this.modalEl.style.maxWidth = '95vw';
    this.modalEl.style.maxHeight = '90vh';
    this.modalEl.style.opacity = this.modalOpacity / 100;
    
    this.setupWheelEvents();
    this.setupResizeHandle();
    this.setupCtrlPassthrough();
    this.setupClickBlocker();
    
    // 先渲染UI框架，再异步加载数据
    this.render();
    this.showLoading();
    await this.loadAllRules();
    this.hideLoading();
    this.sortRules();
    this.renderTable();
  }
  
  showLoading() {
    if (this.tableContainer) {
      this.tableContainer.empty();
      const loadingEl = this.tableContainer.createDiv();
      loadingEl.style.textAlign = "center";
      loadingEl.style.padding = "40px";
      loadingEl.style.color = "var(--text-muted)";
      loadingEl.textContent = t('showcase.loading');
      loadingEl.id = "showcase-loading-indicator";
    }
  }
  
  hideLoading() {
    const loadingEl = document.getElementById("showcase-loading-indicator");
    if (loadingEl) loadingEl.remove();
  }

  setupClickBlocker() {
    const blockClick = (e) => {
      if (this._ctrlPressed) {
        e.preventDefault();
        e.stopPropagation();
      }
    };
    
    if (this.modalEl.parentElement) {
      this.modalEl.parentElement.addEventListener('mousedown', blockClick, true);
      this.modalEl.parentElement.addEventListener('click', blockClick, true);
      this._clickBlocker = blockClick;
      this._modalContainer = this.modalEl.parentElement;
    }
  }

  setupCtrlPassthrough() {
    this._ctrlPressed = false;
    
    const updatePassthrough = (e) => {
      if (e.ctrlKey && !this._ctrlPressed) {
        this._ctrlPressed = true;
      } else if (!e.ctrlKey && this._ctrlPressed) {
        this._ctrlPressed = false;
        this.modalEl.style.pointerEvents = 'auto';
        if (this.modalEl.parentElement) {
          this.modalEl.parentElement.style.pointerEvents = 'auto';
        }
      }
    };
    
    const handleMouseDown = (e) => {
      if (this._ctrlPressed) {
        this.modalEl.style.pointerEvents = 'none';
        if (this.modalEl.parentElement) {
          this.modalEl.parentElement.style.pointerEvents = 'none';
        }
      }
    };
    
    const handleMouseUp = (e) => {
      if (this._ctrlPressed) {
        setTimeout(() => {
          if (this._ctrlPressed && this.modalEl) {
            this.modalEl.style.pointerEvents = 'none';
          }
        }, 100);
      }
    };
    
    document.addEventListener('keydown', updatePassthrough);
    document.addEventListener('keyup', updatePassthrough);
    document.addEventListener('mousedown', handleMouseDown, true);
    document.addEventListener('mouseup', handleMouseUp, true);
    
    this._passthroughListeners = { 
      keydown: updatePassthrough, 
      keyup: updatePassthrough,
      mousedown: handleMouseDown,
      mouseup: handleMouseUp
    };
  }

  async jumpToText(rule) {
    const { MarkdownView } = require('obsidian');
    
    // 如果 rule 是字符串，保持向后兼容
    const text = typeof rule === 'string' ? rule : rule.text;
    const filePath = typeof rule === 'string' ? null : rule.filePath;
    
    let targetView = this.app.workspace.getActiveViewOfType(MarkdownView);
    
    // 如果有指定 filePath 且不是当前文件，先在新标签页打开目标文件
    if (filePath && (!targetView || targetView.file?.path !== filePath)) {
      try {
        const targetFile = this.app.vault.getAbstractFileByPath(filePath);
        if (targetFile) {
          // 创建新标签页
          const newLeaf = this.app.workspace.getLeaf(true);
          await newLeaf.openFile(targetFile);
          targetView = this.app.workspace.getActiveViewOfType(MarkdownView);
          
          // 延迟 500ms，让其他插件（如 remember cursor position）有时间执行
          await new Promise(resolve => setTimeout(resolve, 500));
        }
      } catch (e) {
        console.error('Error opening file:', e);
      }
    }
    
    if (!targetView || !targetView.editor) {
      new Notice(t('main.openMdFile'));
      return;
    }
    
    const editor = targetView.editor;
    const content = editor.getValue();
    const lines = content.split('\n');
    
    for (let i = 0; i < lines.length; i++) {
      const line = lines[i];
      const pos = line.indexOf(text);
      if (pos !== -1) {
        const from = { line: i, ch: pos };
        const to = { line: i, ch: pos + text.length };
        editor.setCursor(from);
        editor.scrollIntoView({ from, to }, true);
        editor.setSelection(from, to);
        new Notice(t('main.jumpedTo') + ': ' + text);
        this.close();
        return;
      }
    }
    
    new Notice(t('main.notFoundInDoc') + ': ' + text);
  }

  setupWheelEvents() {
    const onWheel = (e) => {
      if (e.ctrlKey) {
        e.preventDefault();
        const delta = e.deltaY > 0 ? -5 : 5;
        this.modalOpacity = Math.max(30, Math.min(100, this.modalOpacity + delta));
        this.modalEl.style.opacity = this.modalOpacity / 100;
        this.saveSettings();
      } else if (e.altKey) {
        e.preventDefault();
        const delta = e.deltaY > 0 ? -20 : 20;
        this.modalWidth = Math.max(500, Math.min(1500, this.modalWidth + delta));
        this.modalEl.style.width = `${this.modalWidth}px`;
        this.saveSettings();
      }
    };
    
    this.modalEl.addEventListener("wheel", onWheel, { passive: false });
    
    const originalOnClose = this.onClose.bind(this);
    this.onClose = () => {
      this.modalEl.removeEventListener("wheel", onWheel);
      if (this._resizeListeners) {
        document.removeEventListener("mousemove", this._resizeListeners.mousemove);
        document.removeEventListener("mouseup", this._resizeListeners.mouseup);
      }
      if (this._resizeHandle && document.body.contains(this._resizeHandle)) {
        document.body.removeChild(this._resizeHandle);
      }
      if (this._resizeUpdatePosition) {
        window.removeEventListener("resize", this._resizeUpdatePosition);
      }
      if (this._positionInterval) {
        clearInterval(this._positionInterval);
      }
      if (this._passthroughListeners) {
        document.removeEventListener('keydown', this._passthroughListeners.keydown);
        document.removeEventListener('keyup', this._passthroughListeners.keyup);
        document.removeEventListener('mousedown', this._passthroughListeners.mousedown, true);
        document.removeEventListener('mouseup', this._passthroughListeners.mouseup, true);
      }
      if (this._clickBlocker && this._modalContainer) {
        this._modalContainer.removeEventListener('mousedown', this._clickBlocker, true);
        this._modalContainer.removeEventListener('click', this._clickBlocker, true);
      }
      originalOnClose();
    };
  }

  setupResizeHandle() {
    const resizeHandle = document.body.createDiv();
    resizeHandle.className = "showcase-modal-resize-handle";
    resizeHandle.style.position = "fixed";
    resizeHandle.style.width = "12px";
    resizeHandle.style.height = "12px";
    resizeHandle.style.cursor = "nwse-resize";
    resizeHandle.style.zIndex = "9999";
    resizeHandle.style.background = "linear-gradient(135deg, transparent 50%, var(--text-muted) 50%)";
    resizeHandle.style.pointerEvents = "auto";
    resizeHandle.style.borderRadius = "0 0 8px 0";
    
    const updatePosition = () => {
      if (!this.modalEl || !document.body.contains(this.modalEl)) return;
      const rect = this.modalEl.getBoundingClientRect();
      resizeHandle.style.right = `${window.innerWidth - rect.right + 2}px`;
      resizeHandle.style.bottom = `${window.innerHeight - rect.bottom + 2}px`;
    };
    
    setTimeout(updatePosition, 0);
    setTimeout(updatePosition, 50);
    setTimeout(updatePosition, 100);
    setTimeout(updatePosition, 200);
    
    window.addEventListener("resize", updatePosition);
    
    this._positionInterval = setInterval(updatePosition, 500);
    
    let isResizing = false;
    let resizeStartX, resizeStartY, resizeStartWidth, resizeStartHeight;
    
    const onResizeMouseDown = (e) => {
      isResizing = true;
      resizeStartX = e.clientX;
      resizeStartY = e.clientY;
      resizeStartWidth = this.modalEl.offsetWidth;
      resizeStartHeight = this.modalEl.offsetHeight;
      document.addEventListener("mousemove", onResizeMouseMove);
      document.addEventListener("mouseup", onResizeMouseUp);
      e.preventDefault();
      e.stopPropagation();
    };
    
    const onResizeMouseMove = (e) => {
      if (!isResizing) return;
      const newWidth = Math.max(500, resizeStartWidth + (e.clientX - resizeStartX));
      const newHeight = Math.max(300, resizeStartHeight + (e.clientY - resizeStartY));
      this.modalEl.style.width = `${newWidth}px`;
      this.modalEl.style.height = `${newHeight}px`;
      this.modalWidth = newWidth;
      this.modalHeight = newHeight;
      updatePosition();
    };
    
    const onResizeMouseUp = () => {
      isResizing = false;
      document.removeEventListener("mousemove", onResizeMouseMove);
      document.removeEventListener("mouseup", onResizeMouseUp);
      this.saveSettings();
    };
    
    resizeHandle.addEventListener("mousedown", onResizeMouseDown);
    
    this._resizeHandle = resizeHandle;
    this._resizeUpdatePosition = updatePosition;
    this._resizeListeners = { mousemove: onResizeMouseMove, mouseup: onResizeMouseUp };
  }

  async saveSettings() {
    if (!this.plugin.settings.showcaseModal) {
      this.plugin.settings.showcaseModal = {};
    }
    this.plugin.settings.showcaseModal.sortBy = this.sortBy;
    this.plugin.settings.showcaseModal.sortOrder = this.sortOrder;
    this.plugin.settings.showcaseModal.showStyleName = this.showStyleName;
    this.plugin.settings.showcaseModal.showSource = this.showSource;
    this.plugin.settings.showcaseModal.showRemark = this.showRemark;
    this.plugin.settings.showcaseModal.showTimestamp = this.showTimestamp;
    this.plugin.settings.showcaseModal.opacity = this.modalOpacity;
    this.plugin.settings.showcaseModal.width = this.modalWidth;
    this.plugin.settings.showcaseModal.height = this.modalHeight;
    this.plugin.settings.showcaseModal.scrollPosition = this.scrollPosition;
    this.plugin.settings.showcaseModal.columnWidths = this.columnWidths;
    this.plugin.settings.showcaseMode = this.showcaseMode;
    this.plugin.settings.showcaseMinCount = this.showcaseMinCount;
    await this.plugin.saveData(this.plugin.settings);
  }

  async loadAllRules() {
    this.allRules = [];
    
    let styleNamesToLoad = await this.loadStyleNamesByCount();
    
    // 加载全局规则（根据设置决定是否显示）
    if (this.showGlobalRules && this.plugin.globalRules) {
      // 按 cssClass 建立索引，避免嵌套循环
      const globalByClass = new Map();
      for (const rule of this.plugin.globalRules) {
        if (!globalByClass.has(rule.cssClass)) {
          globalByClass.set(rule.cssClass, []);
        }
        globalByClass.get(rule.cssClass).push(rule);
      }
      for (const styleName of styleNamesToLoad) {
        const rules = globalByClass.get(styleName);
        if (rules) {
          for (const rule of rules) {
            this.allRules.push({
              text: rule.regex,
              styleName: styleName,
              remark: rule.remark || '',
              source: t('main.globalRule'),
              timestamp: rule.timestamp || 0,
              filePath: null,
              isGlobal: true
            });
          }
        }
      }
    }
    
    // 根据筛选选项加载文件规则
    const { MarkdownView } = require('obsidian');
    const styleNameSet = new Set(styleNamesToLoad);
    
    if (this.sourceFilter === 'current') {
      // 仅当前文档
      const activeView = this.app.workspace.getActiveViewOfType(MarkdownView);
      if (activeView && activeView.file) {
        await this.loadFileRules(activeView.file.path, styleNameSet);
      }
    } else if (this.sourceFilter === 'open') {
      // 所有打开文档
      const openViews = this.app.workspace.getLeavesOfType('markdown');
      const promises = openViews
        .filter(leaf => leaf.view instanceof MarkdownView && leaf.view.file)
        .map(leaf => this.loadFileRules(leaf.view.file.path, styleNameSet));
      await Promise.all(promises);
    } else if (this.sourceFilter === 'all') {
      // 所有文档 - 并行读取
      const dataRelDir = '.obsidian/plugins/Regex-Css-Highlighter/data';
      
      const dirExists = await crossFS.exists(this.app.vault, dataRelDir);
      if (dirExists) {
        const files = await crossFS.list(this.app.vault, dataRelDir);
        const ruleFiles = files.filter(f => f.endsWith('.json') && !f.endsWith('_count.json'));
        const promises = ruleFiles.map(file => {
          let filePath = file.replace(/\.json$/, '.md').replace(/_/g, '/');
          return this.loadFileRules(filePath, styleNameSet);
        });
        await Promise.all(promises);
      }
    }
  }
  
  async loadFileRules(filePath, styleNameSet) {
    try {
      // 优先从内存缓存读取
      let rules = this.plugin.fileRules?.get(filePath);
      if (!rules) {
        rules = await this.plugin.loadFileRulesFromPath(filePath);
      }
      if (rules) {
        const fileName = _isDesktop ? require('path').basename(filePath) : filePath.split(/[\/\\]/).pop();
        for (const rule of rules) {
          if (styleNameSet.has(rule.cssClass)) {
            this.allRules.push({
              text: rule.regex,
              styleName: rule.cssClass,
              remark: rule.remark || '',
              source: fileName,
              timestamp: rule.timestamp || 0,
              filePath: filePath
            });
          }
        }
      }
    } catch (e) {
      // 文件可能不存在，忽略错误
    }
  }
  
  async loadStyleNamesByCount() {
    const minCount = this.showcaseMinCount;
    const dataRelDir = '.obsidian/plugins/Regex-Css-Highlighter/data';
    const result = new Set();
    
    let files;
    try {
      files = await crossFS.list(this.app.vault, dataRelDir);
    } catch (e) {
      return [];
    }
    
    const countFiles = files.filter(f => f.endsWith('_count.json'));
    
    // 并行读取所有计数文件
    const contents = await Promise.all(
      countFiles.map(countFile => 
        crossFS.read(this.app.vault, dataRelDir + '/' + countFile)
          .catch(() => null)
      )
    );
    
    for (const content of contents) {
      if (!content) continue;
      try {
        const data = JSON.parse(content) || {};
        for (const category in data) {
          if (data.hasOwnProperty(category) && Array.isArray(data[category])) {
            const arr = data[category];
            for (let i = 0; i < arr.length; i += 2) {
              const className = arr[i];
              const count = arr[i + 1] || 0;
              if (count >= minCount) {
                result.add(className);
              }
            }
          }
        }
      } catch (e) {
      }
    }
    
    return Array.from(result);
  }

  sortRules() {
    this.allRules.sort((a, b) => {
      let compareResult = 0;
      
      if (this.sortBy === 'styleName') {
        compareResult = a.styleName.localeCompare(b.styleName);
      } else if (this.sortBy === 'text') {
        compareResult = a.text.localeCompare(b.text);
      } else if (this.sortBy === 'timestamp') {
        compareResult = (a.timestamp || 0) - (b.timestamp || 0);
      } else if (this.sortBy === 'source') {
        compareResult = a.source.localeCompare(b.source);
      }
      
      return this.sortOrder === 'asc' ? compareResult : -compareResult;
    });
  }

  formatTimestamp(timestamp) {
    if (!timestamp) return '-';
    const date = new Date(timestamp);
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const day = String(date.getDate()).padStart(2, '0');
    const hours = String(date.getHours()).padStart(2, '0');
    const minutes = String(date.getMinutes()).padStart(2, '0');
    return `${year}-${month}-${day} ${hours}:${minutes}`;
  }

  createToggleCheckbox(toolbar, label, checked, onChange) {
    const toggle = toolbar.createEl("label");
    toggle.style.display = "flex";
    toggle.style.alignItems = "center";
    toggle.style.gap = "4px";
    toggle.style.marginLeft = "8px";
    toggle.style.cursor = "pointer";
    
    const checkbox = toggle.createEl("input", { type: "checkbox" });
    checkbox.checked = checked;
    checkbox.style.cursor = "pointer";
    
    const text = toggle.createEl("span", { text: label });
    text.style.fontSize = "13px";
    
    checkbox.addEventListener("change", async (e) => {
      onChange(e);
      await this.saveSettings();
    });
    
    return toggle;
  }

  render() {
    const { contentEl } = this;
    contentEl.empty();
    
    const titleEl = contentEl.createEl("h2", { text: t('showcase.title') });
    titleEl.style.marginBottom = "4px";
    titleEl.style.flexShrink = "0";
    
    // 手机端：折叠式筛选面板
    if (!_isDesktop) {
      const filterHeader = contentEl.createDiv();
      filterHeader.style.display = "flex";
      filterHeader.style.alignItems = "center";
      filterHeader.style.justifyContent = "space-between";
      filterHeader.style.marginBottom = "8px";
      filterHeader.style.flexShrink = "0";
      filterHeader.style.cursor = "pointer";
      filterHeader.style.padding = "6px 10px";
      filterHeader.style.backgroundColor = "var(--background-secondary)";
      filterHeader.style.borderRadius = "4px";
      
      const filterToggleText = filterHeader.createEl("span", { text: t('showcase.filter') + ' ▶' });
      filterToggleText.style.fontSize = "14px";
      filterToggleText.style.fontWeight = "500";
      
      const statsEl = filterHeader.createEl("span");
      statsEl.textContent = t('showcase.totalCount') + ` ${this.allRules.length}`;
      statsEl.style.fontSize = "13px";
      statsEl.style.color = "var(--text-muted)";
      this.statsEl = statsEl;
      
      const filterPanel = contentEl.createDiv();
      filterPanel.style.display = "none";
      filterPanel.style.marginBottom = "8px";
      filterPanel.style.padding = "8px";
      filterPanel.style.backgroundColor = "var(--background-secondary)";
      filterPanel.style.borderRadius = "4px";
      filterPanel.style.flexShrink = "0";
      
      let filterExpanded = false;
      filterHeader.addEventListener("click", () => {
        filterExpanded = !filterExpanded;
        filterPanel.style.display = filterExpanded ? "block" : "none";
        filterToggleText.textContent = filterExpanded ? t('main.filter') + ' ▼' : t('main.filter') + ' ▶';
      });
      
      // 手机端：每行一个筛选项，垂直排列
      const makeRow = () => {
        const row = filterPanel.createDiv();
        row.style.display = "flex";
        row.style.alignItems = "center";
        row.style.gap = "8px";
        row.style.marginBottom = "8px";
        return row;
      };
      
      // 筛选来源
      const row1 = makeRow();
      const sourceLabel = row1.createEl("span", { text: t('showcase.filter') + ':' });
      sourceLabel.style.fontSize = "13px";
      sourceLabel.style.minWidth = "60px";
      
      const sourceSelect = row1.createEl("select");
      sourceSelect.style.padding = "4px 8px";
      sourceSelect.style.borderRadius = "4px";
      sourceSelect.style.border = "1px solid var(--background-modifier-border)";
      sourceSelect.style.flex = "1";
      sourceSelect.createEl("option", { value: 'current', text: t('showcase.currentDoc') });
      sourceSelect.createEl("option", { value: 'open', text: t('showcase.allOpenDocs') });
      sourceSelect.createEl("option", { value: 'all', text: t('showcase.allDocs') });
      sourceSelect.value = this.sourceFilter;
      
      // 全局高亮
      const row2 = makeRow();
      const globalToggle = row2.createEl("label");
      globalToggle.style.display = "flex";
      globalToggle.style.alignItems = "center";
      globalToggle.style.gap = "4px";
      globalToggle.style.cursor = "pointer";
      
      const globalCheckbox = globalToggle.createEl("input", { type: "checkbox" });
      globalCheckbox.checked = this.showGlobalRules;
      globalCheckbox.style.cursor = "pointer";
      
      const globalLabel = globalToggle.createEl("span", { text: t('showcase.showGlobal') });
      globalLabel.style.fontSize = "13px";
      
      // 最小次数
      const countRow = makeRow();
      const countPrefix = countRow.createEl("span", { text: t('showcase.minCountPrefix') });
      countPrefix.style.fontSize = "13px";
      
      const countInput = countRow.createEl("input", { type: "number", value: String(this.showcaseMinCount) });
      countInput.style.width = "60px";
      countInput.style.padding = "2px 6px";
      countInput.style.borderRadius = "4px";
      countInput.style.border = "1px solid var(--background-modifier-border)";
      countInput.style.fontSize = "13px";
      countInput.min = "1";
      
      const countSuffix = countRow.createEl("span", { text: t('showcase.minCountSuffix') });
      countSuffix.style.fontSize = "13px";
      
      // 字数范围
      const lengthRow = makeRow();
      const minLabel = lengthRow.createEl("span", { text: t('showcase.charCount') });
      minLabel.style.fontSize = "13px";
      minLabel.style.minWidth = "40px";
      
      const minInput = lengthRow.createEl("input", { type: "number" });
      minInput.style.width = "50px";
      minInput.style.padding = "2px 6px";
      minInput.style.borderRadius = "4px";
      minInput.style.border = "1px solid var(--background-modifier-border)";
      minInput.style.fontSize = "13px";
      minInput.min = "0";
      minInput.value = this.minLength || '';
      
      const lengthSeparator = lengthRow.createEl("span", { text: "~" });
      lengthSeparator.style.fontSize = "13px";
      
      const maxInput = lengthRow.createEl("input", { type: "number" });
      maxInput.style.width = "50px";
      maxInput.style.padding = "2px 6px";
      maxInput.style.borderRadius = "4px";
      maxInput.style.border = "1px solid var(--background-modifier-border)";
      maxInput.style.fontSize = "13px";
      maxInput.min = "0";
      maxInput.value = this.maxLength || '';
      
      const maxUnit = lengthRow.createEl("span", { text: t('showcase.charUnit') });
      maxUnit.style.fontSize = "13px";
      
      // 列显示切换
      const colRow = makeRow();
      colRow.style.flexWrap = "wrap";
      colRow.style.gap = "12px";
      
      this.createToggleCheckbox(colRow, t('showcase.showStyleName'), this.showStyleName, (e) => {
        this.showStyleName = e.target.checked;
        this.renderTable();
      });
      this.createToggleCheckbox(colRow, t('showcase.showSource'), this.showSource, (e) => {
        this.showSource = e.target.checked;
        this.renderTable();
      });
      this.createToggleCheckbox(colRow, t('showcase.showTimestamp'), this.showTimestamp, (e) => {
        this.showTimestamp = e.target.checked;
        this.renderTable();
      });
      this.createToggleCheckbox(colRow, t('showcase.showRemark'), this.showRemark, (e) => {
        this.showRemark = e.target.checked;
        this.renderTable();
      });
      
      // 事件绑定
      sourceSelect.addEventListener("change", async () => {
        this.sourceFilter = sourceSelect.value;
        this.plugin.settings.showcaseSourceFilter = this.sourceFilter;
        await this.plugin.saveData(this.plugin.settings);
        this.showLoading();
        await this.loadAllRules();
        this.hideLoading();
        this.sortRules();
        this.renderTable();
        statsEl.textContent = t('showcase.totalCount') + ` ${this.allRules.length}`;
      });
      
      globalCheckbox.addEventListener("change", async () => {
        this.showGlobalRules = globalCheckbox.checked;
        this.plugin.settings.showcaseShowGlobal = this.showGlobalRules;
        await this.plugin.saveData(this.plugin.settings);
        this.showLoading();
        await this.loadAllRules();
        this.hideLoading();
        this.sortRules();
        this.renderTable();
        statsEl.textContent = t('showcase.totalCount') + ` ${this.allRules.length}`;
      });
      
      countInput.addEventListener("change", async () => {
        const val = parseInt(countInput.value, 10);
        if (isNaN(val) || val < 1) {
          countInput.value = String(this.showcaseMinCount);
          return;
        }
        this.showcaseMinCount = val;
        this.plugin.settings.showcaseMinCount = val;
        await this.plugin.saveData(this.plugin.settings);
        this.showLoading();
        await this.loadAllRules();
        this.hideLoading();
        this.sortRules();
        this.renderTable();
        statsEl.textContent = t('showcase.totalCount') + ` ${this.allRules.length}`;
      });
      
      const handleLengthFilter = async () => {
        const minVal = parseInt(minInput.value, 10) || 0;
        const maxVal = parseInt(maxInput.value, 10) || 0;
        this.minLength = minVal;
        this.maxLength = maxVal;
        this.plugin.settings.showcaseMinLength = minVal;
        this.plugin.settings.showcaseMaxLength = maxVal;
        await this.plugin.saveData(this.plugin.settings);
        this.renderTable();
      };
      minInput.addEventListener("change", handleLengthFilter);
      maxInput.addEventListener("change", handleLengthFilter);
      
    } else {
    // 桌面端：原有水平布局
    const modeBar = contentEl.createDiv();
    modeBar.style.display = "flex";
    modeBar.style.alignItems = "center";
    modeBar.style.gap = "12px";
    modeBar.style.marginBottom = "8px";
    modeBar.style.flexShrink = "0";
    modeBar.style.flexWrap = "wrap";
    
    // 筛选选择
    const sourceLabel = modeBar.createEl("span", { text: t('showcase.filter') + ':' });
    sourceLabel.style.fontSize = "13px";
    
    const sourceSelect = modeBar.createEl("select");
    sourceSelect.style.padding = "4px 8px";
    sourceSelect.style.borderRadius = "4px";
    sourceSelect.style.border = "1px solid var(--background-modifier-border)";
    
    sourceSelect.createEl("option", { value: 'current', text: t('showcase.currentDoc') });
    sourceSelect.createEl("option", { value: 'open', text: t('showcase.allOpenDocs') });
    sourceSelect.createEl("option", { value: 'all', text: t('showcase.allDocs') });
    sourceSelect.value = this.sourceFilter;
    
    // 显示全局规则选框
    const globalToggle = modeBar.createEl("label");
    globalToggle.style.display = "flex";
    globalToggle.style.alignItems = "center";
    globalToggle.style.gap = "4px";
    globalToggle.style.cursor = "pointer";
    
    const globalCheckbox = globalToggle.createEl("input", { type: "checkbox" });
    globalCheckbox.checked = this.showGlobalRules;
    globalCheckbox.style.cursor = "pointer";
    
    const globalLabel = globalToggle.createEl("span", { text: t('showcase.showGlobal') });
    globalLabel.style.fontSize = "13px";
    
    // 字数范围筛选
    const lengthFilter = modeBar.createEl("div");
    lengthFilter.style.display = "flex";
    lengthFilter.style.alignItems = "center";
    lengthFilter.style.gap = "4px";
    
    const minLabel = lengthFilter.createEl("span", { text: "≥" });
    minLabel.style.fontSize = "13px";
    
    const minInput = lengthFilter.createEl("input", { type: "number" });
    minInput.style.width = "60px";
    minInput.style.padding = "2px 6px";
    minInput.style.borderRadius = "4px";
    minInput.style.border = "1px solid var(--background-modifier-border)";
    minInput.style.fontSize = "13px";
    minInput.min = "0";
    minInput.value = this.minLength || '';
    
    const lengthSeparator = lengthFilter.createEl("span", { text: t('showcase.charUnit') });
    lengthSeparator.style.fontSize = "13px";
    
    const maxLabel = lengthFilter.createEl("span", { text: "≤" });
    maxLabel.style.fontSize = "13px";
    
    const maxInput = lengthFilter.createEl("input", { type: "number" });
    maxInput.style.width = "60px";
    maxInput.style.padding = "2px 6px";
    maxInput.style.borderRadius = "4px";
    maxInput.style.border = "1px solid var(--background-modifier-border)";
    maxInput.style.fontSize = "13px";
    maxInput.min = "0";
    maxInput.value = this.maxLength || '';
    
    const maxUnit = lengthFilter.createEl("span", { text: t('showcase.charUnit') });
    maxUnit.style.fontSize = "13px";
    
    const countInputWrapper = modeBar.createDiv();
    countInputWrapper.style.display = "flex";
    countInputWrapper.style.alignItems = "center";
    countInputWrapper.style.gap = "4px";
    
    const countPrefix = countInputWrapper.createEl("span", { text: t('showcase.minCountPrefix') });
    countPrefix.style.fontSize = "13px";
    
    const countInput = countInputWrapper.createEl("input", { type: "number", value: String(this.showcaseMinCount) });
    countInput.style.width = "60px";
    countInput.style.padding = "2px 6px";
    countInput.style.borderRadius = "4px";
    countInput.style.border = "1px solid var(--background-modifier-border)";
    countInput.style.fontSize = "13px";
    countInput.min = "1";
    
    const countSuffix = countInputWrapper.createEl("span", { text: t('showcase.minCountSuffix') });
    countSuffix.style.fontSize = "13px";
    
    sourceSelect.addEventListener("change", async () => {
      this.sourceFilter = sourceSelect.value;
      this.plugin.settings.showcaseSourceFilter = this.sourceFilter;
      await this.plugin.saveData(this.plugin.settings);
      this.showLoading();
      await this.loadAllRules();
      this.hideLoading();
      this.sortRules();
      this.renderTable();
    });
    
    globalCheckbox.addEventListener("change", async () => {
      this.showGlobalRules = globalCheckbox.checked;
      this.plugin.settings.showcaseShowGlobal = this.showGlobalRules;
      await this.plugin.saveData(this.plugin.settings);
      this.showLoading();
      await this.loadAllRules();
      this.hideLoading();
      this.sortRules();
      this.renderTable();
    });
    
    // 字数范围筛选事件
    const handleLengthFilter = async () => {
      const minVal = parseInt(minInput.value, 10) || 0;
      const maxVal = parseInt(maxInput.value, 10) || 0;
      
      this.minLength = minVal;
      this.maxLength = maxVal;
      
      this.plugin.settings.showcaseMinLength = minVal;
      this.plugin.settings.showcaseMaxLength = maxVal;
      await this.plugin.saveData(this.plugin.settings);
      
      this.renderTable();
    };
    
    minInput.addEventListener("change", handleLengthFilter);
    maxInput.addEventListener("change", handleLengthFilter);
    
    countInput.addEventListener("change", async () => {
      const val = parseInt(countInput.value, 10);
      if (isNaN(val) || val < 1) {
        countInput.value = String(this.showcaseMinCount);
        return;
      }
      this.showcaseMinCount = val;
      this.plugin.settings.showcaseMinCount = val;
      await this.plugin.saveData(this.plugin.settings);
      this.showLoading();
      await this.loadAllRules();
      this.hideLoading();
      this.sortRules();
      this.renderTable();
      statsEl.textContent = t('showcase.totalCount') + ` ${this.allRules.length}`;
    });
    
    const toolbar = contentEl.createDiv();
    toolbar.style.display = "flex";
    toolbar.style.alignItems = "center";
    toolbar.style.gap = "12px";
    toolbar.style.marginBottom = "12px";
    toolbar.style.flexWrap = "wrap";
    toolbar.style.flexShrink = "0";
    
    this.createToggleCheckbox(toolbar, t('showcase.showStyleName'), this.showStyleName, (e) => {
      this.showStyleName = e.target.checked;
      this.renderTable();
    });
    
    this.createToggleCheckbox(toolbar, t('showcase.showSource'), this.showSource, (e) => {
      this.showSource = e.target.checked;
      this.renderTable();
    });
    
    this.createToggleCheckbox(toolbar, t('showcase.showTimestamp'), this.showTimestamp, (e) => {
      this.showTimestamp = e.target.checked;
      this.renderTable();
    });
    
    this.createToggleCheckbox(toolbar, t('showcase.showRemark'), this.showRemark, (e) => {
      this.showRemark = e.target.checked;
      this.renderTable();
    });
    
    const statsEl = toolbar.createEl("span");
    statsEl.textContent = t('showcase.totalCount') + ` ${this.allRules.length}`;
    statsEl.style.fontSize = "13px";
    statsEl.style.color = "var(--text-muted)";
    statsEl.style.marginLeft = "auto";
    this.statsEl = statsEl;
    
    } // end desktop else
    
    this.tableContainer = contentEl.createDiv();
    this.tableContainer.style.overflowY = "auto";
    this.tableContainer.style.border = "1px solid var(--background-modifier-border)";
    this.tableContainer.style.borderRadius = "4px";
    this.tableContainer.style.flex = "1";
    this.tableContainer.style.minHeight = "0";
    
    this.tableContainer.addEventListener("scroll", () => {
      this.scrollPosition = this.tableContainer.scrollTop;
    });
    
    contentEl.style.display = "flex";
    contentEl.style.flexDirection = "column";
    contentEl.style.overflow = "hidden";
    contentEl.style.height = this.modalHeight ? `${this.modalHeight - 80}px` : 'calc(90vh - 80px)';
    
    this.sortRules();
    this.renderTable();
    
    if (this.scrollPosition > 0) {
      const scrollPos = this.scrollPosition;
      const restoreScroll = () => {
        if (this.tableContainer) {
          this.tableContainer.scrollTop = scrollPos;
        }
      };
      requestAnimationFrame(restoreScroll);
      setTimeout(restoreScroll, 50);
      setTimeout(restoreScroll, 150);
      setTimeout(restoreScroll, 300);
      setTimeout(restoreScroll, 500);
    }
  }

  renderTable() {
    this.tableContainer.empty();
    
    // 应用字数范围筛选
    const filteredRules = this.allRules.filter(rule => {
      const textLength = rule.text.length;
      if (this.minLength > 0 && textLength < this.minLength) return false;
      if (this.maxLength > 0 && textLength > this.maxLength) return false;
      for (const [key, filterText] of Object.entries(this.columnFilters)) {
        if (!filterText) continue;
        const lowerFilter = filterText.toLowerCase();
        let cellValue = '';
        if (key === 'text') cellValue = rule.text;
        else if (key === 'styleName') {
          cellValue = rule.styleName;
          const btnText = this.plugin.buttonTexts?.[rule.styleName] || '';
          if (btnText) cellValue += ' ' + btnText;
        }
        else if (key === 'source') cellValue = rule.source;
        else if (key === 'timestamp') cellValue = this.formatTimestamp(rule.timestamp);
        else if (key === 'remark') cellValue = rule.remark || '';
        if (!cellValue.toLowerCase().includes(lowerFilter)) return false;
      }
      return true;
    });
    
    // 手机端：列表式布局，备注折叠
    if (!_isDesktop) {
      if (filteredRules.length === 0) {
        const emptyMsg = this.tableContainer.createEl("div");
        emptyMsg.textContent = t('showcase.noData');
        emptyMsg.style.padding = "20px";
        emptyMsg.style.textAlign = "center";
        emptyMsg.style.color = "var(--text-muted)";
        return;
      }
      filteredRules.forEach((rule, index) => {
        const item = this.tableContainer.createDiv();
        item.style.padding = "8px 12px";
        item.style.borderBottom = "1px solid var(--background-modifier-border)";
        item.style.backgroundColor = index % 2 === 0 ? "var(--background-primary)" : "var(--background-secondary)";
        item.style.cursor = "pointer";
        
        // 高亮文本行
        const textRow = item.createDiv();
        textRow.style.display = "flex";
        textRow.style.alignItems = "flex-start";
        textRow.style.gap = "6px";
        
        // 高亮文本容器：让样式只作用于文本实际范围
        const textWrapper = textRow.createDiv();
        textWrapper.style.flex = "1";
        textWrapper.style.minWidth = "0";
        
        const styledText = textWrapper.createEl("span");
        styledText.textContent = rule.text;
        styledText.className = rule.styleName;
        const inlineStyle = this.plugin.cssStyles?.get(rule.styleName) || '';
        if (inlineStyle) {
          styledText.setAttribute("style", inlineStyle);
        }
        styledText.style.display = "inline";
        styledText.style.wordBreak = "break-word";
        styledText.style.whiteSpace = "pre-wrap";
        
        // 样式名标签
        const styleTag = textRow.createEl("span");
        styleTag.textContent = rule.styleName;
        styleTag.style.fontSize = "10px";
        styleTag.style.color = "var(--text-muted)";
        styleTag.style.backgroundColor = "var(--background-secondary)";
        styleTag.style.padding = "1px 4px";
        styleTag.style.borderRadius = "3px";
        styleTag.style.whiteSpace = "nowrap";
        styleTag.style.flexShrink = "0";
        const btnText = this.plugin.buttonTexts?.[rule.styleName] || '';
        if (btnText) {
          styleTag.textContent = rule.styleName + ' / ' + btnText;
        }
        
        // 来源标签
        if (this.showSource && rule.source) {
          const sourceTag = textRow.createEl("span");
          sourceTag.textContent = rule.source;
          sourceTag.style.fontSize = "10px";
          sourceTag.style.color = rule.source === t('main.globalRule') ? 'var(--text-accent)' : 'var(--text-muted)';
          sourceTag.style.flexShrink = "0";
        }
        
        // 备注折叠指示
        if (this.showRemark && rule.remark) {
          const expandIcon = textRow.createEl("span");
          expandIcon.textContent = "▸";
          expandIcon.style.fontSize = "10px";
          expandIcon.style.color = "var(--text-muted)";
          expandIcon.style.flexShrink = "0";
          expandIcon.style.transition = "transform 0.15s";
          
          // 折叠的备注区域
          const remarkArea = item.createDiv();
          remarkArea.style.display = "none";
          remarkArea.style.marginTop = "4px";
          remarkArea.style.padding = "4px 8px";
          remarkArea.style.fontSize = "12px";
          remarkArea.style.color = "var(--text-muted)";
          remarkArea.style.backgroundColor = "var(--background-secondary)";
          remarkArea.style.borderRadius = "4px";
          remarkArea.style.wordBreak = "break-word";
          
          const hasImage = /!\[\[.*?\]\]/.test(rule.remark) || /!\[.*?\]\(.*?\)/.test(rule.remark);
          if (hasImage) {
            const textPart = rule.remark.replace(/!\[\[.*?\]\]/g, '').replace(/!\[.*?\]\(.*?\)/g, '').trim();
            const imgCount = (rule.remark.match(/!\[\[.*?\]\]/g) || []).length + (rule.remark.match(/!\[.*?\]\(.*?\)/g) || []).length;
            remarkArea.textContent = textPart ? `${textPart} 📷×${imgCount}` : `📷 ` + t('main.image') + `×${imgCount}`;
          } else {
            remarkArea.textContent = rule.remark;
          }
          
          let expanded = false;
          item.addEventListener("click", () => {
            expanded = !expanded;
            remarkArea.style.display = expanded ? "block" : "none";
            expandIcon.textContent = expanded ? "▾" : "▸";
          });
        } else {
          // 无备注时双击跳转
          item.addEventListener("dblclick", () => {
            this.jumpToText(rule);
          });
        }
        
        // 时间
        if (this.showTimestamp && rule.timestamp) {
          const timeRow = item.createDiv();
          timeRow.textContent = this.formatTimestamp(rule.timestamp);
          timeRow.style.fontSize = "10px";
          timeRow.style.color = "var(--text-muted)";
          timeRow.style.marginTop = "2px";
        }
      });
      
    } else {
    // 桌面端：原有表格布局
    const table = this.tableContainer.createEl("table");
    table.style.width = "100%";
    table.style.borderCollapse = "collapse";
    table.style.fontSize = "13px";
    table.style.tableLayout = "fixed";
    
    const thead = table.createEl("thead");
    const headerRow = thead.createEl("tr");
    headerRow.style.backgroundColor = "var(--background-secondary)";
    headerRow.style.position = "sticky";
    headerRow.style.top = "0";
    
    const columns = [
      { key: "text", text: t('showcase.text'), show: true },
      { key: "styleName", text: t('showcase.styleName'), show: this.showStyleName },
      { key: "source", text: t('showcase.source'), show: this.showSource },
      { key: "timestamp", text: t('showcase.time'), show: this.showTimestamp },
      { key: "remark", text: t('showcase.remark'), show: this.showRemark }
    ];
    
    const visibleColumns = columns.filter(col => col.show);
    const defaultWidth = `${100 / visibleColumns.length}%`;
    
    columns.forEach(col => {
      if (col.show) {
        const th = headerRow.createEl("th");
        th.style.padding = "8px 12px";
        th.style.textAlign = "left";
        th.style.borderBottom = "2px solid var(--background-modifier-border)";
        th.style.width = this.columnWidths[col.key] || defaultWidth;
        th.style.position = "relative";
        th.dataset.column = col.key;
        
        // 表头内容容器
        const headerContent = th.createDiv();
        headerContent.style.display = "flex";
        headerContent.style.alignItems = "center";
        headerContent.style.gap = "2px";
        
        // 搜索框替代表头文字
        const searchInput = headerContent.createEl("input", { type: "text" });
        searchInput.placeholder = col.text;
        searchInput.value = this.columnFilters[col.key] || '';
        searchInput.style.width = "100%";
        searchInput.style.padding = "2px 6px";
        searchInput.style.borderRadius = "3px";
        searchInput.style.border = "1px solid var(--background-modifier-border)";
        searchInput.style.fontSize = "12px";
        searchInput.style.backgroundColor = "var(--background-primary)";
        searchInput.style.color = "var(--text-normal)";
        searchInput.style.outline = "none";
        
        searchInput.addEventListener("input", () => {
          this.columnFilters[col.key] = searchInput.value;
          this._activeFilterKey = col.key;
          this._activeFilterCursor = searchInput.selectionStart;
          this.renderTable();
        });
        
        searchInput.addEventListener("click", (e) => {
          e.stopPropagation();
        });
        
        if (this._activeFilterKey === col.key) {
          requestAnimationFrame(() => {
            searchInput.focus();
            if (this._activeFilterCursor != null) {
              searchInput.setSelectionRange(this._activeFilterCursor, this._activeFilterCursor);
            }
          });
          this._activeFilterKey = null;
          this._activeFilterCursor = null;
        }
        
        // 排序按钮 - 使用 span 替代 button，完全去掉按钮样式
        const sortBtn = headerContent.createEl("span");
        sortBtn.style.cursor = "pointer";
        sortBtn.style.marginLeft = "4px";
        sortBtn.style.fontSize = "11px";
        sortBtn.style.lineHeight = "1";
        sortBtn.style.opacity = "0.5";
        sortBtn.style.transition = "opacity 0.15s";
        sortBtn.style.userSelect = "none";
        
        if (this.sortBy === col.key) {
          sortBtn.textContent = this.sortOrder === 'asc' ? '↑' : '↓';
          sortBtn.style.color = 'var(--interactive-accent)';
          sortBtn.style.opacity = "1";
        } else {
          sortBtn.textContent = '↕';
          sortBtn.style.color = 'var(--text-muted)';
        }
        
        sortBtn.addEventListener("mouseenter", () => {
          sortBtn.style.opacity = "1";
        });
        
        sortBtn.addEventListener("mouseleave", () => {
          if (this.sortBy !== col.key) {
            sortBtn.style.opacity = "0.5";
          }
        });
        
        sortBtn.addEventListener("click", async () => {
          if (this.sortBy === col.key) {
            this.sortOrder = this.sortOrder === 'asc' ? 'desc' : 'asc';
          } else {
            this.sortBy = col.key;
            this.sortOrder = 'asc';
          }
          this.sortRules();
          this.renderTable();
          await this.saveSettings();
        });
        
        const resizer = th.createDiv();
        resizer.style.position = "absolute";
        resizer.style.right = "-2px";
        resizer.style.top = "0";
        resizer.style.bottom = "0";
        resizer.style.width = "4px";
        resizer.style.cursor = "col-resize";
        resizer.style.backgroundColor = "var(--background-modifier-border)";
        resizer.style.zIndex = "1";
        
        resizer.addEventListener("mouseenter", () => {
          resizer.style.backgroundColor = "var(--interactive-accent)";
          resizer.style.width = "4px";
        });
        
        resizer.addEventListener("mouseleave", () => {
          resizer.style.backgroundColor = "var(--background-modifier-border)";
        });
        
        let startX, startWidth, nextTh, nextStartWidth;
        
        resizer.addEventListener("mousedown", (e) => {
          startX = e.pageX;
          startWidth = th.offsetWidth;
          nextTh = th.nextElementSibling;
          nextStartWidth = nextTh ? nextTh.offsetWidth : 0;
          
          const tableWidth = table.offsetWidth;
          
          const onMouseMove = (e) => {
            const dx = e.pageX - startX;
            const newWidth = Math.max(50, startWidth + dx);
            const newNextWidth = nextTh ? Math.max(50, nextStartWidth - dx) : 0;
            if (nextTh && newNextWidth < 50) return;
            th.style.width = newWidth + 'px';
            this.columnWidths[col.key] = (newWidth / tableWidth * 100).toFixed(1) + '%';
            if (nextTh) {
              const nextCol = columns.find(c => c.key === nextTh.dataset.column);
              if (nextCol) {
                nextTh.style.width = newNextWidth + 'px';
                this.columnWidths[nextCol.key] = (newNextWidth / tableWidth * 100).toFixed(1) + '%';
              }
            }
          };
          
          const onMouseUp = async () => {
            document.removeEventListener("mousemove", onMouseMove);
            document.removeEventListener("mouseup", onMouseUp);
            await this.saveSettings();
          };
          
          document.addEventListener("mousemove", onMouseMove);
          document.addEventListener("mouseup", onMouseUp);
          e.preventDefault();
          e.stopPropagation();
        });
      }
    });
    
    const tbody = table.createEl("tbody");
    
    if (filteredRules.length === 0) {
      const emptyRow = tbody.createEl("tr");
      const emptyCell = emptyRow.createEl("td");
      emptyCell.colSpan = visibleColumns.length;
      emptyCell.textContent = t('showcase.noData');
      emptyCell.style.padding = "20px";
      emptyCell.style.textAlign = "center";
      emptyCell.style.color = "var(--text-muted)";
    }
    
    const fragment = document.createDocumentFragment();
    
    filteredRules.forEach((rule, index) => {
      const row = document.createElement("tr");
      row.dataset.index = index;
      row.style.backgroundColor = index % 2 === 0 ? "var(--background-primary)" : "var(--background-secondary)";
      
      const textCell = document.createElement("td");
      textCell.style.padding = "8px 12px";
      textCell.style.borderBottom = "1px solid var(--background-modifier-border)";
      textCell.style.wordBreak = "break-word";
      textCell.style.cursor = "pointer";
      textCell.title = t('showcase.dblClickJump');
      textCell.dataset.action = "jump";
      textCell.dataset.ruleIndex = index;
      
      const styledText = document.createElement("span");
      styledText.textContent = rule.text;
      styledText.className = rule.styleName;
      
      const inlineStyle = this.plugin.cssStyles?.get(rule.styleName) || '';
      if (inlineStyle) {
        styledText.setAttribute("style", inlineStyle);
      }
      textCell.appendChild(styledText);
      row.appendChild(textCell);
      
      if (this.showStyleName) {
        const styleNameCell = document.createElement("td");
        styleNameCell.style.padding = "8px 12px";
        styleNameCell.style.borderBottom = "1px solid var(--background-modifier-border)";
        styleNameCell.style.fontFamily = "monospace";
        styleNameCell.style.fontSize = "12px";
        styleNameCell.style.wordBreak = "break-all";
        const nameSpan = document.createElement("div");
        nameSpan.textContent = rule.styleName;
        styleNameCell.appendChild(nameSpan);
        const btnText = this.plugin.buttonTexts?.[rule.styleName] || '';
        if (btnText) {
          const displaySpan = document.createElement("div");
          displaySpan.textContent = btnText;
          displaySpan.style.fontSize = "11px";
          displaySpan.style.color = "var(--text-muted)";
          displaySpan.style.marginTop = "2px";
          styleNameCell.appendChild(displaySpan);
        }
        row.appendChild(styleNameCell);
      }
      
      if (this.showSource) {
        const sourceCell = document.createElement("td");
        sourceCell.textContent = rule.source;
        sourceCell.style.padding = "8px 12px";
        sourceCell.style.borderBottom = "1px solid var(--background-modifier-border)";
        sourceCell.style.fontSize = "12px";
        sourceCell.style.color = rule.source === t('main.globalRule') ? 'var(--text-accent)' : 'var(--text-muted)';
        row.appendChild(sourceCell);
      }
      
      if (this.showTimestamp) {
        const timeCell = document.createElement("td");
        timeCell.textContent = this.formatTimestamp(rule.timestamp);
        timeCell.style.padding = "8px 12px";
        timeCell.style.borderBottom = "1px solid var(--background-modifier-border)";
        timeCell.style.fontSize = "12px";
        timeCell.style.color = "var(--text-muted)";
        row.appendChild(timeCell);
      }
      
      if (this.showRemark) {
        const remarkCell = document.createElement("td");
        remarkCell.style.padding = "8px 12px";
        remarkCell.style.borderBottom = "1px solid var(--background-modifier-border)";
        remarkCell.style.fontSize = "12px";
        remarkCell.style.color = "var(--text-muted)";
        remarkCell.style.wordBreak = "break-word";
        if (rule.remark) {
          const hasImage = /!\[\[.*?\]\]/.test(rule.remark) || /!\[.*?\]\(.*?\)/.test(rule.remark);
          if (hasImage) {
            const textPart = rule.remark.replace(/!\[\[.*?\]\]/g, '').replace(/!\[.*?\]\(.*?\)/g, '').trim();
            const imgCount = (rule.remark.match(/!\[\[.*?\]\]/g) || []).length + (rule.remark.match(/!\[.*?\]\(.*?\)/g) || []).length;
            remarkCell.textContent = textPart ? `${textPart} 📷×${imgCount}` : `📷 ` + t('main.image') + `×${imgCount}`;
          } else {
            remarkCell.textContent = rule.remark;
          }
        } else {
          remarkCell.textContent = '-';
        }
        row.appendChild(remarkCell);
      }
      
      fragment.appendChild(row);
    });
    
    tbody.appendChild(fragment);
    
    tbody.addEventListener("mouseover", (e) => {
      const row = e.target.closest("tr");
      if (row && row.dataset.index !== undefined) {
        row.style.backgroundColor = "var(--background-modifier-hover)";
      }
    });
    
    tbody.addEventListener("mouseout", (e) => {
      const row = e.target.closest("tr");
      if (row && row.dataset.index !== undefined) {
        row.style.backgroundColor = parseInt(row.dataset.index) % 2 === 0 ? "var(--background-primary)" : "var(--background-secondary)";
      }
    });
    
    tbody.addEventListener("dblclick", (e) => {
      const cell = e.target.closest("td[data-action='jump']");
      if (cell) {
        const idx = parseInt(cell.dataset.ruleIndex);
        if (filteredRules[idx]) {
          this.jumpToText(filteredRules[idx]);
        }
      }
    });
    
    // 更新统计显示
    if (this.statsEl) {
      this.statsEl.textContent = t('showcase.filteredCount') + ` ${filteredRules.length} ` + t('showcase.totalLabel') + ` ${this.allRules.length}`;
    }
    } // end desktop else
  }

  onClose() {
    if (this.plugin && this.plugin.settings) {
      if (!this.plugin.settings.showcaseModal) {
        this.plugin.settings.showcaseModal = {};
      }
      this.plugin.settings.showcaseModal.scrollPosition = this.scrollPosition;
      this.plugin.saveData(this.plugin.settings);
    }
    const { contentEl } = this;
    contentEl.empty();
  }
}

// 实体提取模态框类
class EntityExtractionModal extends Modal {
  constructor(app, selectedText, plugin) {
    super(app);
    this.selectedText = selectedText;
    this.plugin = plugin;
    this.extractedEntities = [];
    this.selectedEntity = null;
    this.selectedStyle = null;
    this.entityStyleMap = new Map();
    this.angle0Styles = [];
    
    // 保存编辑器选区位置，以便关闭后恢复
    const { MarkdownView } = require('obsidian');
    const activeView = app.workspace.getActiveViewOfType(MarkdownView);
    if (activeView?.editor) {
      const selection = activeView.editor.listSelections()[0];
      if (selection) {
        this.selectionStart = { line: selection.anchor.line, ch: selection.anchor.ch };
        this.selectionEnd = { line: selection.head.line, ch: selection.head.ch };
      }
    }
  }

  async onOpen() {
    const { contentEl } = this;
    contentEl.empty();
    contentEl.addClass("entity-extraction-modal");
    
    // 设置内容区域样式，避免横向滚动
    contentEl.style.boxSizing = "border-box";
    contentEl.style.padding = "10px";
    contentEl.style.overflowY = "hidden"; // 禁止垂直滚动，改为内部容器滚动
    contentEl.style.overflowX = "hidden"; // 禁止横向滚动
    contentEl.style.display = "flex";
    contentEl.style.flexDirection = "column";
    contentEl.style.height = "100%";
    
    // 标题和宽度设置
    const titleContainer = contentEl.createDiv();
    titleContainer.style.display = "flex";
    titleContainer.style.alignItems = "center";
    titleContainer.style.justifyContent = "space-between";
    titleContainer.style.marginBottom = "20px";
    
    // 标题
    const titleEl = titleContainer.createEl("h2", { text: t('entity.title') });
    titleEl.style.margin = "0";
    
    // 阻止标题行滚动
    titleContainer.addEventListener("wheel", (e) => {
      e.stopPropagation();
    }, { passive: false });
    
    // 透明度设置
    const opacityContainer = titleContainer.createDiv();
    opacityContainer.style.display = "flex";
    opacityContainer.style.alignItems = "center";
    opacityContainer.style.gap = "8px";
    
    const opacityLabel = opacityContainer.createEl("span", { text: t('main.opacity') + ": " });
    opacityLabel.style.fontSize = "14px";
    
    const opacityInput = opacityContainer.createEl("input", { type: "number", attr: { step: 5, min: 20, max: 100 } });
    opacityInput.style.width = "60px";
    opacityInput.style.padding = "4px 8px";
    opacityInput.style.border = "1px solid var(--background-modifier-border)";
    opacityInput.style.borderRadius = "4px";
    opacityInput.style.fontSize = "14px";
    opacityInput.title = t('settings.ctrlScrollOpacity');
    const defaultOpacity = Math.max(20, Math.min(100, this.plugin.settings?.entityModalOpacity || 100));
    opacityInput.value = defaultOpacity;
    
    const opacityUnit = opacityContainer.createEl("span", { text: "%" });
    opacityUnit.style.fontSize = "14px";
    
    opacityInput.addEventListener("input", async () => {
      const opacity = parseInt(opacityInput.value);
      if (!isNaN(opacity) && opacity >= 20 && opacity <= 100) {
        this.modalEl.style.opacity = opacity / 100;
        this.plugin.settings.entityModalOpacity = opacity;
        await this.plugin.saveData(this.plugin.settings);
      }
    });
    
    // 为透明度输入框添加滚轮事件
    opacityInput.addEventListener("wheel", (e) => {
      e.preventDefault();
      const step = e.deltaY > 0 ? -5 : 5;
      let opacity = parseInt(opacityInput.value) || defaultOpacity;
      opacity = Math.max(20, Math.min(100, opacity + step));
      opacityInput.value = opacity;
      this.modalEl.style.opacity = opacity / 100;
      this.plugin.settings.entityModalOpacity = opacity;
      this.plugin.saveData(this.plugin.settings);
    }, { passive: false });
    
    // 保存对 opacityInput 和 defaultOpacity 的引用，用于全局滚轮事件
    const self = this;
    
    // 添加全局 Ctrl+滚轮事件监听（在模态框范围内）
    this.modalEl.addEventListener("wheel", (e) => {
      if (e.ctrlKey) {
        e.preventDefault();
        const step = e.deltaY > 0 ? -5 : 5;
        let opacity = parseInt(opacityInput.value) || defaultOpacity;
        opacity = Math.max(20, Math.min(100, opacity + step));
        opacityInput.value = opacity;
        self.modalEl.style.opacity = opacity / 100;
        self.plugin.settings.entityModalOpacity = opacity;
        self.plugin.saveData(self.plugin.settings);
      } else if (e.altKey) {
        e.preventDefault();
        const step = e.deltaY > 0 ? -10 : 10;
        let width = parseInt(widthInput.value) || defaultWidth;
        width = Math.max(400, Math.min(4096, width + step));
        widthInput.value = width;
        const contentWidth = width - 30;
        contentEl.style.maxWidth = `${contentWidth}px`;
        contentEl.style.width = `${contentWidth}px`;
        self.modalEl.style.width = `${width}px`;
        self.modalEl.style.maxWidth = `${width}px`;
        self.plugin.settings.modalWidth = width;
        self.plugin.saveData(self.plugin.settings);
      }
    }, { passive: false });
    
    opacityInput.addEventListener("blur", () => {
      const opacity = parseInt(opacityInput.value);
      if (isNaN(opacity) || opacity < 20 || opacity > 100) {
        opacityInput.value = defaultOpacity;
        this.modalEl.style.opacity = defaultOpacity / 100;
      }
    });
    
    // 应用初始透明度
    this.modalEl.style.opacity = defaultOpacity / 100;
    
    // 预览字体大小设置UI
    const fontSizeContainer = titleContainer.createDiv();
    fontSizeContainer.style.display = "flex";
    fontSizeContainer.style.alignItems = "center";
    fontSizeContainer.style.gap = "8px";
    
    const fontSizeLabel = fontSizeContainer.createEl("span", { text: t('settings.previewFontSize') + ': ' });
    fontSizeLabel.style.fontSize = "14px";
    
    const fontSizeInput = fontSizeContainer.createEl("input", { type: "number", attr: { step: 1 } });
    fontSizeInput.style.width = "50px";
    fontSizeInput.style.padding = "4px 8px";
    fontSizeInput.style.border = "1px solid var(--background-modifier-border)";
    fontSizeInput.style.borderRadius = "4px";
    fontSizeInput.style.fontSize = "14px";
    this.defaultFontSize = this.plugin.settings?.entityPreviewFontSize || 14;
    fontSizeInput.value = this.defaultFontSize;
    this.previewFontSize = this.defaultFontSize;
    this.fontSizeInput = fontSizeInput;
    
    const fontSizeUnit = fontSizeContainer.createEl("span", { text: "px" });
    fontSizeUnit.style.fontSize = "14px";
    
    // 宽度设置
    const widthContainer = titleContainer.createDiv();
    widthContainer.style.display = "flex";
    widthContainer.style.alignItems = "center";
    widthContainer.style.gap = "8px";
    
    const widthLabel = widthContainer.createEl("span", { text: t('main.width') + ": " });
    widthLabel.style.fontSize = "14px";
    
    const widthInput = widthContainer.createEl("input", { type: "number", attr: { step: 5 } });
    widthInput.style.width = "80px";
    widthInput.style.padding = "4px 8px";
    widthInput.style.border = "1px solid var(--background-modifier-border)";
    widthInput.style.borderRadius = "4px";
    widthInput.style.fontSize = "14px";
    widthInput.title = t('settings.altScrollWidth');
    // 使用plugin.settings.modalWidth作为默认值
    const savedModalWidth = this.plugin.settings?.modalWidth || 600;
    const defaultWidth = _isDesktop ? savedModalWidth : Math.min(savedModalWidth, window.innerWidth - 20);
    widthInput.value = savedModalWidth;
    // 设置初始窗口宽度，与主模态框保持一致
    const contentWidth = defaultWidth - 30; // 减去边距
    contentEl.style.maxWidth = `${contentWidth}px`;
    contentEl.style.width = `${contentWidth}px`;
    
    // 同时设置modalEl的宽度，与主模态框保持一致
    this.modalEl.style.width = `${defaultWidth}px`;
    this.modalEl.style.maxWidth = `${defaultWidth}px`;
    this.modalEl.style.minWidth = "400px"; // 设置最小宽度
    this.modalEl.style.maxHeight = "80vh"; // 限制模态框高度
    
    // 单位
    const widthUnit = widthContainer.createEl("span", { text: "px" });
    widthUnit.style.fontSize = "14px";
    
    // 实时更新宽度（使用节流避免频繁渲染）
    let widthUpdateTimeout = null;
    widthInput.addEventListener("input", () => {
      if (widthUpdateTimeout) {
        clearTimeout(widthUpdateTimeout);
      }
      
      widthUpdateTimeout = setTimeout(async () => {
        const width = parseInt(widthInput.value);
        if (!isNaN(width) && width >= 400 && width <= 4096) {
          const contentWidth = width - 30;
          contentEl.style.maxWidth = `${contentWidth}px`;
          contentEl.style.width = `${contentWidth}px`;
          this.modalEl.style.width = `${width}px`;
          this.modalEl.style.maxWidth = `${width}px`;
          this.plugin.settings.modalWidth = width;
          await this.plugin.saveData(this.plugin.settings);
        }
      }, 300);
    });
    
    widthInput.addEventListener("wheel", (e) => {
      e.preventDefault();
      const step = e.deltaY > 0 ? -10 : 10;
      let width = parseInt(widthInput.value) || defaultWidth;
      width = Math.max(400, Math.min(4096, width + step));
      widthInput.value = width;
      const contentWidth = width - 30;
      contentEl.style.maxWidth = `${contentWidth}px`;
      contentEl.style.width = `${contentWidth}px`;
      this.modalEl.style.width = `${width}px`;
      this.modalEl.style.maxWidth = `${width}px`;
      this.plugin.settings.modalWidth = width;
      this.plugin.saveData(this.plugin.settings);
    }, { passive: false });
    
    widthInput.addEventListener("blur", () => {
      const width = parseInt(widthInput.value);
      if (isNaN(width) || width < 400 || width > 4096) {
        widthInput.value = defaultWidth;
        const contentWidth = defaultWidth - 30;
        contentEl.style.maxWidth = `${contentWidth}px`;
        contentEl.style.width = `${contentWidth}px`;
        this.modalEl.style.width = `${defaultWidth}px`;
        this.modalEl.style.maxWidth = `${defaultWidth}px`;
      }
    });
    
    setupModalResizeHandle(this, this.modalEl, widthInput, opacityInput, {
      minWidth: 400, maxWidth: 4096,
      widthStep: 10,
      widthSettingsKey: 'modalWidth',
      opacitySettingsKey: 'entityModalOpacity'
    });
    
    // 创建加载提示
    const loadingEl = contentEl.createDiv();
    loadingEl.textContent = t('entity.extracting');
    loadingEl.style.textAlign = "center";
    loadingEl.style.padding = "20px";
    
    try {
      // 提取实体
      await this.extractEntities();
      
      // 加载实体样式
      const entityStyles = await this.loadEntityStyles();
      
      // 将提取的实体与样式对应起来
      this.extractedEntities.forEach(entity => {
        let matchedStyle = null;
        
        // 检查实体名称是否在样式文件中（精确匹配）
        if (entityStyles[entity.name]) {
          matchedStyle = entityStyles[entity.name];
          console.log(`为实体 "${entity.name}" 找到精确匹配的样式: ${matchedStyle.className}`);
        } else {
          // 搜索样式文件中的regex字段，支持正则表达式匹配
          for (const [regexPattern, style] of Object.entries(entityStyles)) {
            try {
              // 创建正则表达式对象
              const regex = new RegExp(regexPattern);
              // 测试实体名称是否匹配正则表达式
              if (regex.test(entity.name)) {
                matchedStyle = style;
                console.log(`为实体 "${entity.name}" 找到正则匹配的样式: ${style.className} (正则: ${regexPattern})`);
                break;
              }
            } catch (error) {
              console.error(`正则表达式 "${regexPattern}" 无效:`, error);
              // 如果正则表达式无效，尝试精确匹配
              if (entity.name === regexPattern) {
                matchedStyle = style;
                console.log(`为实体 "${entity.name}" 找到精确匹配的样式: ${style.className}`);
                break;
              }
            }
          }
        }
        
        // 如果找到匹配的样式，存储到entityStyleMap
        if (matchedStyle) {
          this.entityStyleMap.set(entity.name, matchedStyle);
        }
      });
      
      // 加载角标为0的样式
      await this.loadAngle0Styles();
      
      // 移除加载提示
      loadingEl.remove();
      
      // 渲染实体和样式
      await this.renderContent();
    } catch (error) {
      console.error("实体提取错误:", error);
      loadingEl.textContent = t('main.entityExtractFailed') + ': ' + error.message;
      loadingEl.style.color = "red";
    }
  }

  async extractEntities() {
    if (!this.selectedText || !this.selectedText.trim()) {
      throw new Error(t('entity.selectTextFirst'));
    }
    
    // 构建提示词
    const prompt = `请从以下文本中提取所有的人名和地名，以JSON格式返回：

${this.selectedText}

返回格式：
{
  "persons": ["人名1", "人名2"],
  "places": ["地名1", "地名2"]
}`;
    
    // 调用AI API
    const response = await this.plugin.callAI(prompt);
    
    // 解析AI响应
    try {
      // 提取JSON部分
      const jsonMatch = response.match(/\{[\s\S]*\}/);
      if (jsonMatch) {
        const parsed = JSON.parse(jsonMatch[0]);
        
        // 合并人名和地名
        const persons = parsed.persons || [];
        const places = parsed.places || [];
        
        // 去重并添加类型
        const uniqueEntities = new Set();
        persons.forEach(person => {
          if (person && person.trim()) {
            uniqueEntities.add({ name: person.trim(), type: "person" });
          }
        });
        places.forEach(place => {
          if (place && place.trim()) {
            uniqueEntities.add({ name: place.trim(), type: "place" });
          }
        });
        
        this.extractedEntities = Array.from(uniqueEntities);
      } else {
        throw new Error("AI返回格式错误，无法解析实体");
      }
    } catch (parseError) {
      console.error("解析AI响应错误:", parseError);
      throw new Error("无法解析AI返回的实体数据");
    }
  }

  async loadAngle0Styles() {
    try {
      const { MarkdownView } = require('obsidian');
      const activeView = this.plugin.app.workspace.getActiveViewOfType(MarkdownView);
      
      if (!activeView || !activeView.file) {
        return;
      }
      
      const filePath = activeView.file.path;
      const jsonFileName = filePath.replace(/[\/\\]/g, '_').replace(/\.md$/, '_count.json');
      const countJsonPath = this.plugin.app.vault.configDir + '/plugins/Regex-Css-Highlighter/data/' + jsonFileName;
      
      const content = await this.plugin.app.vault.adapter.read(countJsonPath);
      let countData;
      try {
        countData = JSON.parse(content);
      } catch (parseError) {
        return;
      }
      
      if (Array.isArray(countData)) {
        for (let i = 0; i < countData.length; i += 2) {
          const className = countData[i];
          const count = countData[i + 1];
          
          if (count === 0) {
            const style = {
              className: className,
              angle: 0,
              enabled: true
            };
            this.angle0Styles.push(style);
          }
        }
      } else if (typeof countData === 'object' && countData !== null) {
        for (const key in countData) {
          const value = countData[key];
          
          if (Array.isArray(value)) {
            for (let i = 0; i < value.length; i += 2) {
              const className = value[i];
              const count = value[i + 1];
              
              if (count === 0) {
                const style = {
                  className: className,
                  angle: 0,
                  enabled: true
                };
                this.angle0Styles.push(style);
              }
            }
          } else if (value === 0) {
            const style = {
              className: key,
              angle: 0,
              enabled: true
            };
            this.angle0Styles.push(style);
          }
        }
      }
      
      console.log('加载的使用次数为0的样式:', this.angle0Styles);
    } catch (error) {
      console.error('读取count.json文件失败:', error);
    }
  }
  
  fallbackLoadAngle0Styles(styleCategories) {
    // 回退逻辑：加载所有angle为0的样式
    for (const category in styleCategories) {
      const styles = styleCategories[category] || [];
      styles.forEach(style => {
        if (style.angle === 0) {
          this.angle0Styles.push(style);
        }
      });
    }
  }

  async renderContent() {
    const { contentEl } = this;
    
    // 收集所有已应用的样式类
    const appliedStyles = new Set();
    
    // 实体显示区域（固定不滚动）
    const entitiesSection = contentEl.createDiv();
    entitiesSection.style.marginBottom = "20px";
    entitiesSection.style.flexShrink = "0"; // 不允许收缩
    
    const entitiesTitle = entitiesSection.createEl("h3", { text: t('entity.extractedEntities') });
    entitiesTitle.style.marginBottom = "10px";
    entitiesTitle.style.display = "inline";
    
    // 添加实体名称输入框
    const entityNameInput = entitiesSection.createEl("input", { type: "text" });
    entityNameInput.placeholder = t('entity.inputEntityName');
    entityNameInput.style.marginLeft = "15px";
    entityNameInput.style.padding = "6px 10px";
    entityNameInput.style.border = "1px solid var(--background-modifier-border)";
    entityNameInput.style.borderRadius = "4px";
    entityNameInput.style.fontSize = "14px";
    entityNameInput.style.width = "200px";
    entityNameInput.style.verticalAlign = "middle";
    
    // 创建浮动的匹配规则下拉列表
    const ruleDropdown = document.createElement("div");
    ruleDropdown.style.position = "absolute";
    ruleDropdown.style.top = "0";
    ruleDropdown.style.left = "0";
    ruleDropdown.style.width = "200px";
    ruleDropdown.style.maxHeight = "200px";
    ruleDropdown.style.overflowY = "auto";
    ruleDropdown.style.border = "1px solid var(--background-modifier-border)";
    ruleDropdown.style.borderRadius = "4px";
    ruleDropdown.style.backgroundColor = "var(--background-primary)";
    ruleDropdown.style.zIndex = "1000";
    ruleDropdown.style.display = "none"; // 默认隐藏
    ruleDropdown.style.boxShadow = "0 2px 8px rgba(0, 0, 0, 0.15)";
    ruleDropdown.style.pointerEvents = "auto";
    
    // 下拉列表隐藏定时器引用，用于取消之前的定时器
    let hideDropdownTimer = null;
    
    // 添加到文档中
    document.body.appendChild(ruleDropdown);
    
    // 显示匹配的规则列表
    function showMatchingRules(inputValue) {
      // 清空下拉列表
      ruleDropdown.innerHTML = '';
      
      // 搜索匹配的规则
      const matchedRules = this.plugin.rules.filter(rule => {
        try {
          // 检查规则是否包含输入值（简单匹配）
          if (rule.regex.includes(inputValue)) {
            return true;
          }
          // 尝试使用正则表达式匹配
          try {
            const regex = new RegExp(rule.regex);
            return regex.test(inputValue);
          } catch (error) {
            console.error('正则表达式测试失败:', error);
            return false;
          }
        } catch (error) {
          console.error('规则匹配失败:', error);
          return false;
        }
      });
      
      // 如果有匹配的规则，显示下拉列表
      if (matchedRules.length > 0) {
        // 定位下拉列表到输入框下方
        const inputRect = entityNameInput.getBoundingClientRect();
        ruleDropdown.style.top = `${inputRect.bottom + window.scrollY}px`;
        ruleDropdown.style.left = `${inputRect.left + window.scrollX}px`;
        
        matchedRules.forEach(rule => {
          const ruleItem = document.createElement("div");
          ruleItem.textContent = rule.regex;
          ruleItem.style.padding = "6px 10px";
          ruleItem.style.cursor = "pointer";
          ruleItem.style.borderBottom = "1px solid var(--background-modifier-border)";
          
          // 添加点击事件，选择规则
          ruleItem.addEventListener("click", () => {
            entityNameInput.value = rule.regex;
            ruleDropdown.style.display = "none";
          });
          
          // 添加鼠标悬停效果
          ruleItem.addEventListener("mouseover", () => {
            ruleItem.style.backgroundColor = "var(--background-modifier-hover)";
          });
          
          ruleItem.addEventListener("mouseout", () => {
            ruleItem.style.backgroundColor = "transparent";
          });
          
          ruleDropdown.appendChild(ruleItem);
        });
        ruleDropdown.style.display = "block";
      } else {
        ruleDropdown.style.display = "none";
      }
    }
    
    // 输入事件，实时显示匹配的规则
    entityNameInput.addEventListener("input", () => {
      const inputValue = entityNameInput.value.trim();
      if (inputValue) {
        showMatchingRules.call(this, inputValue);
      } else {
        ruleDropdown.style.display = "none";
      }
    });
    
    // 点击其他地方关闭下拉列表
    document.addEventListener("click", (e) => {
      if (!entityNameInput.contains(e.target) && !ruleDropdown.contains(e.target)) {
        ruleDropdown.style.display = "none";
      }
    });
    
    const entitiesContainer = entitiesSection.createDiv();
    entitiesContainer.style.display = "flex";
    entitiesContainer.style.flexWrap = "wrap";
    entitiesContainer.style.gap = "10px";
    entitiesContainer.style.width = "100%";
    entitiesContainer.style.boxSizing = "border-box";
    
    // 字体大小调整事件处理
    const applyFontSize = (fontSize) => {
      entitiesContainer.querySelectorAll("button div").forEach(div => {
        div.style.fontSize = `${fontSize}px`;
      });
      contentEl.querySelectorAll(".entity-style-btn").forEach(btn => {
        btn.style.fontSize = `${fontSize}px`;
      });
    };
    
    this.fontSizeInput.addEventListener("input", async () => {
      const fontSize = parseInt(this.fontSizeInput.value);
      if (!isNaN(fontSize) && fontSize >= 8 && fontSize <= 32) {
        applyFontSize(fontSize);
        this.previewFontSize = fontSize;
        this.plugin.settings.entityPreviewFontSize = fontSize;
        await this.plugin.saveData(this.plugin.settings);
      }
    });
    
    this.fontSizeInput.addEventListener("wheel", (e) => {
      e.preventDefault();
      const step = e.deltaY > 0 ? -1 : 1;
      let fontSize = parseInt(this.fontSizeInput.value) || this.defaultFontSize;
      fontSize = Math.max(8, Math.min(32, fontSize + step));
      this.fontSizeInput.value = fontSize;
      applyFontSize(fontSize);
      this.previewFontSize = fontSize;
      this.plugin.settings.entityPreviewFontSize = fontSize;
      this.plugin.saveData(this.plugin.settings);
    }, { passive: false });
    
    this.fontSizeInput.addEventListener("blur", () => {
      const fontSize = parseInt(this.fontSizeInput.value);
      if (isNaN(fontSize) || fontSize < 8 || fontSize > 32) {
        this.fontSizeInput.value = this.defaultFontSize;
        applyFontSize(this.defaultFontSize);
        this.previewFontSize = this.defaultFontSize;
      }
    });
    
    // Enter键更新实体名称
    entityNameInput.addEventListener("keydown", async (e) => {
      if (e.key === "Enter") {
        // 关闭下拉列表
        ruleDropdown.style.display = "none";
        
        const newName = entityNameInput.value.trim();
        if (!newName) {
          new Notice(t('main.inputEntityName'));
          return;
        }
        
        if (this.selectedEntity) {
          const oldName = this.selectedEntity.name;
          if (oldName !== newName) {
            // 更新实体名称
            this.selectedEntity.name = newName;
            
            // 如果实体有对应的样式，也需要更新entityStyleMap的key
            if (this.entityStyleMap.has(oldName)) {
              const style = this.entityStyleMap.get(oldName);
              this.entityStyleMap.delete(oldName);
              this.entityStyleMap.set(newName, style);
            }
            
            // 更新按钮显示
            const entityBtn = entitiesContainer.querySelector(`button[data-entity="${CSS.escape(oldName)}"]`);
            if (entityBtn) {
              const example = entityBtn.querySelector("div");
              if (example) {
                example.textContent = newName;
              }
              entityBtn.dataset.entity = newName;
            }
            
            // 更新规则中的regex
            const { MarkdownView } = require('obsidian');
            const activeView = this.app.workspace.getActiveViewOfType(MarkdownView);
            if (activeView?.file) {
              const filePath = activeView.file.path;
              // 加载当前文件的规则
              await this.plugin.loadFileRules(filePath);
              
              // 查找旧regex的规则（支持正则表达式）
              let oldRuleIndex = -1;
              let oldRule = null;
              
              // 首先尝试精确匹配
              oldRuleIndex = this.plugin.rules.findIndex(rule => rule.regex === oldName);
              
              // 如果没有找到，尝试使用正则表达式匹配
              if (oldRuleIndex === -1) {
                try {
                  const oldRegex = new RegExp(`^${oldName}$`);
                  oldRuleIndex = this.plugin.rules.findIndex(rule => {
                    try {
                      return oldRegex.test(rule.regex);
                    } catch (error) {
                      return false;
                    }
                  });
                } catch (error) {
                  console.error('正则表达式匹配失败:', error);
                }
              }
              
              if (oldRuleIndex !== -1) {
                oldRule = this.plugin.rules[oldRuleIndex];
                
                // 如果新regex与旧regex相同，不更新
                if (oldRule.regex === newName) {
                  console.log(`新regex与旧regex相同，不更新: ${newName}`);
                } else {
                  // 更新规则的regex
                  oldRule.regex = newName;
                  
                  // 如果新regex已经存在其他规则，合并或处理
                  const newRuleIndex = this.plugin.rules.findIndex(rule => rule.regex === newName);
                  if (newRuleIndex !== -1 && newRuleIndex !== oldRuleIndex) {
                    // 如果新regex已经有规则了，合并cssClass
                    const newRule = this.plugin.rules[newRuleIndex];
                    if (oldRule.cssClass && newRule.cssClass && oldRule.cssClass !== newRule.cssClass) {
                      // 如果两个规则都有cssClass且不同，保留一个
                      // 这里简单地保留新规则的cssClass
                      newRule.cssClass = oldRule.cssClass || newRule.cssClass;
                    }
                    // 删除旧规则
                    this.plugin.rules.splice(oldRuleIndex, 1);
                  }
                  
                  // 保存更新后的规则
                  await this.plugin.saveFileRules(filePath, this.plugin.rules);
                  
                  // 更新规则版本号并触发更新事件
                  this.plugin.rulesVersion++;
                  this.plugin.rulesUpdateEmitter.dispatchEvent(new Event('update'));
                  
                  // 刷新视图
                  this.plugin.refreshCurrentView();
                  setTimeout(() => {
                    this.plugin.refreshCurrentView();
                  }, 100);
                  
                  console.log(`规则已更新: ${oldName} -> ${newName}`);
                }
              } else {
                console.log(`未找到旧规则: ${oldName}`);
              }
            }
            
            new Notice(t('main.entityNameUpdated') + ': ' + newName);
          }
        } else {
          // 没有选中实体时，可以添加新实体
          const newEntity = { name: newName };
          this.extractedEntities.push(newEntity);
          
          // 创建新实体按钮
          const entityBtn = entitiesContainer.createEl("button");
          entityBtn.style.padding = "8px 16px";
          entityBtn.style.cursor = "pointer";
          entityBtn.style.fontSize = "14px";
          entityBtn.style.transition = "all 0.2s";
          entityBtn.style.border = "none";
          entityBtn.style.backgroundColor = "unset";
          entityBtn.dataset.entity = newName;
          
          const entityExample = entityBtn.createDiv();
          entityExample.textContent = newName;
          entityExample.style.whiteSpace = "nowrap";
          entityExample.style.overflow = "visible";
          entityExample.style.textOverflow = "clip";
          entityExample.style.fontSize = `${this.previewFontSize || 14}px`;
          
          // 添加点击事件
          entityBtn.addEventListener("click", () => {
            entitiesContainer.querySelectorAll("button").forEach(btn => {
              btn.style.border = "none";
              btn.style.backgroundColor = "unset";
            });
            
            this.selectedEntity = newEntity;
            entityBtn.style.border = "2px solid var(--interactive-accent)";
            entityBtn.style.backgroundColor = "var(--background-modifier-hover)";
            entityNameInput.value = newName;
            entityNameInput.focus();
          });
          
          // 添加鼠标悬停事件，显示匹配的规则
          entityBtn.addEventListener("mouseover", () => {
            // 搜索规则中是否有匹配的规则
            const matchedRules = this.plugin.rules.filter(rule => {
              try {
                // 检查规则是否包含实体名称（简单匹配）
                if (rule.regex.includes(newName)) {
                  return true;
                }
                // 尝试使用正则表达式匹配
                try {
                  const regex = new RegExp(rule.regex);
                  return regex.test(newName);
                } catch (error) {
                  console.error('正则表达式测试失败:', error);
                  return false;
                }
              } catch (error) {
                console.error('规则匹配失败:', error);
                return false;
              }
            });
            
            // 如果有匹配的规则，在控制台输出
            if (matchedRules.length > 0) {
              console.log('匹配的规则:', matchedRules);
              // 高亮显示匹配的样式按钮
              stylesContainer.querySelectorAll("span").forEach(styleBtn => {
                // 移除之前的高亮状态
                styleBtn.style.boxShadow = "";
              });
              
              // 高亮显示匹配的样式按钮
              matchedRules.forEach(rule => {
                const styleBtn = stylesContainer.querySelector(`span.${rule.cssClass}`);
                if (styleBtn) {
                  styleBtn.style.boxShadow = "0 0 0 2px var(--interactive-accent)";
                }
              });
              
              // 显示匹配的规则列表在实体按钮下方
              // 定位下拉列表到实体按钮下方
              const btnRect = entityBtn.getBoundingClientRect();
              ruleDropdown.style.top = `${btnRect.bottom + window.scrollY}px`;
              ruleDropdown.style.left = `${btnRect.left + window.scrollX}px`;
              
              // 清空下拉列表
              ruleDropdown.innerHTML = '';
              
              // 添加匹配的规则到下拉列表
              matchedRules.forEach(rule => {
                const ruleItem = document.createElement("div");
                ruleItem.textContent = rule.regex;
                ruleItem.style.padding = "6px 10px";
                ruleItem.style.cursor = "pointer";
                ruleItem.style.borderBottom = "1px solid var(--background-modifier-border)";
                
                // 添加点击事件，选择规则并替换实体按钮文字
                ruleItem.addEventListener("click", () => {
                  // 保存旧的实体名称（用于更新entityStyleMap的key）
                  const oldEntityName = newEntity.name;
                  const newEntityName = rule.regex;
                  
                  // 更新实体名称
                  newEntity.name = newEntityName;
                  
                  // 更新实体按钮显示
                  const example = entityBtn.querySelector("div");
                  if (example) {
                    example.textContent = newEntityName;
                  }
                  entityBtn.dataset.entity = newEntityName;
                  
                  // 更新输入框值
                  entityNameInput.value = newEntityName;
                  
                  // 更新entityStyleMap的key：使用旧名称查找，新名称作为key
                  if (this.entityStyleMap.has(oldEntityName)) {
                    const style = this.entityStyleMap.get(oldEntityName);
                    // 删除旧key，添加新key
                    this.entityStyleMap.delete(oldEntityName);
                    this.entityStyleMap.set(newEntityName, style);
                    console.log(`entityStyleMap更新: ${oldEntityName} -> ${newEntityName}, 样式: ${style.className}`);
                  }
                  
                  // 应用样式到文档
                  this.applyStylesToDocument(true);
                  
                  // 关闭下拉列表
                  ruleDropdown.style.display = "none";
                });
                
                // 添加鼠标悬停效果
                ruleItem.addEventListener("mouseover", () => {
                  ruleItem.style.backgroundColor = "var(--background-modifier-hover)";
                });
                
                ruleItem.addEventListener("mouseout", () => {
                  ruleItem.style.backgroundColor = "transparent";
                });
                
                ruleDropdown.appendChild(ruleItem);
              });
              
              // 显示下拉列表
              ruleDropdown.style.display = "block";
            } else {
              // 没有匹配的规则，移除所有样式按钮的高亮状态
              stylesContainer.querySelectorAll("span").forEach(styleBtn => {
                styleBtn.style.boxShadow = "";
              });
              
              // 隐藏规则列表
              ruleDropdown.style.display = "none";
            }
          });
          
          // 添加鼠标离开事件，隐藏下拉列表
          entityBtn.addEventListener("mouseout", (e) => {
            // 检查鼠标是否移动到了下拉列表
            const rect = ruleDropdown.getBoundingClientRect();
            const isMovingToDropdown = e.clientX >= rect.left && e.clientX <= rect.right && 
                                     e.clientY >= rect.top && e.clientY <= rect.bottom;
            
            if (!isMovingToDropdown) {
              // 延迟隐藏，以便用户可以移动鼠标到下拉列表
              hideDropdownTimer = setTimeout(() => {
                // 使用更可靠的检查方式：检查是否在下拉列表或实体按钮上
                const dropdownHovered = document.contains(document.querySelector(':hover') || null) && 
                                      ruleDropdown.matches(':hover');
                const btnHovered = entityBtn.matches(':hover');
                if (!dropdownHovered && !btnHovered) {
                  ruleDropdown.style.display = "none";
                }
              }, 500);
            }
          });
          
          // 添加下拉列表鼠标离开事件，隐藏下拉列表
          ruleDropdown.addEventListener("mouseout", (e) => {
            // 检查鼠标是否移动到了实体按钮
            const rect = entityBtn.getBoundingClientRect();
            const isMovingToEntityBtn = e.clientX >= rect.left && e.clientX <= rect.right && 
                                       e.clientY >= rect.top && e.clientY <= rect.bottom;
            
            if (!isMovingToEntityBtn) {
              // 延迟隐藏，以便用户可以移动鼠标回实体按钮
              hideDropdownTimer = setTimeout(() => {
                // 使用更可靠的检查方式：检查是否在下拉列表或实体按钮上
                const dropdownHovered = document.contains(document.querySelector(':hover') || null) && 
                                      ruleDropdown.matches(':hover');
                const btnHovered = entityBtn.matches(':hover');
                if (!dropdownHovered && !btnHovered) {
                  ruleDropdown.style.display = "none";
                }
              }, 500);
            }
          });
          
          // 自动选中新添加的实体
          entityBtn.click();
          
          new Notice(t('main.entityAdded') + ': ' + newName);
        }
      }
    });
    
    // 渲染实体按钮
    this.extractedEntities.forEach(entity => {
      const entityBtn = entitiesContainer.createEl("button");
      entityBtn.style.padding = "8px 16px";
      entityBtn.style.cursor = "pointer";
      entityBtn.style.fontSize = "14px";
      entityBtn.style.transition = "all 0.2s";
      entityBtn.style.border = "none";
      entityBtn.style.backgroundColor = "unset";
      
      const entityExample = entityBtn.createDiv();
      entityExample.textContent = entity.name;
      entityExample.style.fontSize = `${this.previewFontSize || 14}px`;
      
      if (this.entityStyleMap.has(entity.name)) {
        const style = this.entityStyleMap.get(entity.name);
        entityExample.classList.add(style.className);
        appliedStyles.add(style.className);
      } else {
        const appliedStyle = this.checkEntityStyleInDocument(entity.name);
        if (appliedStyle) {
          entityExample.classList.add(appliedStyle);
          this.entityStyleMap.set(entity.name, { className: appliedStyle });
          appliedStyles.add(appliedStyle);
          console.log(`为实体 "${entity.name}" 应用样式: ${appliedStyle}`);
        } else if (this.plugin.globalRules && this.plugin.globalRules.length > 0) {
          // 检查全局规则中是否存在该实体
          const globalRule = this.plugin.globalRules.find(rule => {
            if (rule.regex === entity.name) {
              return true;
            }
            if (rule.regex.includes('|')) {
              const parts = rule.regex.split('|');
              return parts.includes(entity.name);
            }
            try {
              const regex = new RegExp(rule.regex);
              return regex.test(entity.name);
            } catch (error) {
              return false;
            }
          });
          
          if (globalRule) {
            entityExample.classList.add(globalRule.cssClass);
            this.entityStyleMap.set(entity.name, { className: globalRule.cssClass });
            appliedStyles.add(globalRule.cssClass);
            console.log(`为实体 "${entity.name}" 应用全局规则样式: ${globalRule.cssClass}`);
          } else {
            entityExample.textContent = entity.name;
          }
        } else {
          entityExample.textContent = entity.name;
        }
      }
      
      // 设置示例元素的样式，确保样式能够正确显示
      entityExample.style.whiteSpace = "nowrap";
      entityExample.style.overflow = "visible";
      entityExample.style.textOverflow = "clip";
      
      // 添加data-entity属性，方便后续查找
      entityBtn.dataset.entity = entity.name;
      
      // 添加点击事件
      entityBtn.addEventListener("click", () => {
        // 移除其他实体的选中状态
        entitiesContainer.querySelectorAll("button").forEach(btn => {
          // 移除选中状态的样式，但保留样式类中的样式
          btn.style.border = "none";
          btn.style.backgroundColor = "unset";
        });
        
        // 设置当前选中的实体
        this.selectedEntity = entity;
        // 添加选中状态的样式，同时保留样式类中的样式
        entityBtn.style.border = "2px solid var(--interactive-accent)";
        entityBtn.style.backgroundColor = "var(--background-modifier-hover)";
        
        // 将选中的实体名称填入输入框
        entityNameInput.value = entity.name;
        // 聚焦到输入框
        entityNameInput.focus();
      });
      
      // 添加鼠标悬停事件，显示匹配的规则
      entityBtn.addEventListener("mouseover", () => {
        if (hideDropdownTimer) {
          clearTimeout(hideDropdownTimer);
          hideDropdownTimer = null;
        }
        
        const matchedRules = this.plugin.rules.filter(rule => {
          try {
            if (rule.regex.includes(entity.name)) {
              return true;
            }
            try {
              const regex = new RegExp(rule.regex);
              return regex.test(entity.name);
            } catch (error) {
              return false;
            }
          } catch (error) {
            return false;
          }
        });
        
        // 过滤掉与按钮文字完全相同的选项
        const filteredRules = matchedRules.filter(rule => rule.regex !== entity.name);
        
        // 如果没有匹配的规则或过滤后没有规则，不显示下拉列表
        if (filteredRules.length === 0) {
          ruleDropdown.style.display = "none";
          return;
        }
        
        stylesContainer.querySelectorAll("span").forEach(styleBtn => {
          styleBtn.style.boxShadow = "";
        });
        
        matchedRules.forEach(rule => {
          const styleBtn = stylesContainer.querySelector(`span.${rule.cssClass}`);
          if (styleBtn) {
            styleBtn.style.boxShadow = "0 0 0 2px var(--interactive-accent)";
          }
        });
        
        const btnRect = entityBtn.getBoundingClientRect();
        ruleDropdown.style.top = `${btnRect.bottom + window.scrollY}px`;
        ruleDropdown.style.left = `${btnRect.left + window.scrollX}px`;
        
        ruleDropdown.innerHTML = '';
        
        filteredRules.forEach(rule => {
          const ruleItem = document.createElement("div");
          ruleItem.textContent = rule.regex;
          ruleItem.style.padding = "6px 10px";
          ruleItem.style.cursor = "pointer";
          ruleItem.style.borderBottom = "1px solid var(--background-modifier-border)";
          
          ruleItem.addEventListener("click", () => {
            const oldEntityName = entity.name;
            const newEntityName = rule.regex;
            
            entity.name = newEntityName;
            
            const example = entityBtn.querySelector("div");
            if (example) {
              example.textContent = newEntityName;
            }
            entityBtn.dataset.entity = newEntityName;
            
            entityNameInput.value = newEntityName;
            
            if (this.entityStyleMap.has(oldEntityName)) {
              const style = this.entityStyleMap.get(oldEntityName);
              this.entityStyleMap.delete(oldEntityName);
              this.entityStyleMap.set(newEntityName, style);
            }
            
            entitiesContainer.querySelectorAll("button").forEach(btn => {
              btn.style.border = "none";
              btn.style.backgroundColor = "unset";
            });
            entityBtn.style.border = "2px solid var(--interactive-accent)";
            entityBtn.style.backgroundColor = "var(--background-modifier-hover)";
            
            this.selectedEntity = entity;
            
            ruleDropdown.style.display = "none";
          });
          
          ruleItem.addEventListener("mouseover", () => {
            ruleItem.style.backgroundColor = "var(--background-modifier-hover)";
          });
          
          ruleItem.addEventListener("mouseout", () => {
            ruleItem.style.backgroundColor = "transparent";
          });
          
          ruleDropdown.appendChild(ruleItem);
        });
        
        ruleDropdown.style.display = "block";
      });
      
      // 添加鼠标离开事件，隐藏下拉列表
      entityBtn.addEventListener("mouseout", (e) => {
        // 检查鼠标是否移动到了下拉列表
        const rect = ruleDropdown.getBoundingClientRect();
        const isMovingToDropdown = e.clientX >= rect.left && e.clientX <= rect.right && 
                                 e.clientY >= rect.top && e.clientY <= rect.bottom;
        
        if (!isMovingToDropdown) {
          // 延迟隐藏，以便用户可以移动鼠标到下拉列表
          hideDropdownTimer = setTimeout(() => {
            // 使用更可靠的检查方式：检查是否在下拉列表或实体按钮上
            const dropdownHovered = document.contains(document.querySelector(':hover') || null) && 
                                  ruleDropdown.matches(':hover');
            const btnHovered = entityBtn.matches(':hover');
            if (!dropdownHovered && !btnHovered) {
              ruleDropdown.style.display = "none";
            }
          }, 500);
        }
      });
      
      // 添加下拉列表鼠标离开事件，隐藏下拉列表
      ruleDropdown.addEventListener("mouseout", (e) => {
        // 检查鼠标是否移动到了实体按钮
        const rect = entityBtn.getBoundingClientRect();
        const isMovingToEntityBtn = e.clientX >= rect.left && e.clientX <= rect.right && 
                                   e.clientY >= rect.top && e.clientY <= rect.bottom;
        
        if (!isMovingToEntityBtn) {
          // 延迟隐藏，以便用户可以移动鼠标回实体按钮
          hideDropdownTimer = setTimeout(() => {
            // 使用更可靠的检查方式：检查是否在下拉列表或实体按钮上
            const dropdownHovered = document.contains(document.querySelector(':hover') || null) && 
                                  ruleDropdown.matches(':hover');
            const btnHovered = entityBtn.matches(':hover');
            if (!dropdownHovered && !btnHovered) {
              ruleDropdown.style.display = "none";
            }
          }, 500);
        }
      });
    });
    
    // 确保所有已应用的样式都能被正确加载
    if (appliedStyles.size > 0) {
      console.log("已应用的样式类:", Array.from(appliedStyles));
    }
    
    // 样式显示区域（可滚动）
    const stylesSection = contentEl.createDiv();
    stylesSection.style.marginBottom = "20px";
    stylesSection.style.flex = "1"; // 占据剩余空间
    stylesSection.style.overflowY = "auto"; // 允许垂直滚动
    stylesSection.style.overflowX = "hidden"; // 禁止横向滚动
    stylesSection.style.minHeight = "100px"; // 设置最小高度
    
    const stylesTitle = stylesSection.createEl("h3", { text: t('entity.stylesWithZeroCount') });
    stylesTitle.style.marginBottom = "10px";
    
    const stylesContainer = stylesSection.createDiv();
    stylesContainer.style.display = "flex";
    stylesContainer.style.flexWrap = "wrap";
    stylesContainer.style.gap = "10px";
    stylesContainer.style.width = "100%";
    stylesContainer.style.boxSizing = "border-box";
    
    // 读取styles.css文件，获取样式定义
    let stylesCssContent = '';
    try {
      const stylesCssPath = '.obsidian/plugins/Regex-Css-Highlighter/styles.css';
      stylesCssContent = await this.plugin.app.vault.adapter.read(stylesCssPath);
    } catch (error) {
      console.error('读取styles.css文件失败:', error);
    }
    
    // 渲染样式按钮
    this.angle0Styles.forEach(style => {
      const styleBtn = stylesContainer.createEl("span");
      styleBtn.textContent = t('entity.preview');
      styleBtn.style.display = "inline-flex";
      styleBtn.style.cursor = "pointer";
      styleBtn.style.margin = "2px 4px";
      styleBtn.style.padding = "4px 8px";
      styleBtn.style.minWidth = "50px";
      styleBtn.style.minHeight = "25px";
      styleBtn.style.alignItems = "center";
      styleBtn.style.justifyContent = "center";
      styleBtn.style.fontSize = `${this.previewFontSize || 14}px`;
      styleBtn.style.overflow = "visible";
      
      styleBtn.classList.add(style.className);
      styleBtn.classList.add("entity-style-btn");
      
      // 添加点击事件
      styleBtn.addEventListener("mousedown", async (e) => {
        // 检查是否是中键点击
        if (e.button === 1) {
          // 中键点击：应用到全局规则
          if (this.selectedEntity) {
            try {
              const entityName = this.selectedEntity.name;
              const className = style.className;
              
              // 检查全局规则中是否已存在相同的规则
              const existingRule = this.plugin.globalRules.find(
                rule => rule.regex === entityName && rule.cssClass === className
              );
              
              if (existingRule) {
                new Notice(t('main.globalRuleExists'));
              } else {
                // 添加到全局规则
                this.plugin.globalRules.push({
                  regex: entityName,
                  cssClass: className,
                  remark: ''
                });
                
                // 保存全局规则
                await this.plugin.saveGlobalRules(this.plugin.globalRules);
                
                // 更新规则版本并刷新视图
                this.plugin.rulesVersion++;
                this.plugin.rulesUpdateEmitter.dispatchEvent(new Event('update'));
                this.plugin.refreshCurrentView();
                
                new Notice(t('main.globalRuleAdded'));
              }
            } catch (err) {
              console.error('添加全局规则失败:', err);
              new Notice(t('main.globalRuleAddFailed') + ': ' + err.message);
            }
          } else {
            new Notice(t('main.selectEntity'));
          }
          e.preventDefault();
          return;
        }
      });
      
      // 添加左键点击事件
      styleBtn.addEventListener("click", async () => {
        // 左键点击：应用样式
        if (this.selectedEntity) {
          // 存储实体和样式的对应关系
          this.entityStyleMap.set(this.selectedEntity.name, style);
          
          // 为样式按钮添加粗边框，表示已被选中过
          styleBtn.style.border = "3px solid var(--interactive-accent)";
          
          // 应用样式到实体按钮
          const entityButtons = entitiesContainer.querySelectorAll("button");
          entityButtons.forEach(btn => {
            if (btn.textContent === this.selectedEntity.name) {
              // 找到实体按钮中的示例元素
              const entityExample = btn.querySelector('div');
              if (entityExample) {
                // 移除之前的样式类
                entityExample.classList.forEach(cls => {
                  if (cls !== "") {
                    entityExample.classList.remove(cls);
                  }
                });
                // 添加新的样式类
                entityExample.classList.add(style.className);
                // 移除选中状态，保留样式类中的样式
                btn.style.border = "none";
                btn.style.backgroundColor = "unset";
              }
            }
          });
          
          // 立即应用样式到文档
          await this.applyStylesToDocument(true); // 只更新选中的实体
          
          // 显示反馈
          new Notice(t('main.entityStyleAssigned'));
          
          // 清除选中状态，等待选择下一个实体
          this.selectedEntity = null;
        } else {
          new Notice(t('main.selectEntity'));
        }
      });
    });
    
    // 取消按钮
    const buttonContainer = contentEl.createDiv();
    buttonContainer.style.display = "flex";
    buttonContainer.style.justifyContent = "flex-end";
    buttonContainer.style.gap = "10px";
    
    const cancelBtn = buttonContainer.createEl("button");
    cancelBtn.textContent = t('main.close');
    cancelBtn.style.padding = "8px 16px";
    cancelBtn.style.border = "1px solid var(--background-modifier-border)";
    cancelBtn.style.borderRadius = "4px";
    cancelBtn.style.backgroundColor = "transparent";
    cancelBtn.style.cursor = "pointer";
    
    cancelBtn.addEventListener("click", () => {
      this.close();
    });
  }

  applyStyles() {
    if (this.entityStyleMap.size === 0) {
      new Notice(t('main.assignStyleFirst'));
      return;
    }
    
    // 获取当前活动的Markdown编辑器
    const { MarkdownView } = require('obsidian');
    const activeView = this.app.workspace.getActiveViewOfType(MarkdownView);
    
    if (!activeView?.editor) {
      new Notice(t('main.openMdFile'));
      return;
    }
    
    try {
      // 获取编辑器内容
      const content = activeView.editor.getValue();
      let newContent = content;
      
      // 为每个实体应用样式
      this.entityStyleMap.forEach((style, entityName) => {
        // 创建正则表达式，匹配整个单词
        const regex = new RegExp(`\\b${entityName}\\b`, 'g');
        // 替换为带有样式的文本
        newContent = newContent.replace(regex, `<span class="${style.className}">${entityName}</span>`);
      });
      
      // 更新编辑器内容
      activeView.editor.setValue(newContent);
      
      new Notice(t('main.entityStyleApplied'));
      this.close();
    } catch (error) {
      console.error("应用样式错误:", error);
      new Notice(t('main.entityStyleApplyFailed') + ': ' + error.message);
    }
  }
  
  async loadEntityStyles() {
    try {
      const { MarkdownView } = require('obsidian');
      const activeView = this.plugin.app.workspace.getActiveViewOfType(MarkdownView);
      
      if (!activeView || !activeView.file) {
        return {};
      }
      
      const filePath = activeView.file.path;
      const jsonFileName = filePath.replace(/[\/\\]/g, '_').replace(/\.md$/, '.json');
      const entityStylesJsonPath = this.plugin.app.vault.configDir + '/plugins/Regex-Css-Highlighter/data/' + jsonFileName;
      
      const content = await this.plugin.app.vault.adapter.read(entityStylesJsonPath);
      const entityStylesData = JSON.parse(content);
      
      const entityStyles = {};
      
      if (Array.isArray(entityStylesData)) {
        entityStylesData.forEach(item => {
          if (item.regex && item.cssClass) {
            entityStyles[item.regex] = { className: item.cssClass };
          }
        });
      } else if (typeof entityStylesData === 'object') {
        if (Array.isArray(entityStylesData.rules)) {
          entityStylesData.rules.forEach(item => {
            if (item.regex && item.cssClass) {
              entityStyles[item.regex] = { className: item.cssClass };
            }
          });
        } else {
          for (const [key, value] of Object.entries(entityStylesData)) {
            if (value.cssClass) {
              entityStyles[key] = { className: value.cssClass };
            }
          }
        }
      }
      
      return entityStyles;
    } catch (error) {
      console.error('读取实体样式文件失败:', error);
      return {};
    }
  }
  
  checkEntityStyleInDocument(entityName) {
    // 从entityStyleMap中获取实体的样式
    if (this.entityStyleMap.has(entityName)) {
      const style = this.entityStyleMap.get(entityName);
      return style.className;
    }
    
    // 获取当前活动的Markdown编辑器
    const { MarkdownView } = require('obsidian');
    const activeView = this.app.workspace.getActiveViewOfType(MarkdownView);
    
    if (!activeView?.editor) {
      return null;
    }
    
    try {
      // 获取编辑器内容
      const content = activeView.editor.getValue();
      
      // 搜索该实体是否已经被包裹在带有样式类的span标签中
      // 匹配格式：<span class="样式类名">实体名称</span>
      const regex = new RegExp(`<span class="([^"]+)">${entityName}</span>`, 'g');
      const match = regex.exec(content);
      
      if (match && match[1]) {
        // 确保该样式类存在于文档中
        const styleClassName = match[1];
        console.log(`为实体 "${entityName}" 找到已应用的样式: ${styleClassName}`);
        return styleClassName;
      }
      
      return null;
    } catch (error) {
      console.error("检查实体样式错误:", error);
      return null;
    }
  }
  
  async saveEntityStyles(onlySelectedEntity = false) {
    try {
      const { MarkdownView } = require('obsidian');
      const activeView = this.plugin.app.workspace.getActiveViewOfType(MarkdownView);
      
      if (!activeView || !activeView.file) {
        return;
      }
      
      const filePath = activeView.file.path;
      const jsonFileName = filePath.replace(/[\/\\]/g, '_').replace(/\.md$/, '.json');
      const entityStylesJsonPath = this.plugin.app.vault.configDir + '/plugins/Regex-Css-Highlighter/data/' + jsonFileName;
      
      let existingData = { rules: [] };
      try {
        const fileContent = await this.plugin.app.vault.adapter.read(entityStylesJsonPath);
        existingData = JSON.parse(fileContent);
        if (!Array.isArray(existingData.rules)) {
          existingData.rules = [];
        }
      } catch (readError) {
      }
      
      const entitiesToProcess = onlySelectedEntity && this.selectedEntity 
        ? [[this.selectedEntity.name, this.entityStyleMap.get(this.selectedEntity.name)]]
        : Array.from(this.entityStyleMap.entries());
      
      entitiesToProcess.forEach(([entityName, style]) => {
        if (!style) return;
        
        const existingExactMatchIndex = existingData.rules.findIndex(rule => rule.regex === entityName);
        
        if (existingExactMatchIndex !== -1) {
          existingData.rules[existingExactMatchIndex].cssClass = style.className;
        } else {
          const existingRuleIndex = existingData.rules.findIndex(rule => rule.cssClass === style.className);
          
          if (existingRuleIndex !== -1) {
            const existingRule = existingData.rules[existingRuleIndex];
            if (existingRule.regex.includes("|")) {
              existingData.rules.push({
                regex: entityName,
                cssClass: style.className,
                remark: ""
              });
            } else {
              existingData.rules[existingRuleIndex].regex = entityName;
            }
          } else {
            existingData.rules.push({
              regex: entityName,
              cssClass: style.className,
              remark: ""
            });
          }
        }
      });
      
      const content = JSON.stringify(existingData, null, 2);
      await this.plugin.app.vault.adapter.write(entityStylesJsonPath, content);
    } catch (error) {
      // 忽略错误
    }
  }
  
  async applyStylesToDocument(onlySelectedEntity = false) {
    const { MarkdownView } = require('obsidian');

    const activeView = this.app.workspace.getActiveViewOfType(MarkdownView);
    
    if (!activeView?.editor) {
      new Notice(t('main.openMdFile'));
      return;
    }
    
    try {
      const filePath = activeView.file.path;
      
      // 直接使用内存中的规则，避免重复加载
      // 如果规则为空，才加载
      if (!this.plugin.rules || this.plugin.rules.length === 0) {
        await this.plugin.loadFileRules(filePath);
      }
      
      let addedCount = 0;
      let updatedCount = 0;
      
      const ruleMap = new Map();
      
      this.plugin.rules.forEach(rule => {
        ruleMap.set(rule.regex, rule);
      });
      
      const processEntity = (entityName, style, skipCompositeCheck = false) => {
        const regex = entityName.trim();
        if (!regex) return;
        
        if (ruleMap.has(regex)) {
          const existingRule = ruleMap.get(regex);
          if (existingRule.cssClass !== style.className) {
            existingRule.cssClass = style.className;
            updatedCount++;
          }
        } else {
          let foundInCompositeRule = false;
          let compositeRule = null;
          let compositeRuleRegex = "";
          
          if (!regex.includes("|") && !skipCompositeCheck) {
            ruleMap.forEach((rule, ruleRegex) => {
              if (ruleRegex.includes("|")) {
                const entities = ruleRegex.split("|").map(e => e.trim());
                if (entities.includes(regex)) {
                  foundInCompositeRule = true;
                  compositeRule = rule;
                  compositeRuleRegex = ruleRegex;
                }
              }
            });
          }
          
          if (foundInCompositeRule && compositeRule) {
            const entities = compositeRuleRegex.split("|").map(e => e.trim());
            const otherEntities = entities.filter(e => e !== regex);
            const otherEntitiesInMap = otherEntities.filter(e => this.entityStyleMap.has(e));
            
            if (otherEntitiesInMap.length === 0) {
              return;
            }
            
            let shouldSplit = true;
            const firstOtherStyle = this.entityStyleMap.get(otherEntitiesInMap[0]);
            shouldSplit = otherEntitiesInMap.every(e => {
              const otherStyle = this.entityStyleMap.get(e);
              return otherStyle.className === firstOtherStyle.className;
            });
            
            if (firstOtherStyle && firstOtherStyle.className === style.className) {
              shouldSplit = false;
            }
            
            if (shouldSplit && otherEntities.length > 0) {
              ruleMap.set(regex, {
                regex: regex,
                cssClass: style.className,
                remark: compositeRule.remark || ""
              });
              addedCount++;
              
              const remainingEntities = otherEntities;
              const newCompositeRegex = remainingEntities.join("|");
              compositeRule.regex = newCompositeRegex;
              ruleMap.delete(compositeRuleRegex);
              ruleMap.set(newCompositeRegex, compositeRule);
            } else {
              if (compositeRule.cssClass !== style.className) {
                compositeRule.cssClass = style.className;
                updatedCount++;
              }
            }
          } else if (!foundInCompositeRule) {
            ruleMap.set(regex, {
              regex: regex,
              cssClass: style.className,
              remark: ""
            });
            addedCount++;
          }
        }
      };
      
      if (onlySelectedEntity && this.selectedEntity) {
        if (this.entityStyleMap.has(this.selectedEntity.name)) {
          const style = this.entityStyleMap.get(this.selectedEntity.name);
          processEntity(this.selectedEntity.name, style, true);
        }
      } else {
        this.entityStyleMap.forEach((style, entityName) => {
          processEntity(entityName, style);
        });
      }
      
      if (onlySelectedEntity && this.selectedEntity && !this.entityStyleMap.has(this.selectedEntity.name)) {
        return;
      }
      
      this.plugin.rules = Array.from(ruleMap.values());
      
      const savePromises = [
        this.plugin.saveFileRules(filePath, this.plugin.rules),
        this.saveEntityStyles(onlySelectedEntity)
      ];
      
      this.plugin.rulesVersion++;
      this.plugin.rulesUpdateEmitter.dispatchEvent(new Event('update'));
      
      await Promise.all(savePromises);
      
      // 刷新视图（只刷新一次）
      this.plugin.refreshCurrentView();
      
      new Notice(t('main.entityRulesAdded'));
    } catch (error) {
      console.error("应用样式错误:", error);
      new Notice(t('main.entityStyleApplyFailed') + ': ' + error.message);
    }
  }

  onClose() {
    const { contentEl } = this;
    contentEl.empty();
    
    if (this._resizeHandle && document.body.contains(this._resizeHandle)) {
      document.body.removeChild(this._resizeHandle);
    }
    if (this._resizeUpdatePosition) {
      window.removeEventListener("resize", this._resizeUpdatePosition);
    }
    if (this._resizeListeners) {
      document.removeEventListener("mousemove", this._resizeListeners.mousemove);
      document.removeEventListener("mouseup", this._resizeListeners.mouseup);
    }
    if (this._positionInterval) {
      clearInterval(this._positionInterval);
    }
    
    // 恢复编辑器选区
    if (this.selectionStart && this.selectionEnd) {
      const { MarkdownView } = require('obsidian');
      const activeView = this.app.workspace.getActiveViewOfType(MarkdownView);
      if (activeView?.editor) {
        // 恢复选区
        activeView.editor.setSelection(
          { line: this.selectionStart.line, ch: this.selectionStart.ch },
          { line: this.selectionEnd.line, ch: this.selectionEnd.ch }
        );
        // 使编辑器获得焦点
        activeView.editor.focus();
      }
    }
  }
}

// 样式分组配置 - 从JSON文件加载
let styleCategories = {};

// CSS编辑器弹窗类
class CSSEditorModal extends Modal {
  constructor(app, className, currentStyle, onSave, plugin) {
    super(app);
    this.className = className;
    this.currentStyle = currentStyle;
    this.onSave = onSave;
    this.originalStyle = currentStyle;
    this.plugin = plugin;
    this.buttonText = '';
    
    try {
      // 方法1: 尝试从传入的plugin参数获取
      if (plugin && plugin.buttonTexts && typeof plugin.buttonTexts === 'object') {
        this.buttonText = plugin.buttonTexts[className] || '';
      }
      // 方法2: 如果方法1失败，尝试从app.plugins中获取原始插件实例
      else if (app && app.plugins && app.plugins.plugins) {
        // 尝试查找Regex-Css-Highlighter插件
        const pluginName = 'regex-css-highlighter';
        const originalPlugin = app.plugins.plugins[pluginName];
        
        if (originalPlugin && originalPlugin.buttonTexts && typeof originalPlugin.buttonTexts === 'object') {
          this.buttonText = originalPlugin.buttonTexts[className] || '';
        }
      }
      // 方法3: 尝试从window对象中查找可能的全局引用（作为最后的尝试）
      else if (window.regexCssHighlighterPlugin) {
        const globalPlugin = window.regexCssHighlighterPlugin;
        if (globalPlugin && globalPlugin.buttonTexts && typeof globalPlugin.buttonTexts === 'object') {
          this.buttonText = globalPlugin.buttonTexts[className] || '';
        }
      }
    } catch (e) {
      // 出错时保持buttonText为空字符串
      this.buttonText = '';
    }
  }

  onOpen() {
    const { contentEl } = this;
    contentEl.empty();
    
    // 设置弹窗样式
    contentEl.style.padding = "20px";
    contentEl.style.minWidth = "500px";
    contentEl.style.maxWidth = "700px";
    contentEl.style.maxHeight = "80vh";
    contentEl.style.overflowY = "auto";
    
    // 标题
    const titleEl = contentEl.createEl("h2", { text: t('cssEditor.editStyle') + ` .${this.className}` });
    titleEl.style.margin = "0 0 15px 0";
    titleEl.style.fontSize = "18px";
    titleEl.style.color = "#333";
    titleEl.style.borderBottom = "2px solid #007bff";
    titleEl.style.paddingBottom = "10px";
    
    // CSS编辑器区域
    const editorSection = contentEl.createDiv();
    editorSection.style.marginBottom = "12px";
    
    // 创建动态样式元素用于预览（支持伪元素）
    const previewStyleId = 'edit-style-preview-' + this.className.replace(/[^a-zA-Z0-9]/g, '_');
    let previewStyleEl = document.getElementById(previewStyleId);
    if (!previewStyleEl) {
      previewStyleEl = document.createElement('style');
      previewStyleEl.id = previewStyleId;
      document.head.appendChild(previewStyleEl);
    }
    
    // 将样式预览文本改为"预览"或类名，并移除CSS样式代码标题
    const previewDisplayText = this.plugin?.settings?.showClassNameAsPreview ? this.className : t('entity.preview');
    const previewText = editorSection.createEl("span", { text: previewDisplayText });
    previewText.style.marginBottom = "8px";
    previewText.style.fontSize = "16px";
    previewText.style.display = "inline-block";
    previewText.classList.add(this.className);
    
    // 更新预览样式的函数
    const updatePreviewStyle = (cssCode) => {
      // 提取主样式内容用于内联样式
      const mainStyleMatch = cssCode.match(/\.([^{]+)\s*\{([^}]*)\}/);
      if (mainStyleMatch) {
        const styleContent = mainStyleMatch[2].trim();
        previewText.setAttribute("style", "margin-bottom: 8px; font-size: 16px; display: inline-block; " + styleContent);
      }
      
      // 处理伪元素样式：将类名替换为带有唯一前缀的类名，避免影响其他元素
      const previewClassName = 'preview-' + this.className.replace(/[^a-zA-Z0-9]/g, '_');
      
      // 替换CSS中的类名为预览专用类名
      let processedCss = cssCode.replace(
        new RegExp('\\.' + this.className.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'g'),
        '.' + previewClassName
      );
      
      // 更新样式表
      previewStyleEl.textContent = processedCss;
      
      // 更新预览元素的类名
      previewText.className = previewClassName;
    };
    
    // 初始应用当前样式
    setTimeout(() => {
      updatePreviewStyle(this.currentStyle);
    }, 0);
    
    // 创建文本编辑器
    const textArea = editorSection.createEl("textarea");
    textArea.value = this.currentStyle;
    textArea.style.width = "100%";
    textArea.style.height = "150px";
    textArea.style.fontFamily = "'Courier New', monospace";
    textArea.style.fontSize = "12px";
    textArea.style.border = "1px solid #ccc";
    textArea.style.borderRadius = "4px";
    textArea.style.padding = "8px";
    textArea.style.resize = "vertical";
    textArea.style.lineHeight = "1.4";
    
    // 异步加载完整的CSS规则（包括伪类选择器）
    this.loadFullCssRule().then(fullCssRule => {
      if (fullCssRule && fullCssRule !== this.currentStyle) {
        textArea.value = fullCssRule;
        updatePreviewStyle(fullCssRule);
      }
    });
    
    // 实时预览功能
    let previewTimeout;
    textArea.addEventListener("input", () => {
      clearTimeout(previewTimeout);
      previewTimeout = setTimeout(() => {
        const newStyle = textArea.value;
        updatePreviewStyle(newStyle);
      }, 300);
    });
    
    // 按钮文字设置
    const buttonTextSection = contentEl.createDiv();
    buttonTextSection.style.marginBottom = "12px";
    
    const buttonTextLabel = buttonTextSection.createEl("label", { text: t('cssEditor.buttonText') });
    buttonTextLabel.style.display = "block";
    buttonTextLabel.style.marginBottom = "4px";
    buttonTextLabel.style.fontSize = "13px";
    buttonTextLabel.style.color = "#666";
    
    // 创建按钮文字输入框
    const buttonTextInput = buttonTextSection.createEl("input");
    buttonTextInput.type = "text";
    buttonTextInput.placeholder = t('cssEditor.inputButtonText');
    buttonTextInput.style.width = "100%";
    buttonTextInput.style.padding = "6px";
    buttonTextInput.style.border = "1px solid #ccc";
    buttonTextInput.style.borderRadius = "4px";
    buttonTextInput.style.fontSize = "13px";
    
    // 使用setTimeout确保DOM已完全渲染后再设置值
    setTimeout(() => {
      // 方法1: 首先尝试使用构造函数中设置的this.buttonText
      let textToSet = this.buttonText || '';
      
      // 方法2: 如果方法1失败，尝试从window对象中获取最新的按钮文字
      if (!textToSet && typeof window !== 'undefined' && window.regexCssHighlighterPlugin && 
          window.regexCssHighlighterPlugin.buttonTexts && this.className) {
        textToSet = window.regexCssHighlighterPlugin.buttonTexts[this.className] || '';
      }
      
      // 方法3: 最后尝试从app.plugins中获取
      if (!textToSet && this.app && this.app.plugins && this.app.plugins.plugins) {
        const pluginName = 'regex-css-highlighter';
        const plugin = this.app.plugins.plugins[pluginName];
        if (plugin && plugin.buttonTexts && this.className) {
          textToSet = plugin.buttonTexts[this.className] || '';
        }
      }
      
      // 设置输入框值
      buttonTextInput.value = textToSet || '';
    }, 0);
    
    // AI功能区域
    const aiSection = contentEl.createDiv();
    aiSection.style.marginBottom = "12px";
    aiSection.style.padding = "10px";
    aiSection.style.border = "1px solid #ddd";
    aiSection.style.borderRadius = "4px";
    aiSection.style.backgroundColor = "#f0f8ff";
    
    const aiLabel = aiSection.createEl("h3", { text: t('cssEditor.aiStyleOptimize') });
    aiLabel.style.margin = "0 0 6px 0";
    aiLabel.style.fontSize = "13px";
    aiLabel.style.color = "#0066cc";
    aiLabel.style.display = "inline";
    
    // 检查是否有可用的AI配置（有API Key）
    let aiConfigs = [];
    if (this.plugin?.settings?.aiConfigs) {
      aiConfigs = this.plugin.settings.aiConfigs;
    } else if (this.app && this.app.plugins && this.app.plugins.plugins) {
      // 尝试从app.plugins中获取原始插件实例
      const pluginName = 'regex-css-highlighter';
      const originalPlugin = this.app.plugins.plugins[pluginName];
      if (originalPlugin && originalPlugin.settings?.aiConfigs) {
        aiConfigs = originalPlugin.settings.aiConfigs;
      }
    } else if (window.regexCssHighlighterPlugin) {
      // 尝试从window对象中查找全局引用
      const globalPlugin = window.regexCssHighlighterPlugin;
      if (globalPlugin && globalPlugin.settings?.aiConfigs) {
        aiConfigs = globalPlugin.settings.aiConfigs;
      }
    }
    const hasAvailableAI = aiConfigs.some(config => config.apiKey && config.apiKey.trim() !== "");
    
    if (!hasAvailableAI) {
      // 添加红字提示（可点击链接）
      const noAIWarning = aiSection.createEl("span", { text: '  ' + t('cssEditor.noAiWarning') });
      noAIWarning.style.color = "red";
      noAIWarning.style.fontSize = "12px";
      noAIWarning.style.marginLeft = "8px";
      
      const settingsLink = aiSection.createEl("a", { text: t('cssEditor.goToSettings') });
      settingsLink.style.color = "red";
      settingsLink.style.fontSize = "12px";
      settingsLink.style.textDecoration = "underline";
      settingsLink.style.cursor = "pointer";
      settingsLink.addEventListener("click", (e) => {
        e.preventDefault();
        e.stopPropagation();
        this.close();
        setTimeout(() => {
          const aiSettingsSection = document.getElementById("ai-settings-section");
          if (aiSettingsSection) {
            aiSettingsSection.scrollIntoView({ behavior: "smooth", block: "start" });
          }
        }, 100);
      });
    }
    
    // 修改要求输入框
    const aiPromptInput = aiSection.createEl("textarea");
    aiPromptInput.placeholder = t('cssEditor.inputModifyReq');
    aiPromptInput.style.width = "100%";
    aiPromptInput.style.height = "60px"; // 减小高度
    aiPromptInput.style.fontFamily = "'Microsoft YaHei', sans-serif";
    aiPromptInput.style.fontSize = "12px";
    aiPromptInput.style.border = "1px solid #ccc";
    aiPromptInput.style.borderRadius = "4px";
    aiPromptInput.style.padding = "8px";
    aiPromptInput.style.resize = "vertical";
    aiPromptInput.style.backgroundColor = "white";
    
    // AI发送按钮
    const aiSendButton = aiSection.createEl("button", { text: t('cssEditor.sendToAiOptimize') });
    aiSendButton.style.marginTop = "6px";
    aiSendButton.style.backgroundColor = "#007bff";
    aiSendButton.style.color = "white";
    aiSendButton.style.border = "none";
    aiSendButton.style.borderRadius = "4px";
    aiSendButton.style.padding = "6px 12px";
    aiSendButton.style.fontSize = "12px";
    aiSendButton.style.cursor = "pointer";
    
    aiSendButton.addEventListener("click", async () => {
      try {
        // 获取当前CSS内容和用户要求
        const currentCss = textArea.value;
        const userPrompt = aiPromptInput.value.trim();
        
        if (!userPrompt) {
          new Notice(t('main.inputStyleModification'));
          return;
        }
        
        // 构建完整的提示词
        const fullPrompt = `请优化以下CSS样式代码：

${currentCss}

修改要求：${userPrompt}

请仅返回优化后的CSS代码，不要包含其他解释或说明。`;
        
        // 显示加载提示
        aiSendButton.textContent = t('cssEditor.optimizing');
        aiSendButton.disabled = true;
        
        // 获取完整的插件实例
        let fullPluginInstance = this.plugin;
        
        // 方法1: 尝试从app.plugins中获取原始插件实例
        if (!fullPluginInstance || typeof fullPluginInstance.callAI !== 'function') {
          if (this.app && this.app.plugins && this.app.plugins.plugins) {
            const pluginName = 'regex-css-highlighter';
            fullPluginInstance = this.app.plugins.plugins[pluginName];
          }
        }
        
        // 方法2: 尝试从window对象中查找全局引用
        if (!fullPluginInstance || typeof fullPluginInstance.callAI !== 'function') {
          if (window.regexCssHighlighterPlugin) {
            fullPluginInstance = window.regexCssHighlighterPlugin;
          }
        }
        
        // 检查是否有callAI方法
        if (!fullPluginInstance || typeof fullPluginInstance.callAI !== 'function') {
          throw new Error('无法找到完整的插件实例或callAI方法');
        }
        
        // 调用AI API
        const aiResponse = await fullPluginInstance.callAI(fullPrompt);
        
        // 处理AI响应，移除可能的代码块标记
        let processedResponse = aiResponse.trim();
        
        // 正则表达式匹配常见的代码块标记
        const codeBlockRegex = /^```\s*css\s*([\s\S]*?)\s*```\s*$/i;
        const match = processedResponse.match(codeBlockRegex);
        
        if (match && match[1]) {
          // 如果匹配到代码块标记，提取中间的CSS内容
          processedResponse = match[1].trim();
        } else {
          // 检查是否有单独的开头或结尾标记
          processedResponse = processedResponse
            .replace(/^```\s*css\s*/i, '')
            .replace(/\s*```\s*$/i, '');
        }
        
        // 将处理后的响应填充到CSS编辑器
        textArea.value = processedResponse;
        
        // 触发实时预览
        const inputEvent = new Event("input");
        textArea.dispatchEvent(inputEvent);
        
        // 显示成功提示
        new Notice(t('main.aiStyleOptimized'));
        
        // 恢复按钮状态
        aiSendButton.textContent = t('cssEditor.sendToAiOptimize');
        aiSendButton.disabled = false;
      } catch (error) {
        console.error("AI优化出错:", error);
        new Notice(t('main.aiOptimizeFailed') + ': ' + error.message);
        
        // 恢复按钮状态
        aiSendButton.textContent = t('cssEditor.sendToAiOptimize');
        aiSendButton.disabled = false;
      }
    });
    
    // 按钮区域
    const buttonSection = contentEl.createDiv();
    buttonSection.style.display = "flex";
    buttonSection.style.justifyContent = "flex-end";
    buttonSection.style.gap = "10px";
    buttonSection.style.marginTop = "20px";
    buttonSection.style.paddingTop = "15px";
    buttonSection.style.borderTop = "1px solid #eee";
    
    // 重置按钮
    const resetBtn = buttonSection.createEl("button", { text: t('cssEditor.reset') });
    resetBtn.style.padding = "8px 16px";
    resetBtn.style.border = "1px solid #6c757d";
    resetBtn.style.borderRadius = "4px";
    resetBtn.style.backgroundColor = "#6c757d";
    resetBtn.style.color = "white";
    resetBtn.style.cursor = "pointer";
    resetBtn.style.fontSize = "14px";
    
    resetBtn.addEventListener("click", () => {
      textArea.value = this.originalStyle;
      previewText.setAttribute("style", this.originalStyle);
    });
    
    // 取消按钮
    const cancelBtn = buttonSection.createEl("button", { text: t('main.cancel') });
    cancelBtn.style.padding = "8px 16px";
    cancelBtn.style.border = "1px solid #6c757d";
    cancelBtn.style.borderRadius = "4px";
    cancelBtn.style.backgroundColor = "#6c757d";
    cancelBtn.style.color = "white";
    cancelBtn.style.cursor = "pointer";
    cancelBtn.style.fontSize = "14px";
    
    cancelBtn.addEventListener("click", () => {
      this.close();
    });
    
    // 保存按钮
    const saveBtn = buttonSection.createEl("button", { text: t('main.save') });
    saveBtn.style.padding = "8px 16px";
    saveBtn.style.border = "1px solid #007bff";
    saveBtn.style.borderRadius = "4px";
    saveBtn.style.backgroundColor = "#007bff";
    saveBtn.style.color = "white";
    saveBtn.style.cursor = "pointer";
    saveBtn.style.fontSize = "14px";
    saveBtn.style.fontWeight = "bold";
    
    saveBtn.addEventListener("click", async () => {
      const newStyle = textArea.value;
      const buttonTextValue = buttonTextInput.value.trim();
      try {
        await this.onSave(this.className, newStyle, buttonTextValue);
        this.close();
      } catch (error) {
        console.error("保存样式失败:", error);
        // 显示错误提示
        const errorDiv = contentEl.createDiv();
        errorDiv.textContent = t('main.saveFailed') + ': ' + error.message;
        errorDiv.style.color = "#dc3545";
        errorDiv.style.backgroundColor = "#f8d7da";
        errorDiv.style.border = "1px solid #f5c6cb";
        errorDiv.style.borderRadius = "4px";
        errorDiv.style.padding = "10px";
        errorDiv.style.marginTop = "10px";
        
        setTimeout(() => {
          errorDiv.remove();
        }, 3000);
      }
    });
    
    // 快捷键支持
    textArea.addEventListener("keydown", (e) => {
      if (e.ctrlKey && e.key === "s") {
        e.preventDefault();
        saveBtn.click();
      }
      if (e.key === "Escape") {
        e.preventDefault();
        cancelBtn.click();
      }
    });
    
    // 聚焦到文本编辑器
    setTimeout(() => {
      textArea.focus();
      textArea.setSelectionRange(textArea.value.length, textArea.value.length);
    }, 100);
  }

  async loadFullCssRule() {
    try {
      const cssPath = '.obsidian/plugins/Regex-Css-Highlighter/styles.css';
      const cssContent = await this.app.vault.adapter.read(cssPath);
      const escapedClassName = this.className.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
      const ruleRegex = new RegExp(`\\.${escapedClassName}(?:::[a-zA-Z-]+(?:\\([^)]*\\))?)*\\s*\\{(?:[^{}]|\\{[^{}]*\\})*\\}`, 'gs');
      const matches = cssContent.match(ruleRegex);
      if (matches && matches.length > 0) {
        return matches.join('\n');
      }
    } catch (error) {
      console.log('Failed to load full CSS rule:', error.message);
    }
    return null;
  }

  onClose() {
    const { contentEl } = this;
    contentEl.empty();
    
    // 清理动态创建的预览样式元素
    const previewStyleId = 'edit-style-preview-' + this.className.replace(/[^a-zA-Z0-9]/g, '_');
    const previewStyleEl = document.getElementById(previewStyleId);
    if (previewStyleEl) {
      previewStyleEl.remove();
    }
  }

  showAddStyleDialog(category, existingClassNames) {
    // 创建添加样式的弹窗
    const modal = new Modal(this.app);
    modal.contentEl.style.padding = "20px";
    modal.contentEl.style.minWidth = "400px";
    modal.contentEl.style.maxWidth = "600px";
    
    // 初始化对话历史
    const conversationHistory = [];
    
    // 添加系统提示（只在第一次时添加）
    const systemPrompt = {
      role: "system",
      content: t('ai.cssExpertPrompt')
    };
    conversationHistory.push(systemPrompt);
    
    const titleEl = modal.contentEl.createEl("h2", { text: t('main.addNewStyleTo') + ` "${category}"` });
    titleEl.style.margin = "0 0 15px 0";
    titleEl.style.fontSize = "18px";
    titleEl.style.color = "#333";
    titleEl.style.borderBottom = "2px solid #007bff";
    titleEl.style.paddingBottom = "10px";
    
    // CSS样式输入
    const styleContainer = modal.contentEl.createDiv();
    styleContainer.style.marginBottom = "15px";
    
    const styleTextarea = styleContainer.createEl("textarea");
    styleTextarea.placeholder = ".my-custom-style { background-color: #ffeb3b; color: #333; padding: 2px 4px; border-radius: 3px; }";
    styleTextarea.style.width = "100%";
    styleTextarea.style.height = "250px";
    styleTextarea.style.padding = "8px 12px";
    styleTextarea.style.border = "1px solid #ddd";
    styleTextarea.style.borderRadius = "4px";
    styleTextarea.style.fontSize = "13px";
    styleTextarea.style.fontFamily = "'Courier New', monospace";
    styleTextarea.style.lineHeight = "1.4";
    styleTextarea.style.resize = "vertical";
    
    // 解析CSS样式的函数（与AI生成后相同）
    const parseCssStyles = (cssText) => {
      const styles = [];
      const pseudoRules = []; // 先收集伪元素/伪类规则
      const keyframeRules = []; // 收集 @keyframes 规则
      const styleRegex = /\.([^{]+?)\s*\{([^}]*)\}/g;
      let match;
      
      // 提取 @keyframes 规则（使用括号计数法匹配任意深度）
      const extractKeyframes = (text) => {
        const results = [];
        const startRegex = /@keyframes\s+([a-zA-Z0-9_-]+)\s*\{/g;
        let startMatch;
        while ((startMatch = startRegex.exec(text)) !== null) {
          const name = startMatch[1];
          const startPos = startMatch.index;
          const openPos = startMatch.index + startMatch[0].length - 1;
          let depth = 1;
          let pos = openPos + 1;
          while (pos < text.length && depth > 0) {
            if (text[pos] === '{') depth++;
            else if (text[pos] === '}') depth--;
            pos++;
          }
          results.push({ name, fullStyle: text.substring(startPos, pos) });
        }
        return results;
      };
      const kfResults = extractKeyframes(cssText);
      for (const kf of kfResults) {
        keyframeRules.push(kf);
      }
      
      // 从文本中移除 @keyframes 块，避免内部的小数点被误匹配为类选择器
      let cssTextNoKeyframes = cssText;
      for (const kf of kfResults) {
        cssTextNoKeyframes = cssTextNoKeyframes.replace(kf.fullStyle, '');
      }
      
      while ((match = styleRegex.exec(cssTextNoKeyframes)) !== null) {
        const className = match[1].trim();
        const styleContent = match[2].trim();
        const fullStyle = `.${className} { ${styleContent} }`;
        if (className.includes('::') || className.includes(':')) {
          // 提取主类名（伪元素/伪类前的部分）
          const baseName = className.split(/::|:/)[0].trim();
          pseudoRules.push({ baseName, fullStyle });
        } else {
          styles.push({
            className,
            styleContent,
            fullStyle
          });
        }
      }
      
      // 将伪元素规则关联到对应的主类
      for (const pseudo of pseudoRules) {
        const parent = styles.find(s => s.className === pseudo.baseName);
        if (parent) {
          parent.fullStyle += '\n' + pseudo.fullStyle;
        }
      }
      
      // 将 @keyframes 规则关联到引用它的主类
      for (const kf of keyframeRules) {
        for (const style of styles) {
          if (style.fullStyle.includes(kf.name)) {
            style.fullStyle = style.fullStyle + '\n' + kf.fullStyle;
          }
        }
      }
      
      return styles;
    };
    
    // 实时预览功能（与AI生成后相同的方法）
    const updatePreview = () => {
      const styleText = styleTextarea.value.trim();
      
      // 移除旧的预览容器
      let previewContainer = modal.contentEl.querySelector('.styles-preview-container');
      if (previewContainer) {
        previewContainer.remove();
      }
      
      // 清理临时预览样式
      let tempPreviewStyle = document.getElementById('add-style-preview-temp');
      if (tempPreviewStyle) tempPreviewStyle.textContent = '';
      
      if (!styleText) {
        return;
      }
      
      const styles = parseCssStyles(styleText);
      
      // 注入临时CSS样式（含伪元素），使预览能正确显示
      if (!tempPreviewStyle) {
        tempPreviewStyle = document.createElement('style');
        tempPreviewStyle.id = 'add-style-preview-temp';
        document.head.appendChild(tempPreviewStyle);
      }
      tempPreviewStyle.textContent = styles.map(s => s.fullStyle).join('\n');
      
      // 如果有样式，显示预览容器
      if (styles.length >= 1) {
        previewContainer = modal.contentEl.createDiv();
        previewContainer.className = 'styles-preview-container';
        previewContainer.style.marginBottom = '15px';
        previewContainer.style.padding = '10px 0';
        previewContainer.style.border = 'none';
        previewContainer.style.backgroundColor = 'transparent';
        
        // 样式列表容器 - 顶部横排展示
        const stylesList = previewContainer.createEl('div');
        stylesList.style.display = 'flex';
        stylesList.style.flexWrap = 'wrap';
        stylesList.style.gap = '15px';
        stylesList.style.alignItems = 'center';
        
        // 创建每个样式的预览
        styles.forEach((style, index) => {
          const previewWrapper = stylesList.createEl('div');
          previewWrapper.style.display = 'flex';
          previewWrapper.style.alignItems = 'center';
          previewWrapper.style.gap = '8px';
          
          // 预览文本 - 无框设计
          const previewSpan = previewWrapper.createEl('span', { text: t('entity.preview') });
          previewSpan.className = style.className;
          previewSpan.style.display = 'inline-block';
          previewSpan.style.padding = '2px 8px';
          previewSpan.style.borderRadius = '3px';
          previewSpan.style.fontSize = '12px';
          previewSpan.setAttribute('style', `font-size: 12px; display: inline-block; ${style.styleContent}`);
        });
        
        // 将预览容器插入到样式输入区域上方
        styleContainer.parentNode.insertBefore(previewContainer, styleContainer);
      }
    };
    
    let previewTimeout;
    styleTextarea.addEventListener("input", () => {
      clearTimeout(previewTimeout);
      previewTimeout = setTimeout(updatePreview, 200);
    });
    
    styleTextarea.addEventListener("paste", () => {
      setTimeout(updatePreview, 50);
    });
    
    // AI功能区域
    const aiSection = modal.contentEl.createDiv();
    aiSection.style.marginBottom = "15px";
    aiSection.style.padding = "10px";
    aiSection.style.border = "1px solid #ddd";
    aiSection.style.borderRadius = "4px";
    aiSection.style.backgroundColor = "#f0f8ff";
    
    const aiLabel = aiSection.createEl("h3", { text: t('cssEditor.aiStyleGenerate') });
    aiLabel.style.margin = "0 0 6px 0";
    aiLabel.style.fontSize = "13px";
    aiLabel.style.color = "#0066cc";
    aiLabel.style.display = "inline";
    
    // 检查是否有可用的AI配置（有API Key）
    const aiConfigs = this.plugin?.settings?.aiConfigs || [];
    const hasAvailableAI = aiConfigs.some(config => config.apiKey && config.apiKey.trim() !== "");
    
    if (!hasAvailableAI) {
      // 添加红字提示（可点击链接）
      const noAIWarning = aiSection.createEl("span", { text: '  ' + t('cssEditor.noAiWarning') });
      noAIWarning.style.color = "red";
      noAIWarning.style.fontSize = "12px";
      noAIWarning.style.marginLeft = "8px";
      
      const settingsLink = aiSection.createEl("a", { text: t('cssEditor.goToSettings') });
      settingsLink.style.color = "red";
      settingsLink.style.fontSize = "12px";
      settingsLink.style.textDecoration = "underline";
      settingsLink.style.cursor = "pointer";
      settingsLink.addEventListener("click", (e) => {
        e.preventDefault();
        e.stopPropagation();
        modal.close();
        setTimeout(() => {
          const aiSettingsSection = document.getElementById("ai-settings-section");
          if (aiSettingsSection) {
            aiSettingsSection.scrollIntoView({ behavior: "smooth", block: "start" });
          }
        }, 100);
      });
    }
    
    // 样式需求输入框
    const aiPromptInput = aiSection.createEl("textarea");
    aiPromptInput.placeholder = t('cssEditor.inputStyleEffect');
    aiPromptInput.style.width = "100%";
    aiPromptInput.style.height = "60px";
    aiPromptInput.style.fontFamily = "'Microsoft YaHei', sans-serif";
    aiPromptInput.style.fontSize = "12px";
    aiPromptInput.style.border = "1px solid #ccc";
    aiPromptInput.style.borderRadius = "4px";
    aiPromptInput.style.padding = "8px";
    aiPromptInput.style.resize = "vertical";
    aiPromptInput.style.backgroundColor = "white";
    
    // AI生成按钮
    const aiGenerateButton = aiSection.createEl("button", { text: t('cssEditor.generateStyle') });
    aiGenerateButton.style.marginTop = "6px";
    aiGenerateButton.style.backgroundColor = "#007bff";
    aiGenerateButton.style.color = "white";
    aiGenerateButton.style.border = "none";
    aiGenerateButton.style.borderRadius = "4px";
    aiGenerateButton.style.padding = "6px 12px";
    aiGenerateButton.style.fontSize = "12px";
    aiGenerateButton.style.cursor = "pointer";
    
    aiGenerateButton.addEventListener("click", async () => {
      try {
        // 获取用户要求
        const userPrompt = aiPromptInput.value.trim();
        
        if (!userPrompt) {
          new Notice(t('main.inputStyleRequirement'));
          return;
        }
        
        // 显示加载提示
        aiGenerateButton.textContent = t('cssEditor.generating');
        aiGenerateButton.disabled = true;
        
        // 获取完整的插件实例
        let fullPluginInstance = this.plugin;
        
        // 方法1: 尝试从app.plugins中获取原始插件实例
        if (!fullPluginInstance || typeof fullPluginInstance.callAI !== 'function') {
          if (this.app && this.app.plugins && this.app.plugins.plugins) {
            const pluginName = 'regex-css-highlighter';
            fullPluginInstance = this.app.plugins.plugins[pluginName];
          }
        }
        
        // 方法2: 尝试从window对象中查找全局引用
        if (!fullPluginInstance || typeof fullPluginInstance.callAI !== 'function') {
          if (window.regexCssHighlighterPlugin) {
            fullPluginInstance = window.regexCssHighlighterPlugin;
          }
        }
        
        // 检查是否有callAI方法
        if (!fullPluginInstance || typeof fullPluginInstance.callAI !== 'function') {
          throw new Error('无法找到完整的插件实例或callAI方法');
        }
        
        // 添加用户提示到对话历史
        const userMessage = {
          role: "user",
          content: userPrompt
        };
        conversationHistory.push(userMessage);
        
        // 调用AI API(带对话历史)
        const aiResponse = await fullPluginInstance.callAIWithHistory(conversationHistory);
        
        // 添加AI响应到对话历史
        const aiMessage = {
          role: "assistant",
          content: aiResponse
        };
        conversationHistory.push(aiMessage);
        
        // 处理AI响应，移除可能的代码块标记
        let processedResponse = aiResponse.trim();
        
        // 正则表达式匹配常见的代码块标记
        const codeBlockRegex = /^```\s*css\s*([\s\S]*?)\s*```\s*$/i;
        const match = processedResponse.match(codeBlockRegex);
        
        if (match && match[1]) {
          // 如果匹配到代码块标记，提取中间的CSS内容
          processedResponse = match[1].trim();
        } else {
          // 检查是否有单独的开头或结尾标记
          processedResponse = processedResponse
            .replace(/^```\s*css\s*/i, '')
            .replace(/\s*```\s*$/i, '');
        }
        
        // 解析多个CSS样式
        const parseCssStyles = (cssText) => {
          const styles = [];
          const pseudoRules = [];
          const keyframeRules = [];
          // 匹配CSS类选择器和样式内容
          const styleRegex = /\.([^{]+?)\s*\{([^}]*)\}/g;
          let match;
          
          // 提取 @keyframes 规则（使用括号计数法匹配任意深度）
          const extractKeyframes = (text) => {
            const results = [];
            const startRegex = /@keyframes\s+([a-zA-Z0-9_-]+)\s*\{/g;
            let startMatch;
            while ((startMatch = startRegex.exec(text)) !== null) {
              const name = startMatch[1];
              const startPos = startMatch.index;
              const openPos = startMatch.index + startMatch[0].length - 1;
              let depth = 1;
              let pos = openPos + 1;
              while (pos < text.length && depth > 0) {
                if (text[pos] === '{') depth++;
                else if (text[pos] === '}') depth--;
                pos++;
              }
              results.push({ name, fullStyle: text.substring(startPos, pos) });
            }
            return results;
          };
          const kfResults = extractKeyframes(cssText);
          for (const kf of kfResults) {
            keyframeRules.push(kf);
          }
          
          // 从文本中移除 @keyframes 块，避免内部的小数点被误匹配为类选择器
          let cssTextNoKeyframes = cssText;
          for (const kf of kfResults) {
            cssTextNoKeyframes = cssTextNoKeyframes.replace(kf.fullStyle, '');
          }
          
          while ((match = styleRegex.exec(cssTextNoKeyframes)) !== null) {
            const className = match[1].trim();
            const styleContent = match[2].trim();
            const fullStyle = `.${className} { ${styleContent} }`;
            if (className.includes('::') || className.includes(':')) {
              const baseName = className.split(/::|:/)[0].trim();
              pseudoRules.push({ baseName, fullStyle });
            } else {
              styles.push({
                className,
                styleContent,
                fullStyle
              });
            }
          }
          
          for (const pseudo of pseudoRules) {
            const parent = styles.find(s => s.className === pseudo.baseName);
            if (parent) {
              parent.fullStyle += '\n' + pseudo.fullStyle;
            }
          }
          
          // 将 @keyframes 规则关联到引用它的主类
          for (const kf of keyframeRules) {
            for (const style of styles) {
              if (style.fullStyle.includes(kf.name)) {
                style.fullStyle = style.fullStyle + '\n' + kf.fullStyle;
              }
            }
          }
          
          return styles;
        };
        
        const styles = parseCssStyles(processedResponse);
        
        // 将AI返回的内容直接全部显示在回复框中
        styleTextarea.value = processedResponse;
        // 触发实时预览
        const inputEvent = new Event("input");
        styleTextarea.dispatchEvent(inputEvent);
        
        // 如果有多个样式，显示预览容器
        if (styles.length > 1) {
          // 创建样式预览容器
          let previewContainer = modal.contentEl.querySelector('.styles-preview-container');
          if (previewContainer) {
            previewContainer.remove();
          }
          
          previewContainer = modal.contentEl.createDiv();
          previewContainer.className = 'styles-preview-container';
          previewContainer.style.marginBottom = '15px';
          previewContainer.style.padding = '10px 0';
          previewContainer.style.border = 'none';
          previewContainer.style.backgroundColor = 'transparent';
          
          // 样式列表容器 - 顶部横排展示
          const stylesList = previewContainer.createEl('div');
          stylesList.style.display = 'flex';
          stylesList.style.flexWrap = 'wrap';
          stylesList.style.gap = '15px';
          stylesList.style.alignItems = 'center';
          
          // 创建每个样式的预览
          styles.forEach((style, index) => {
            const previewWrapper = stylesList.createEl('div');
            previewWrapper.style.display = 'flex';
            previewWrapper.style.alignItems = 'center';
            previewWrapper.style.gap = '8px';
            
            // 预览文本 - 无框设计
            const previewSpan = previewWrapper.createEl('span', { text: t('entity.preview') });
            previewSpan.className = style.className;
            previewSpan.style.display = 'inline-block';
            previewSpan.style.padding = '2px 8px';
            previewSpan.style.borderRadius = '3px';
            previewSpan.style.fontSize = '12px';
            previewSpan.setAttribute('style', `font-size: 12px; display: inline-block; ${style.styleContent}`);
          });
          
          // 将预览容器插入到样式输入区域上方
          styleContainer.parentNode.insertBefore(previewContainer, styleContainer);
        }
        
        // 显示成功提示
        new Notice(t('main.aiStyleGenerated'));
        
        // 恢复按钮状态
        aiGenerateButton.textContent = t('cssEditor.generateStyle');
        aiGenerateButton.disabled = false;
      } catch (error) {
        console.error("AI生成出错:", error);
        new Notice(t('main.aiGenerateFailed') + ': ' + error.message);
        
        // 恢复按钮状态
        aiGenerateButton.textContent = t('cssEditor.generateStyle');
        aiGenerateButton.disabled = false;
      }
    });
    
    // 快速模板已移除
    
    // 按钮区域
    const buttonContainer = modal.contentEl.createDiv();
    buttonContainer.style.display = "flex";
    buttonContainer.style.justifyContent = "flex-end";
    buttonContainer.style.alignItems = "center";
    buttonContainer.style.gap = "10px";
    buttonContainer.style.marginTop = "20px";
    buttonContainer.style.paddingTop = "15px";
   // buttonContainer.style.borderTop = "1px solid #eee";

    // 更多样式链接
    const moreStylesLink = buttonContainer.createEl("a", { text: t('cssEditor.moreStyles') });
    moreStylesLink.href = "https://github.com/dlsdgj/obsidian-regex-css-highlighter/discussions/1";
    moreStylesLink.target = "_blank";
    moreStylesLink.style.marginRight = "auto";
    moreStylesLink.style.fontSize = "14px";
    moreStylesLink.style.textDecoration = "none";

    // 取消按钮
    const cancelBtn = buttonContainer.createEl("button", { text: t('main.cancel') });
    cancelBtn.style.padding = "8px 16px";
    cancelBtn.style.border = "1px solid #6c757d";
    cancelBtn.style.borderRadius = "4px";
    cancelBtn.style.backgroundColor = "#6c757d";
    cancelBtn.style.color = "white";
    cancelBtn.style.cursor = "pointer";
    cancelBtn.style.fontSize = "14px";
    
    cancelBtn.addEventListener("click", () => {
      modal.close();
    });
    
    // 添加按钮
    const addBtn = buttonContainer.createEl("button", { text: t('cssEditor.addStyle') });
    addBtn.style.padding = "8px 16px";
    addBtn.style.border = "1px solid #28a745";
    addBtn.style.borderRadius = "4px";
    addBtn.style.backgroundColor = "#28a745";
    addBtn.style.color = "white";
    addBtn.style.cursor = "pointer";
    addBtn.style.fontSize = "14px";
    addBtn.style.fontWeight = "bold";
    
    addBtn.addEventListener("click", async () => {
      // 直接从文本框解析所有样式
      const styleText = styleTextarea.value.trim();
      const selectedStyles = parseCssStyles(styleText);
      
      if (selectedStyles.length === 0) {
        this.showError(modal.contentEl, "请输入有效的CSS样式格式，例如：.my-class { color: red; }");
        return;
      }
      
      try {
        // 处理每个选中的样式
        for (const style of selectedStyles) {
          const { className, styleContent, fullStyle } = style;
          
          // 检查类名是否已存在
          if (existingClassNames.includes(className)) {
            new Notice(t('main.classNameExists'));
            continue;
          }
          
          // 添加到CSS文件（使用fullStyle以包含伪元素规则）
          await this.addStyleToCSSFileDirectly(fullStyle);
          
          // 添加到配置文件
          await this.addStyleToConfig(category, className);
        }
        
        // 更新内存缓存
        for (const style of selectedStyles) {
          const { className, styleContent } = style;
          const fullStyle = `.${className} { ${styleContent} }`;
          this.cssStyles.set(className, fullStyle);
        }
        
        // 重新加载样式
        this.reloadStyles();
        
        // 显示成功消息
        if (selectedStyles.length === 1) {
          const { className } = selectedStyles[0];
          this.showSuccessMessage(t('main.styleAddedToCategorySuccess') + ` .${className} ` + t('main.category') + ` "${category}"`);
        } else {
          this.showSuccessMessage(t('main.stylesAddedToCategory') + ` ${selectedStyles.length} ` + t('main.category') + ` "${category}"`);
        }
        
        modal.close();
        
        // 重新加载样式分类配置和CSS样式
        await this.plugin.loadStyleCategories();
        await this.loadCssStyles();
        
        // 刷新当前主面板内容
        this.onOpen();
        
      } catch (error) {
        console.error('Error adding style:', error);
        this.showError(modal.contentEl, "添加样式失败: " + error.message);
      }
    });
    
    // 聚焦到样式输入框
    setTimeout(() => {
      styleTextarea.focus();
    }, 100);
    
    modal.open();
  }
  

  async addStyleToCSSFile(className, styleText) {
    const cssPath = '.obsidian/plugins/Regex-Css-Highlighter/styles.css';
    let cssContent = '';
    
    try {
      cssContent = await this.app.vault.adapter.read(cssPath);
    } catch (error) {
      console.log('CSS file not found, creating new one');
      cssContent = '';
    }
    
    // 添加新的CSS规则，使用与addStyleToCSSFileDirectly相同的逻辑，在第一个@keyframes前插入
    const newCssRule = `.${className} {\n  ${styleText}\n}\n`;
    
    // 查找第一个@keyframes规则的位置
    const keyframesMatch = cssContent.match(/@keyframes/);
    
    if (keyframesMatch && keyframesMatch.index > 0) {
      // 如果找到了@keyframes规则，在其前面插入新的CSS规则
      cssContent = cssContent.substring(0, keyframesMatch.index) + newCssRule + cssContent.substring(keyframesMatch.index);
      console.log(`CSS rule for .${className} added before first @keyframes`);
    } else {
      // 如果没有找到@keyframes规则，将新规则添加到文件末尾
      cssContent += newCssRule;
      console.log(`CSS rule for .${className} added to end of file (no @keyframes found)`);
    }
    
    // 保存CSS文件
    await this.app.vault.adapter.write(cssPath, cssContent);
    console.log('Added new CSS rule for', className);
    
    // 直接更新动态样式元素，确保新样式立即生效
    appendCSSToDynamicStyle(newCssRule);
  }
  
  // 直接将CSS代码添加到文件中，插入到第一个@keyframes之前
  async addStyleToCSSFileDirectly(cssCode) {
    const cssPath = '.obsidian/plugins/Regex-Css-Highlighter/styles.css';
    let cssContent = '';
    
    try {
      cssContent = await this.app.vault.adapter.read(cssPath);
    } catch (error) {
      console.log('CSS file not found, creating new one');
      cssContent = '';
    }
    
    // 检查是否有@keyframes规则
    const keyframesIndex = cssContent.indexOf('@keyframes');
    
    if (keyframesIndex !== -1) {
      // 在第一个@keyframes之前插入
      cssContent = cssContent.substring(0, keyframesIndex) + cssCode + '\n\n' + cssContent.substring(keyframesIndex);
    } else {
      // 如果没有@keyframes，则直接添加到文件末尾
      cssContent += '\n' + cssCode + '\n';
    }
    
    // 保存CSS文件
    await this.app.vault.adapter.write(cssPath, cssContent);
    console.log('Added CSS code directly to file');
    
    // 重新注入CSS内容，传入已知的cssContent避免读写不一致
    // 这会同时更新标题样式规则
    if (typeof this.plugin.injectCSSContent === 'function') {
      await this.plugin.injectCSSContent(cssContent);
    }
  }
  
  async addStyleToConfig(category, className) {
    // 添加到配置文件
    if (!styleCategories[category]) {
      styleCategories[category] = [];
    }
    
    if (!styleCategories[category].includes(className)) {
      styleCategories[category].push(className);
      
      // 保存配置文件
      const configPath = '.obsidian/plugins/Regex-Css-Highlighter/style-categories.json';
      await this.app.vault.adapter.write(configPath, JSON.stringify(styleCategories, null, 2));
      console.log(`Added ${className} to category ${category}`);
    }
  }
  
  showError(container, message) {
    // 移除之前的错误消息
    const existingError = container.querySelector('.error-message');
    if (existingError) {
      existingError.remove();
    }
    
    const errorDiv = container.createDiv();
    errorDiv.className = 'error-message';
    errorDiv.textContent = message;
    errorDiv.style.color = "#dc3545";
    errorDiv.style.backgroundColor = "#f8d7da";
    errorDiv.style.border = "1px solid #f5c6cb";
    errorDiv.style.borderRadius = "4px";
    errorDiv.style.padding = "10px";
    errorDiv.style.marginTop = "10px";
    errorDiv.style.fontSize = "14px";
    
    // 3秒后自动移除
    setTimeout(() => {
      if (errorDiv.parentNode) {
        errorDiv.remove();
      }
    }, 3000);
  }
  
  async saveSortedStyles(draggedCategory, draggedIndex, targetCategory, targetIndex) {
    try {
      console.log(`Saving sorted styles: moving from ${draggedIndex} in ${draggedCategory} to ${targetIndex} in ${targetCategory}`);
      
      // 确保styleCategories是对象且分类存在
      if (!styleCategories || typeof styleCategories !== 'object' || 
          !styleCategories[draggedCategory] || !styleCategories[targetCategory]) {
        console.error('Invalid styleCategories or category not found');
        this.showError(this.contentEl, '分类不存在，无法移动样式');
        return;
      }
      
      // 复制当前分类的类名数组
      const sourceClassNames = [...styleCategories[draggedCategory]];
      const targetClassNames = [...styleCategories[targetCategory]];
      
      // 验证索引是否有效
      if (draggedIndex < 0 || draggedIndex >= sourceClassNames.length || 
          targetIndex < 0 || targetIndex >= targetClassNames.length) {
        console.error('Invalid index for sorting');
        this.showError(this.contentEl, '索引无效，无法移动样式');
        return;
      }
      
      // 处理相同分类内的移动
      if (draggedCategory === targetCategory) {
        if (draggedIndex === targetIndex) {
          console.log('Same index and category, no sorting needed');
          return;
        }
        
        // 移除被拖拽的元素
        const draggedClassName = sourceClassNames.splice(draggedIndex, 1)[0];
        
        // 在目标位置插入被拖拽的元素
        sourceClassNames.splice(targetIndex, 0, draggedClassName);
        
        // 更新样式分类配置
        styleCategories[draggedCategory] = sourceClassNames;
        console.log('Intra-category move completed, updated categories:', styleCategories);
      } 
      // 处理跨分类移动
      else {
        // 从源分类移除元素
        const draggedClassName = sourceClassNames.splice(draggedIndex, 1)[0];
        
        // 添加到目标分类
        targetClassNames.splice(targetIndex, 0, draggedClassName);
        
        // 更新样式分类配置
        styleCategories[draggedCategory] = sourceClassNames;
        styleCategories[targetCategory] = targetClassNames;
        
        console.log(`Style moved across categories: ${draggedClassName} from ${draggedCategory} to ${targetCategory}`);
      }
      
      // 保存到配置文件 - 使用与addStyleToConfig相同的相对路径方式
      const configPath = '.obsidian/plugins/Regex-Css-Highlighter/style-categories.json';
      console.log('Saving to config path:', configPath);
      
      // 先保存到文件
      await this.app.vault.adapter.write(configPath, JSON.stringify(styleCategories, null, 2));
      console.log('Styles reordered successfully, saved to file');
      
      // 然后重新加载配置到全局变量，确保数据一致性
      if (this.plugin && typeof this.plugin.loadStyleCategories === 'function') {
        console.log('Reloading style categories...');
        await this.plugin.loadStyleCategories();
        console.log('Style categories reloaded:', Object.keys(styleCategories));
      }
      
      // 无论是否跨分类移动，都刷新索引，确保UI显示正确
      if (typeof this.refreshStyleButtonIndices === 'function') {
        console.log('Refreshing style button indices...');
        this.refreshStyleButtonIndices();
      }
      
      // 刷新当前弹窗内容，确保立即显示最新的样式顺序
      if (typeof this.refreshModalContent === 'function') {
        console.log('Refreshing modal content to show updated style order...');
        this.refreshModalContent();
      }
      
    } catch (error) {
      console.error('Error saving sorted styles:', error);
      // 添加错误提示
      this.showError(this.contentEl, '保存样式顺序失败: ' + error.message);
    }
  }
  
  // 刷新样式按钮的索引，确保它们的data-style-index属性与当前顺序一致
  refreshStyleButtonIndices() {
    try {
      // 获取所有分类容器
      const allSections = Array.from(document.querySelectorAll('.modal-content [style*="display: flex"][style*="flex-wrap: wrap"]')).map(grid => grid.parentElement).filter(Boolean);
      
      allSections.forEach(section => {
        const categoryName = section.querySelector('h4').textContent.trim();
        const gridContainer = section.querySelector('div');
        
        if (gridContainer) {
          const styleButtons = Array.from(gridContainer.querySelectorAll('[data-style-index]'));
          
          // 更新每个按钮的索引
          styleButtons.forEach((button, index) => {
            button.setAttribute('data-style-index', index);
          });
          
          console.log(`Refreshed indices for ${categoryName}: ${styleButtons.length} buttons updated`);
        }
      });
    } catch (error) {
      console.error('Error refreshing style button indices:', error);
    }
  }
  
  refreshModalContent() {
    // 修复：使用原生DOM方法替代jQuery方法，确保在Obsidian环境中正常工作
    console.log('refreshModalContent: 开始刷新模态框内容');
    
    try {
      // 使用原生DOM方法清空内容
      if (this.contentEl) {
        // 先检查this.contentEl是否存在
        console.log('refreshModalContent: 清空内容区域');
        
        // 原生方法清空元素内容
        while (this.contentEl.firstChild) {
          this.contentEl.removeChild(this.contentEl.firstChild);
        }
        
        // 确保AddRegexRuleModal存在且onOpen方法可用
        if (typeof AddRegexRuleModal !== 'undefined' && typeof AddRegexRuleModal.prototype.onOpen === 'function') {
          console.log('refreshModalContent: 调用AddRegexRuleModal.prototype.onOpen');
          // 重新调用onOpen方法重建内容
          AddRegexRuleModal.prototype.onOpen.call(this);
        } else {
          // 备用方案：如果AddRegexRuleModal不可用，尝试使用实例自身的onOpen方法
          if (typeof this.onOpen === 'function') {
            console.log('refreshModalContent: 调用this.onOpen');
            this.onOpen();
          } else {
            console.error('refreshModalContent: 无法找到onOpen方法');
          }
        }
        
        console.log('refreshModalContent: 刷新完成');
      } else {
        console.error('refreshModalContent: contentEl不存在');
      }
    } catch (error) {
      console.error('refreshModalContent执行错误:', error);
      // 如果出错，尝试最简单的刷新方法
      if (this.contentEl) {
        console.log('refreshModalContent: 执行备用刷新');
        this.contentEl.textContent = t('common.refreshing');
      }
    }
  }
}
