              copyClassNameOption.addEventListener('click', async () => {
                try {
                  await navigator.clipboard.writeText(className);
                  new Notice(t('main.classNameCopied'));
                } catch (err) {
                  // clipboard API 失败时使用备用方法
                  const textarea = document.createElement('textarea');
                  textarea.value = className;
                  textarea.style.position = 'fixed';
                  textarea.style.opacity = '0';
                  document.body.appendChild(textarea);
                  textarea.select();
                  document.execCommand('copy');
                  document.body.removeChild(textarea);
                  new Notice(t('main.classNameCopied'));
                }
                if (document.body.contains(menu)) {
                  document.body.removeChild(menu);
                }
              });
              
              menu.appendChild(copyClassNameOption);
              
              // 添加复制完整样式选项
              const copyFullStyleOption = document.createElement('div');
              copyFullStyleOption.textContent = t('context.copyFullStyle');
              copyFullStyleOption.style.cssText = `
                padding: 8px 16px;
                cursor: pointer;
                font-size: 14px;
                color: var(--text-normal);
              `;
              
              copyFullStyleOption.addEventListener('mouseenter', () => {
                copyFullStyleOption.style.background = 'var(--background-modifier-hover)';
              });
              
              copyFullStyleOption.addEventListener('mouseleave', () => {
                copyFullStyleOption.style.background = 'transparent';
              });
              
              copyFullStyleOption.addEventListener('click', async () => {
                // 从动态样式元素中提取与该类名相关的所有CSS规则（含伪元素、动效）
                let fullStyle = '';
                const styleEl = document.getElementById('Regex-Css-Highlighter-dynamic-styles');
                if (styleEl) {
                  const cssText = styleEl.textContent;
                  const escapedClassName = className.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
                  // 提取所有包含该类名的CSS规则（主规则、伪元素、伪类、多选择器等）
                  const ruleRegex = new RegExp(`[^{}]*\\.${escapedClassName}[^{}]*\\{(?:[^{}]|\\{[^{}]*\\})*\\}`, 'g');
                  let ruleMatch;
                  while ((ruleMatch = ruleRegex.exec(cssText)) !== null) {
                    fullStyle += ruleMatch[0] + '\n';
                  }
                  // 提取相关的@keyframes规则
                  const animationNames = [];
                  const animPropRegex = /animation\s*:\s*([^;]+)/g;
                  let animMatch;
                  while ((animMatch = animPropRegex.exec(fullStyle)) !== null) {
                    // animation值格式: name duration timing-function delay iteration-count direction fill-mode
                    const parts = animMatch[1].trim().split(/\s+/);
                    parts.forEach(part => {
                      if (!/^\d|ease|linear|infinite|alternate|normal|forwards|backwards|both|running|paused|step/i.test(part)) {
                        animationNames.push(part);
                      }
                    });
                  }
                  // 也检查animation-name属性
                  const animNameRegex = /animation-name\s*:\s*([^;]+)/g;
                  while ((animMatch = animNameRegex.exec(fullStyle)) !== null) {
                    animationNames.push(animMatch[1].trim());
                  }
                  if (animationNames.length > 0) {
                    const kfRegex = /@keyframes\s+[a-zA-Z_-][a-zA-Z0-9_-]*\s*\{[^{}]*(?:\{[^{}]*\}[^{}]*)*\}/g;
                    let kfMatch;
                    while ((kfMatch = kfRegex.exec(cssText)) !== null) {
                      const kfRule = kfMatch[0];
                      const kfNameMatch = kfRule.match(/@keyframes\s+([a-zA-Z_-][a-zA-Z0-9_-]*)/);
                      if (kfNameMatch && animationNames.includes(kfNameMatch[1])) {
                        fullStyle += kfRule + '\n';
                      }
                    }
                  }
                }
                // 回退：如果未从动态样式中提取到，使用内联样式
                if (!fullStyle.trim()) {
                  fullStyle = `.${className} { ${styleInfo.style} }`;
                }
                try {
                  await navigator.clipboard.writeText(fullStyle.trim());
                  new Notice(t('main.fullStyleCopied'));
                } catch (err) {
                  const textarea = document.createElement('textarea');
                  textarea.value = fullStyle.trim();
                  textarea.style.position = 'fixed';
                  textarea.style.opacity = '0';
                  document.body.appendChild(textarea);
                  textarea.select();
                  document.execCommand('copy');
                  document.body.removeChild(textarea);
                  new Notice(t('main.fullStyleCopied'));
                }
                if (document.body.contains(menu)) {
                  document.body.removeChild(menu);
                }
              });
              
