            const savedStyle = this.plugin?.floatButtonData?.groupButtonStyleClasses?.[catName];
            if (!savedStyle) {
              categoryTitle.style.backgroundColor = '#007bff';
            }
            categoryTitle.title = t('main.dblClickHideGroup');
