  // 刷新打开的模态框，确保规则列表更新
  refreshOpenModal() {
    try {
      // 查找当前打开的AddRegexRuleModal实例
      const modals = document.querySelectorAll('.modal');
      for (const modal of modals) {
        if (modal.modalInstance && modal.modalInstance instanceof AddRegexRuleModal) {
          // 刷新规则显示区域
          const rulesContainer = modal.modalInstance.contentEl.querySelector('.rules-container');
          if (rulesContainer) {
            // 重新构建规则列表
            this.rebuildRulesList(modal.modalInstance, rulesContainer);
          }
          
          break;
        }
      }
    } catch (error) {
      console.error('刷新打开的模态框时出错:', error);
    }
  }
  
