  async loadStyleCategories() {
    try {
      let categoriesContent;
      try {
        categoriesContent = await crossFS.read(this.app.vault, '.obsidian/plugins/Regex-Css-Highlighter/style-categories.json');
      } catch (e) {
        categoriesContent = null;
      }
      
      if (!categoriesContent || categoriesContent.trim() === '') {
        throw new Error('配置文件内容为空');
      }
      
      styleCategories = JSON.parse(categoriesContent);
      
      if (!styleCategories || typeof styleCategories !== 'object' || Object.keys(styleCategories).length === 0) {
        throw new Error('解析后的styleCategories为空或无效');
      }
      
      if (!this.config) {
        this.config = {};
      }
      this.config.styleCategories = styleCategories;
      
      this.registerCategoryShortcuts();
    } catch (error) {
      styleCategories = {
        [t('main.newGroup')]: []
      };
      
      if (!this.config) {
        this.config = {};
      }
      this.config.styleCategories = styleCategories;
      this.registerCategoryShortcuts();
      
      // 将默认分组写入磁盘，确保 syncStylesToCategories 能正确读取
      try {
        await crossFS.write(this.app.vault, '.obsidian/plugins/Regex-Css-Highlighter/style-categories.json', JSON.stringify(styleCategories, null, 2));
      } catch (writeError) {
      }
    }
  }

  async syncStylesToCategories() {
    const cssRelPath = '.obsidian/plugins/Regex-Css-Highlighter/styles.css';
    const categoriesRelPath = '.obsidian/plugins/Regex-Css-Highlighter/style-categories.json';

    try {
      const cssExists = await crossFS.exists(this.app.vault, cssRelPath);
      if (!cssExists) {
        return;
      }
      
      const cssContent = await crossFS.read(this.app.vault, cssRelPath);
      
      const classNameRegex = /\.([\w\u4e00-\u9fa5_-][\w\u4e00-\u9fa50-9_-]*)\s*\{/g;
      const cssClasses = new Set();
      let match;
      while ((match = classNameRegex.exec(cssContent)) !== null) {
        cssClasses.add(match[1]);
      }
      
      const categoriesExists = await crossFS.exists(this.app.vault, categoriesRelPath);
      let categories = {};
      if (categoriesExists) {
        const categoriesContent = await crossFS.read(this.app.vault, categoriesRelPath);
        if (categoriesContent && categoriesContent.trim()) {
          categories = JSON.parse(categoriesContent);
        }
      }
      
      const existingClasses = new Set();
      for (const category of Object.values(categories)) {
        if (Array.isArray(category)) {
          for (const className of category) {
            existingClasses.add(className);
          }
        }
      }
      
      const newClasses = [];
      for (const className of cssClasses) {
        if (!existingClasses.has(className)) {
          newClasses.push(className);
        }
      }
      
      if (newClasses.length > 0) {
        const defaultGroupName = t('main.newGroup');
        if (!categories[defaultGroupName]) {
          categories[defaultGroupName] = [];
        }
        for (const className of newClasses) {
          if (!categories[defaultGroupName].includes(className)) {
            categories[defaultGroupName].push(className);
          }
        }
        
        await crossFS.write(this.app.vault, categoriesRelPath, JSON.stringify(categories, null, 2));
        
        styleCategories = categories;
        if (!this.config) {
          this.config = {};
        }
        this.config.styleCategories = styleCategories;
        this.registerCategoryShortcuts();
      }
    } catch (error) {
    }
  }

  // 加载插件CSS样式到cssStyles Map
  async loadPluginCssStyles() {
    try {
      const cssContent = await this.app.vault.adapter.read('.obsidian/plugins/Regex-Css-Highlighter/styles.css');
      
      const cssRules = cssContent.match(/\.([^{]+)\s*\{([^}]+)\}/g) || [];
      
      cssRules.forEach(rule => {
        const match = rule.match(/\.([^{]+)\s*\{([^}]+)\}/);
        if (match) {
          const className = match[1].trim();
          const styles = match[2].trim();
          this.cssStyles.set(className, styles);
        }
      });

      // 加载标题样式（从data.json的headingStyles读取）
      if (this.settings && this.settings.headingStyles) {
        Object.entries(this.settings.headingStyles).forEach(([className, styles]) => {
          this.cssStyles.set(className, styles);
        });
      }
    } catch (error) {
      console.error('加载CSS样式时出错:', error);
    }
  }

  // 缓存所有hover样式
  cacheHoverStyles() {
    try {
      const startTime = performance.now();
      this.hoverStylesCache.clear();
      
      const styleSheets = document.styleSheets;
      for (let sheet of styleSheets) {
        try {
          const rules = sheet.cssRules || sheet.rules;
          for (let rule of rules) {
            if (rule.selectorText && rule.selectorText.includes(':hover')) {
              // 提取className
              const match = rule.selectorText.match(/\.([\w\u4e00-\u9fa5_-][\w\u4e00-\u9fa50-9_-]*):hover/);
              if (match) {
                const className = match[1];
                const hoverStyle = rule.style;
                const hoverStyles = {};
                
                // 收集hover样式
                for (let i = 0; i < hoverStyle.length; i++) {
                  const prop = hoverStyle[i];
                  hoverStyles[prop] = hoverStyle.getPropertyValue(prop);
                }
                
                this.hoverStylesCache.set(className, hoverStyles);
              }
            }
          }
        } catch (e) {
          // 跨域样式表会抛出错误，忽略
        }
      }
    } catch (e) {
      console.error('缓存hover样式时出错:', e);
    }
  }

